AFTER.guideHub = () => {
  if ((state.data.guideSub || 'toolkits') !== 'toolkits') return;
  _refreshToolkitManage();
};
async function _refreshToolkitManage() {
  const eccSlot = document.getElementById('tkManage-everything-claude-code');
  const ccbSlot = document.getElementById('tkManage-claude-code-best-practice');
  if (!eccSlot && !ccbSlot) return;
  try {
    const r = await api('/api/toolkit/status');
    if (!r || !r.ok) return;
    if (eccSlot) eccSlot.innerHTML = _renderEccManage(r);
    if (ccbSlot) ccbSlot.innerHTML = _renderCcbManage(r);
  } catch {}
}
function _renderEccManage(r) {
  const e = r.ecc || {};
  const cloned = !!e.marketplaceCloned;
  const nInstalled = (e.installedPlugins || []).length;
  const stateChip = cloned
    ? `<span class="chip chip-ok text-[10px]">✓ ${t('마켓플레이스 추가됨')}${e.commit ? ' · ' + escapeHtml(e.commit) : ''}</span>`
    : `<span class="chip text-[10px]">${t('미설치')}</span>`;
  const pluginChip = nInstalled > 0
    ? `<span class="chip chip-ok text-[10px]">🔌 ${nInstalled} ${t('개 플러그인 설치됨')}</span>`
    : cloned ? `<span class="chip chip-warn text-[10px]">${t('플러그인 설치 필요')}</span>` : '';
  return `
    <div class="flex items-center gap-2 flex-wrap mb-2">
      <div class="text-xs font-semibold text-[var(--text-dim)] uppercase tracking-wider flex-1">${t('대시보드에서 관리')}</div>
      ${stateChip} ${pluginChip}
    </div>
    <div class="flex items-center gap-2 flex-wrap">
      ${cloned
        ? `<button class="btn text-[12px]" onclick="_eccInstall(this)" ${!r.gitAvailable?'disabled':''}>🔄 ${t('업데이트')}</button>
           ${nInstalled > 0
             ? `<button class="btn-danger btn text-[12px]" onclick="_eccInstallPlugin(this, 'uninstall')">🗑 ${t('플러그인 제거')}</button>`
             : `<button class="btn-primary btn text-[12px]" onclick="_eccInstallPlugin(this, 'install')">🔌 ${t('플러그인 설치')}</button>`}
           <button class="btn-danger btn text-[12px]" onclick="_eccUninstall(this)">${t('마켓 제거')}</button>`
        : `<button class="btn-primary btn text-[12px]" onclick="_eccInstall(this)" ${!r.gitAvailable?'disabled':''}>⬇︎ ${t('마켓플레이스 추가')}</button>`}
    </div>
    ${cloned ? `<div class="text-[11px] text-[var(--text-dim)] mt-1.5">📂 ${escapeHtml(e.installDir || '')}</div>` : ''}`;
}
function _renderCcbManage(r) {
  const c = r.ccb || {};
  const cloned = !!c.cloned;
  const stateChip = cloned
    ? `<span class="chip chip-ok text-[10px]">✓ ${t('설치됨')}${c.commit ? ' · ' + escapeHtml(c.commit) : ''}</span>`
    : `<span class="chip text-[10px]">${t('미설치')}</span>`;
  return `
    <div class="flex items-center gap-2 flex-wrap mb-2">
      <div class="text-xs font-semibold text-[var(--text-dim)] uppercase tracking-wider flex-1">${t('대시보드에서 관리')}</div>
      ${stateChip}
    </div>
    <div class="flex items-center gap-2 flex-wrap">
      ${cloned
        ? `<button class="btn text-[12px]" onclick="_ccbInstall(this)" ${!r.gitAvailable?'disabled':''}>🔄 ${t('업데이트')}</button>
           <button class="btn text-[12px]" onclick="_ccbOpen(this)">📂 ${t('폴더 열기')}</button>
           <button class="btn-danger btn text-[12px]" onclick="_ccbUninstall(this)">🗑 ${t('제거')}</button>`
        : `<button class="btn-primary btn text-[12px]" onclick="_ccbInstall(this)" ${!r.gitAvailable?'disabled':''}>⬇︎ ${t('레포 내려받기')}</button>`}
    </div>
    <div class="text-[11px] text-[var(--text-dim)] mt-1.5">📂 ${escapeHtml(c.defaultDir || '')}</div>`;
}
async function _eccInstall(btn) {
  btn.disabled = true; const orig = btn.textContent; btn.textContent = '⏳ ' + t('설치 중...');
  try {
    const r = await api('/api/toolkit/ecc/install', { method: 'POST', body: {} });
    if (r.ok) { toast(r.updated ? t('ECC 마켓 업데이트 완료') : t('ECC 마켓 추가 완료'), 'ok'); _refreshToolkitManage(); }
    else { toast(r.error || t('설치 실패'), 'err'); btn.disabled = false; btn.textContent = orig; }
  } catch (e) { toast(String(e), 'err'); btn.disabled = false; btn.textContent = orig; }
}
async function _eccInstallPlugin(btn, action) {
  const url = action === 'install' ? '/api/toolkit/ecc/install-plugin' : '/api/toolkit/ecc/uninstall-plugin';
  const waitText = action === 'install' ? t('플러그인 설치 중...') : t('플러그인 제거 중...');
  btn.disabled = true; const orig = btn.textContent; btn.textContent = '⏳ ' + waitText;
  try {
    const r = await api(url, { method: 'POST', body: { scope: 'user' } });
    if (r.ok) {
      // v2.33.5 — Plugins / Marketplaces 탭 캐시 무효화 → 이동 시 즉시 최신 표시
      _apiCacheInvalidate('/api/plugins');
      _apiCacheInvalidate('/api/marketplaces');
      toast(action === 'install' ? t('플러그인 설치 완료') + ' — ' + t('플러그인 탭에서 확인') : t('플러그인 제거 완료'), 'ok');
      _refreshToolkitManage();
    } else {
      toast(r.error || t('실패'), 'err');
      btn.disabled = false; btn.textContent = orig;
    }
  } catch (e) { toast(String(e), 'err'); btn.disabled = false; btn.textContent = orig; }
}
async function _eccUninstall(btn) {
  if (!confirm(t('ECC 마켓플레이스 디렉터리와 레지스트리 entry 를 제거합니다. 계속할까요?'))) return;
  btn.disabled = true;
  try {
    const r = await api('/api/toolkit/ecc/uninstall', { method: 'POST', body: {} });
    if (r.ok) {
      _apiCacheInvalidate('/api/plugins');
      _apiCacheInvalidate('/api/marketplaces');
      toast(t('ECC 마켓 제거 완료') + (r.note ? ' · ' + r.note : ''), 'ok');
      _refreshToolkitManage();
    }
    else { toast(r.error || t('제거 실패'), 'err'); btn.disabled = false; }
  } catch (e) { toast(String(e), 'err'); btn.disabled = false; }
}
async function _ccbInstall(btn) {
  btn.disabled = true; const orig = btn.textContent; btn.textContent = '⏳ ' + t('내려받는 중...');
  try {
    const r = await api('/api/toolkit/ccb/install', { method: 'POST', body: {} });
    if (r.ok) { toast(r.updated ? t('CCB 업데이트 완료') : t('CCB 내려받기 완료'), 'ok'); _refreshToolkitManage(); }
    else { toast(r.error || t('설치 실패'), 'err'); btn.disabled = false; btn.textContent = orig; }
  } catch (e) { toast(String(e), 'err'); btn.disabled = false; btn.textContent = orig; }
}
async function _ccbUninstall(btn) {
  if (!confirm(t('CCB 디렉터리를 완전히 제거합니다. 계속할까요?'))) return;
  btn.disabled = true;
  try {
    const r = await api('/api/toolkit/ccb/uninstall', { method: 'POST', body: {} });
    if (r.ok) { toast(t('CCB 제거 완료'), 'ok'); _refreshToolkitManage(); }
    else { toast(r.error || t('제거 실패'), 'err'); btn.disabled = false; }
  } catch (e) { toast(String(e), 'err'); btn.disabled = false; }
}
async function _ccbOpen() {
  try {
    const r = await api('/api/toolkit/ccb/open', { method: 'POST', body: {} });
    if (!r.ok) toast(r.error || t('폴더 열기 실패'), 'err');
  } catch (e) { toast(String(e), 'err'); }
}

function _renderGuideToolkits(list) {
  if (!list.length) return `<div class="card p-8 empty">${t('데이터 없음')}</div>`;
  return `
    <div class="grid grid-cols-1 gap-4">
      ${list.map(tk => `
        <div class="card p-5">
          <div class="flex items-start justify-between gap-3 flex-wrap mb-3">
            <div class="min-w-0 flex-1">
              <div class="flex items-center gap-2 mb-1">
                <h3 class="text-lg font-semibold">${escapeHtml(tk.title)}</h3>
                ${tk.stars ? `<span class="chip text-[10px]" style="background:rgba(250,204,21,0.15);color:#fbbf24;">⭐ ${escapeHtml(tk.stars)}</span>` : ''}
                ${tk.license ? `<span class="chip text-[10px]">${escapeHtml(tk.license)}</span>` : ''}
              </div>
              <div class="text-sm text-[var(--text-mute)] mb-1">${escapeHtml(tk.subtitle||'')}</div>
              <div class="text-[11px] text-[var(--text-dim)]">${t('제작')}: ${escapeHtml(tk.author||'')}</div>
            </div>
            <a class="btn text-xs" href="${escapeHtml(tk.repo)}" target="_blank" rel="noopener">↗ ${t('리포 열기')}</a>
          </div>

          ${tk.highlights?.length ? `
            <div class="mb-3">
              <div class="text-xs font-semibold text-[var(--text-dim)] mb-1 uppercase tracking-wider">${t('하이라이트')}</div>
              <ul class="text-sm text-[var(--text-mute)] space-y-1">
                ${tk.highlights.map(h => `<li>• ${escapeHtml(h)}</li>`).join('')}
              </ul>
            </div>` : ''}

          <div id="tkManage-${escapeHtml(tk.id)}" class="mb-3"></div>

          ${tk.install?.length ? `
            <div class="mb-3">
              <div class="text-xs font-semibold text-[var(--text-dim)] mb-1 uppercase tracking-wider">${t('설치 & 사용')}</div>
              <div class="space-y-2">
                ${tk.install.map(inst => `
                  <div>
                    <div class="text-[11px] text-[var(--text-dim)] mb-0.5">${escapeHtml(inst.label)}</div>
                    <div class="flex items-center gap-2">
                      <code class="code-terminal flex-1 min-w-0 px-2 py-1.5 rounded text-xs font-mono"
                            style="word-break:break-all;">${escapeHtml(inst.code)}</code>
                      <button class="btn text-[11px]" onclick="_copyToClipboard(this, ${JSON.stringify(inst.code).replace(/"/g,'&quot;')})">📋 ${t('복사')}</button>
                    </div>
                  </div>`).join('')}
              </div>
            </div>` : ''}

          ${tk.categories?.length ? `
            <div class="grid grid-cols-1 md:grid-cols-2 gap-3">
              ${tk.categories.map(c => `
                <div style="background:rgba(255,255,255,0.02); border:1px solid var(--border); border-radius:8px; padding:10px 12px;">
                  <div class="text-xs font-semibold mb-1.5">${escapeHtml(c.name)}</div>
                  <div class="flex flex-wrap gap-1">
                    ${(c.items||[]).map(it => `<span class="chip chip-violet text-[10px]" style="background:rgba(167,139,250,0.12); color:#c4b5fd;">${escapeHtml(it)}</span>`).join('')}
                  </div>
                </div>`).join('')}
            </div>` : ''}
        </div>`).join('')}
    </div>
  `;
}

