// 🔀 WORKFLOWS — n8n 스타일 세션 워크플로우 에디터
// ────────────────────────────────────────────────────────────────
const __wf = {
  workflows: [],
  current: null,
  dirty: false,
  selectedNodeId: null,
  selectedEdgeId: null,
  drag: null,          // {kind:'node'|'pan'|'edge', ...}
  edgeDraft: null,
  patchTimer: null,
  lastTouchTs: 0,
  pollTimer: null,
  runId: null,
  lastRunResults: null,
  _clipboard: [],      // 복사된 노드 배열
  _undoStack: [],      // undo 스냅샷 (최대 30)
  // v2.44.0 — perf caches
  _webhookSecretCache: {},     // wfId → secret (refreshed only on load/save/rotate)
  _lastInspectedId: null,      // last selectedNodeId rendered into the inspector
  _inspectorDirty: false,      // any inspector-relevant data changed since last render
  // v2.44.1 — keyed-diff canvas renderer (perf): see _wfRenderCanvas comment.
  _nodeEls: new Map(),         // node id → live <g.wf-node> element in #wfNodes
  _nodeSnapshot: new Map(),    // node id → JSON of fields that affect rendering
  // AA1 (v2.66.13) — same keyed-diff for edges so port hover / drag doesn't
  // tear down every <path>. Snapshot includes endpoint positions so if
  // either endpoint node moved we re-emit only that edge's path.
  _edgeEls: new Map(),         // edge id → live <path.wf-edge> in #wfEdges
  _edgeSnapshot: new Map(),    // edge id → snap key string
  _forceFullCanvasRebuild: true, // when true, _wfRenderCanvas falls back to innerHTML rebuild
  // v2.46.0 perf — cache the <g id="wfViewport"> element so pan/wheel/fit
  // handlers don't have to call getElementById on every event. Set in
  // _wfBindCanvas after the SVG is in the DOM; cleared on _wfOpen so the
  // next bind cycle (after a view re-render) refreshes the reference.
  _viewportEl: null,
};

