AFTER.workflows = async () => {
  _wfRenderList();
  _wfApplyInspectorState();
  // 워크플로우 통계 로드
  _wfLoadStats();
  // v2.50.0 — Execution telemetry (auto-hides if no runs)
  _wfLoadTelemetry();
  _wfStartTelemetryAutoRefresh();
  // 검색 바인딩
  const se = document.getElementById('wfSearch');
  if (se) se.oninput = (e) => { __wf.search = e.target.value.toLowerCase(); _wfRenderList(); };
  // 캔버스 이벤트 바인딩
  _wfBindCanvas();
  // 위저드 → 신규 워크플로우 자동 오픈 (one-shot)
  let pendingOpenId = '';
  try { pendingOpenId = localStorage.getItem('__wf_open_id') || ''; } catch(_){}
  if (pendingOpenId && __wf.workflows.find(w => w.id === pendingOpenId)) {
    try { localStorage.removeItem('__wf_open_id'); } catch(_){}
    await _wfOpen(pendingOpenId);
  } else if (!__wf.current && __wf.workflows.length) {
    await _wfOpen(__wf.workflows[0].id);
  } else if (__wf.current) {
    _wfRenderCanvas();
    // v2.44.0 — tab re-entry wiped the DOM; force a full render bypassing
    // the early-exit guard.
    _wfRenderInspector({ force: true });
    _wfUpdateToolbar();
  }
};

