VIEWS.sessions = async () => {
  const q = state.data.sessionsFilter || { q: '', sort: 'recent', project: '', minScore: 0, errorsOnly: false };
  // v2.53.0 — full-text content search across recent JSONL transcripts.
  // When `searchState.results` is set, the result table replaces the normal list.
  const searchState = state.data._sessSearch || { query: '', results: null, loading: false, error: '' };
  state.data._sessSearch = searchState;
  const params = new URLSearchParams({ limit: 100, q: q.q, sort: q.sort });
  const [res, ar] = await Promise.all([
    api('/api/sessions/list?' + params),
    api('/api/auto_resume/status').catch(() => ({ active: [] })),
  ]);
  const arActiveIds = new Set((ar.active || []).map(e => e.sessionId));
  state.data._arActiveCount = arActiveIds.size;
  // v2.33.7 — 클라이언트 측 프로젝트 / 스코어 / 오류 필터
  const allSessions = res.sessions || [];
  const projects = {};
  for (const s of allSessions) {
    const p = s.project || '—';
    projects[p] = (projects[p] || 0) + 1;
  }
  const topProjects = Object.entries(projects).sort((a,b) => b[1]-a[1]).slice(0, 6);
  const filtered = allSessions.filter(s => {
    if (q.project && (s.project || '—') !== q.project) return false;
    if (q.minScore && (s.score || 0) < q.minScore) return false;
    if (q.errorsOnly && !(s.error_count > 0)) return false;
    return true;
  });
  state.data.sessions = { ...res, sessions: filtered, _rawTotal: allSessions.length };
  // v2.47 perf — virtual scroll. Render first 50 rows; an IntersectionObserver
  // appends the next 50 when the sentinel scrolls into view.
  state.data._sessRows = filtered;
  state.data._sessArActiveIds = arActiveIds;
  state.data._sessRendered = Math.min(50, filtered.length);
  const initial = filtered.slice(0, state.data._sessRendered);
  const needSentinel = filtered.length > state.data._sessRendered;
  const showingSearch = !!(searchState.results && searchState.results.ok);
  const searchHits = showingSearch ? (searchState.results.hits || []) : [];
  return `
    <div class="mb-4 flex items-center justify-between gap-3 flex-wrap">
      <div>
        <h1 class="text-2xl font-bold">세션 히스토리</h1>
        <p class="text-sm text-[var(--text-mute)] mt-1">총 ${res.total}개 세션 중 ${filtered.length}개 표시. 행을 클릭하면 상세 타임라인.</p>
      </div>
      <div class="flex gap-2">
        <input id="sessQ" class="input max-w-[300px]" placeholder="요청/프로젝트/세션ID 검색…" value="${escapeHtml(q.q)}" />
        <a class="btn text-xs" href="${DOCS_BASE}interactive-mode" target="_blank" rel="noopener">📖</a>
        <select id="sessSort" class="input max-w-[150px]">
          <option value="recent" ${q.sort==='recent'?'selected':''}>최신순</option>
          <option value="score" ${q.sort==='score'?'selected':''}>스코어순</option>
          <option value="tools" ${q.sort==='tools'?'selected':''}>도구 사용순</option>
          <option value="tokens" ${q.sort==='tokens'?'selected':''}>토큰 사용순</option>
          <option value="duration" ${q.sort==='duration'?'selected':''}>지속시간순</option>
        </select>
      </div>
    </div>

    <div class="card p-3 mb-4 flex flex-wrap items-center gap-2">
      <input id="sessSearch" type="search" class="input flex-1 min-w-[200px]"
             placeholder="${t('세션 내용 검색…')}" value="${escapeHtml(searchState.query || '')}" />
      ${showingSearch ? `<button class="btn text-xs" onclick="_sessSearchClear()">${t('검색 지우기')}</button>` : ''}
      ${searchState.loading ? `<span class="text-xs text-[var(--text-dim)]">${t('검색 중…')}</span>` : ''}
      ${searchState.error ? `<span class="text-xs text-[var(--err)]">${escapeHtml(searchState.error)}</span>` : ''}
      ${showingSearch ? `<span class="text-xs text-[var(--text-dim)]">${t('스캔한 세션')}: ${searchState.results.totalScanned} · ${t('일치한 세션')}: ${searchState.results.totalMatched}</span>` : ''}
    </div>

    ${showingSearch ? `
    <div class="card overflow-hidden">
      <div class="p-3 border-b border-[var(--border)] text-sm font-bold">${t('검색 결과')}</div>
      <div class="overflow-x-auto">
        <table class="data">
          <thead><tr>
            <th class="text-right">${t('점수')}</th>
            <th>${t('역할')}</th>
            <th>${t('스니펫')}</th>
            <th class="hidden md:table-cell">${t('프로젝트')}</th>
            <th class="text-right hidden sm:table-cell">${t('시작')}</th>
          </tr></thead>
          <tbody>
          ${searchHits.length === 0 ? `<tr><td colspan="5" class="empty">${t('검색 결과 없음')}</td></tr>` : searchHits.map(h => `
            <tr style="cursor:pointer" onclick="openSessionDetail('${escapeHtml(h.sessionId)}')">
              <td class="text-right mono">${h.score}</td>
              <td><span class="chip ${h.role==='user'?'':'chip-accent'}">${escapeHtml(h.role || '')}</span></td>
              <td class="text-xs"><div class="line-clamp-2">${escapeHtml(h.snippet || '')}</div></td>
              <td class="hidden md:table-cell text-xs text-[var(--text-mute)]">${escapeHtml((h.cwd || '').split('/').pop() || '—')}</td>
              <td class="text-right text-xs hidden sm:table-cell">${fmtRel(h.started_at || h.ts || 0)}</td>
            </tr>`).join('')}
          </tbody>
        </table>
      </div>
    </div>
    ` : `
    <div class="card p-3 mb-4 flex flex-wrap items-center gap-2">
      <span class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mr-1">${t('프로젝트')}</span>
      <button class="chip ${!q.project?'chip-accent':''}" onclick="_sessSet('project','')">${t('전체')} ${allSessions.length}</button>
      ${topProjects.map(([p,n]) => `<button class="chip ${p===q.project?'chip-accent':''}" onclick="_sessSet('project', ${JSON.stringify(p).replace(/"/g,'&quot;')})">${escapeHtml(p)} ${n}</button>`).join('')}
      <span class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mx-1 ml-3">${t('스코어')}</span>
      ${[0, 40, 60, 80].map(n => `<button class="chip ${q.minScore===n?'chip-accent':''}" onclick="_sessSet('minScore', ${n})">${n===0?t('전체'):'≥'+n}</button>`).join('')}
      <label class="chip cursor-pointer ${q.errorsOnly?'chip-err':''}" onclick="_sessSet('errorsOnly', !state.data.sessionsFilter.errorsOnly)">${q.errorsOnly?'✓':''} ${t('오류만')}</label>
    </div>

    <div class="card overflow-hidden">
      <table class="data">
        <thead><tr>
          <th>스코어</th>
          <th>첫 요청</th>
          <th>프로젝트</th>
          <th class="text-right">메시지</th>
          <th class="text-right">도구</th>
          <th class="text-right">에이전트</th>
          <th class="text-right">토큰</th>
          <th class="text-right">오류</th>
          <th class="text-right">지속</th>
          <th class="text-right">시작</th>
        </tr></thead>
        <tbody id="sessTbody">
        ${initial.map(s => _sessRowHtml(s, arActiveIds)).join('') || `<tr><td colspan="10" class="empty">세션이 없습니다. 재인덱스 버튼을 눌러보세요.</td></tr>`}
        ${needSentinel ? `<tr id="sessSentinel"><td colspan="10" class="text-center text-xs text-[var(--text-dim)] py-3">${t('더 불러오는 중…')}</td></tr>` : ''}
        </tbody>
      </table>
    </div>
    `}
  `;
};
AFTER.sessions = () => {
  const qInput = document.getElementById('sessQ');
  const sortInput = document.getElementById('sessSort');
  let debounce;
  if (qInput) {
    qInput.addEventListener('input', e => {
      clearTimeout(debounce);
      debounce = setTimeout(() => {
        _sessSet('q', e.target.value);
      }, 250);
    });
  }
  if (sortInput) {
    sortInput.addEventListener('change', () => {
      _sessSet('sort', sortInput.value);
    });
  }
  // v2.53.0 — full-text content search box (debounced 300ms).
  const searchInput = document.getElementById('sessSearch');
  if (searchInput) {
    let sDeb;
    searchInput.addEventListener('input', e => {
      clearTimeout(sDeb);
      sDeb = setTimeout(() => _sessSearchInput(e.target.value), 300);
    });
  }
  // v2.47 perf — virtual scroll: append rows in 50-row chunks when the
  // sentinel intersects the viewport.
  const sentinel = document.getElementById('sessSentinel');
  if (!sentinel) return;
  const tbody = document.getElementById('sessTbody');
  const rows = state.data._sessRows || [];
  const arActiveIds = state.data._sessArActiveIds || new Set();
  const io = new IntersectionObserver((entries) => {
    if (!entries.some(en => en.isIntersecting)) return;
    const start = state.data._sessRendered || 0;
    const end = Math.min(start + 50, rows.length);
    if (end <= start) { io.disconnect(); sentinel.remove(); return; }
    const frag = document.createRange().createContextualFragment(
      rows.slice(start, end).map(s => _sessRowHtml(s, arActiveIds)).join('')
    );
    tbody.insertBefore(frag, sentinel);
    state.data._sessRendered = end;
    if (end >= rows.length) {
      io.disconnect();
      sentinel.remove();
    }
  }, { root: null, rootMargin: '200px', threshold: 0 });
  io.observe(sentinel);
};
// v2.33.7 — 부분 업데이트 헬퍼
function _sessSet(key, value) {
  state.data.sessionsFilter = Object.assign(
    { q: '', sort: 'recent', project: '', minScore: 0, errorsOnly: false },
    state.data.sessionsFilter || {},
    { [key]: value },
  );
  renderView();
}
window._sessSet = _sessSet;

// v2.53.0 — full-text content search wiring.
async function _sessSearchInput(raw) {
  const q = (raw || '').trim();
  const ss = state.data._sessSearch || (state.data._sessSearch = { query: '', results: null, loading: false, error: '' });
  ss.query = q;
  if (q.length < 2) {
    ss.results = null;
    ss.loading = false;
    ss.error = q.length === 1 ? t('검색어가 너무 짧음 (2글자 이상)') : '';
    renderView();
    return;
  }
  ss.loading = true;
  ss.error = '';
  try {
    const r = await api('/api/sessions/search?' + new URLSearchParams({ q, limit: 20 }));
    if (r && r.ok) {
      ss.results = r;
      ss.error = '';
    } else {
      ss.results = null;
      ss.error = (r && r.error) || t('검색 결과 없음');
    }
  } catch (e) {
    ss.results = null;
    ss.error = e.message || String(e);
  } finally {
    ss.loading = false;
    renderView();
  }
}
function _sessSearchClear() {
  state.data._sessSearch = { query: '', results: null, loading: false, error: '' };
  renderView();
}
window._sessSearchInput = _sessSearchInput;
window._sessSearchClear = _sessSearchClear;

async function openSessionDetail(sessionId) {
  showModalLoading(t('세션 불러오는 중…'));
  try {
    const [d, tok, tl] = await Promise.all([
      api('/api/sessions/detail/' + sessionId),
      api('/api/sessions/tokens/' + sessionId),
      api('/api/sessions/timeline/' + sessionId),
    ]);
    if (d.error) { closeModal(); toast(errMsg(d), 'err'); return; }
    renderSessionDetail(d, tok, tl);
  } catch (e) {
    closeModal();
    toast(e.message, 'err');
  }
}

function fmtTokens(n) {
  if (!n) return '0';
  if (n >= 1e9) return (n/1e9).toFixed(2)+'B';
  if (n >= 1e6) return (n/1e6).toFixed(2)+'M';
  if (n >= 1e3) return (n/1e3).toFixed(1)+'K';
  return String(n);
}
function renderSessionDetail(d, tok, tl) {
  const s = d.session;
  const tools = d.tools || [];
  const msgs = d.messages || [];
  tok = tok || { totals:{}, byTool:[], byAgent:[] };
  tl = tl || { nodes:[], edges:[] };
  const toolCounts = {};
  tools.forEach(t => { toolCounts[t.tool] = (toolCounts[t.tool]||0) + 1; });
  const breakdown = s.score_breakdown || {};
  const breakdownHtml = Object.entries(breakdown).map(([k,v]) => `
    <div class="flex justify-between py-1 text-xs">
      <span class="text-[var(--text-mute)]">${k}</span>
      <span class="mono font-bold" style="color:${scoreColor(v*4)}">+${v}</span>
    </div>`).join('');

  const toolsHtml = tools.slice(0, 120).map(t => `
    <div class="flex items-center gap-2 p-2 hover:bg-white/5 rounded">
      <span class="chip ${t.had_error?'chip-err':''}">${escapeHtml(t.tool)}</span>
      ${t.subagent_type ? `<span class="chip chip-accent">→ ${escapeHtml(t.subagent_type)}</span>` : ''}
      <span class="text-xs flex-1 truncate text-[var(--text-mute)] mono">${escapeHtml(t.input_summary || '')}</span>
      <span class="text-[10px] text-[var(--text-dim)]">${fmtMs(t.ts)}</span>
    </div>`).join('');

  const msgsHtml = msgs.slice(-40).map(m => `
    <div class="p-2 border-l-2 ${m.role==='user'?'border-[var(--cyan)]':'border-[var(--accent)]'} pl-3 mb-2">
      <div class="text-[10px] uppercase tracking-widest text-[var(--text-dim)] mb-1">${m.role} · ${fmtRel(m.ts)}</div>
      <div class="text-xs whitespace-pre-wrap line-clamp-6">${escapeHtml(m.preview||'')}</div>
    </div>`).join('');

  showModal(`
    <div class="p-6 border-b border-[var(--border)] flex items-start gap-4">
      <div class="score-ring" style="--p:${s.score}; width:110px; height:110px;">
        <div class="text-center">
          <div class="text-3xl font-bold mono" style="color:${scoreColor(s.score)}">${s.score}</div>
        </div>
      </div>
      <div class="flex-1 min-w-0">
        <div class="text-xs text-[var(--text-dim)] mono">${escapeHtml(s.session_id)}</div>
        <h2 class="text-lg font-bold mt-1 line-clamp-2">${escapeHtml(s.first_user_prompt || '(요청 없음)')}</h2>
        <div class="flex flex-wrap gap-2 mt-3">
          <span class="chip">📁 ${escapeHtml(s.project || '—')}</span>
          <span class="chip">💬 ${s.message_count}</span>
          <span class="chip">🛠 ${s.tool_use_count}</span>
          <span class="chip chip-accent">🤝 ${s.agent_call_count}</span>
          <span class="chip">⏱ ${fmtDur(s.duration_ms)}</span>
          <span class="chip">${escapeHtml(s.model||'—')}</span>
          ${s.error_count ? `<span class="chip chip-err">❌ ${s.error_count}</span>` : ''}
        </div>
      </div>
      <button class="btn-ghost btn" onclick="closeModal()">✕</button>
    </div>
    <div class="flex-1 overflow-y-auto p-6 space-y-5">

      <!-- Auto-Resume 패널 -->
      <div id="autoResumePanel" data-session-id="${escapeHtml(s.session_id)}" data-cwd="${escapeHtml(s.cwd || s.projectPath || '')}">
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">${t('Auto-Resume — 세션에 재시도 워커 주입')}</div>
        <div class="card p-3 text-xs"><div class="empty text-xs">${t('상태 불러오는 중…')}</div></div>
      </div>

      <!-- 1행: 토큰 요약 + 5축 점수 -->
      <div class="grid grid-cols-1 lg:grid-cols-5 gap-3">
        ${[
          ['전체 토큰', fmtTokens(tok.totals.total), '#d97757'],
          ['입력', fmtTokens(tok.totals.input), '#86efac'],
          ['출력', fmtTokens(tok.totals.output), '#7dd3fc'],
          ['캐시 read', fmtTokens(tok.totals.cacheRead), '#a78bfa'],
          ['캐시 create', fmtTokens(tok.totals.cacheCreate), '#fcd34d'],
        ].map(([l,v,c]) => `
          <div class="card p-3">
            <div class="text-[10px] uppercase text-[var(--text-dim)]">${l}</div>
            <div class="text-2xl font-bold mono mt-1" style="color:${c}">${v}</div>
          </div>`).join('')}
      </div>

      <!-- 2행: 토큰 분해 (도구별 / 에이전트별) -->
      <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div>
          <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">🛠 도구별 토큰 (turn 기준 분배)</div>
          <div class="card p-3 max-h-[260px] overflow-y-auto">
            ${(tok.byTool||[]).map(r => {
              const max = (tok.byTool[0]||{}).tokens || 1;
              const pct = Math.max(2, Math.round((r.tokens||0)/max*100));
              return `
              <div class="mb-2">
                <div class="flex justify-between text-xs mb-1">
                  <span class="mono">${escapeHtml(r.tool)} <span class="text-[var(--text-dim)]">×${r.calls}</span></span>
                  <span class="mono font-bold" style="color:#d97757">${fmtTokens(r.tokens||0)}</span>
                </div>
                <div class="h-1.5 bg-white/5 rounded overflow-hidden"><div style="width:${pct}%; height:100%; background:#d97757;"></div></div>
              </div>`;
            }).join('') || '<div class="empty text-xs">데이터 없음</div>'}
          </div>
        </div>
        <div>
          <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">🤝 서브에이전트별 토큰</div>
          <div class="card p-3 max-h-[260px] overflow-y-auto">
            ${(tok.byAgent||[]).map(r => {
              const max = (tok.byAgent[0]||{}).tokens || 1;
              const pct = Math.max(2, Math.round((r.tokens||0)/max*100));
              return `
              <div class="mb-2">
                <div class="flex justify-between text-xs mb-1">
                  <span class="mono">${escapeHtml(r.agent)} <span class="text-[var(--text-dim)]">×${r.calls}</span></span>
                  <span class="mono font-bold" style="color:#a78bfa">${fmtTokens(r.tokens||0)}</span>
                </div>
                <div class="h-1.5 bg-white/5 rounded overflow-hidden"><div style="width:${pct}%; height:100%; background:#a78bfa;"></div></div>
              </div>`;
            }).join('') || '<div class="empty text-xs">서브에이전트 위임 없음</div>'}
          </div>
        </div>
      </div>

      <!-- 3행: 진행 그래프 (Obsidian 스타일) -->
      <div>
        <div class="flex items-center justify-between mb-2">
          <div class="text-[11px] uppercase text-[var(--text-dim)]">📈 진행 그래프 (시작 → 종료)</div>
          <span class="text-[10px] text-[var(--text-dim)]">${tl.nodes.length} 노드 · ⬛ 세션 / ◆ user 프롬프트 / ⬢ 에이전트 / ● 도구</span>
        </div>
        <div class="card p-2" style="height:420px; position:relative;">
          <div id="sessionTimelineGraph" style="width:100%; height:100%;"></div>
        </div>
      </div>

      <!-- 4행: 점수 + 카운트 + 메시지 -->
      <div class="grid grid-cols-1 lg:grid-cols-3 gap-4">
        <div>
          <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">스코어 브레이크다운</div>
          <div class="card p-3">${breakdownHtml}</div>
          <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2 mt-3">서브에이전트</div>
          <div class="card p-3 text-xs">
            ${Object.entries(s.subagent_types || {}).map(([k,v]) =>
              `<span class="chip chip-accent mr-1 mb-1">${escapeHtml(k)} ×${v}</span>`
            ).join('') || '<span class="text-[var(--text-dim)]">호출 없음</span>'}
          </div>
        </div>
        <div class="lg:col-span-2">
          <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">메시지 (최근 40)</div>
          <div class="card max-h-[320px] overflow-y-auto p-3">${msgsHtml || '<div class="empty text-xs">메시지 없음</div>'}</div>
        </div>
      </div>
    </div>
  `);
  // 그래프 렌더 — vis-network
  setTimeout(() => drawSessionTimeline(tl), 50);
  setTimeout(() => _arLoad(s.session_id), 30);
}

// ────────────────────────────────────────────────────────────────
// AUTO-RESUME — inject a retry loop into a live Claude Code session.
// Mirrors the user's reference shell: claude --resume <id> -p "..." in a
// loop with sleep(pollInterval) between non-zero exits. Backend worker at
// server/auto_resume.py owns the actual loop; this UI just toggles +
// shows live status.
// ────────────────────────────────────────────────────────────────
const _AR_STATE_LABEL = {
  watching:  { ko: '대기 중 (idle 미충족)', cls: '' },
  retrying:  { ko: '실행 중 (claude --resume)', cls: 'chip-accent' },
  sleeping:  { ko: '쿨다운 중 (다음 시도 예약)', cls: 'chip-warn' },
  succeeded: { ko: '재개 성공', cls: 'chip-ok' },
  stopped:   { ko: '중단됨', cls: '' },
  error:     { ko: '오류', cls: 'chip-err' },
};

async function _arLoad(sessionId) {
  if (!sessionId) return;
  const panel = document.getElementById('autoResumePanel');
  if (!panel || panel.dataset.sessionId !== sessionId) return;
  try {
    const r = await api('/api/auto_resume/get?sessionId=' + encodeURIComponent(sessionId));
    _arRender(panel, r.entry);
    _arSchedulePoll(sessionId, !!(r.entry && r.entry.enabled));
  } catch (e) {
    panel.querySelector('.card').innerHTML = `<div class="text-xs" style="color:#fca5a5">${escapeHtml(e.message || String(e))}</div>`;
  }
}

const _AR_REASON_CHIP = {
  rate_limit:    { ko: '레이트 한도', cls: 'chip-warn' },
  context_full:  { ko: '컨텍스트 한도 초과', cls: 'chip-err' },
  auth_expired:  { ko: '인증 만료', cls: 'chip-err' },
  clean:         { ko: '정상 종료', cls: 'chip-ok' },
  unknown:       { ko: '알 수 없음', cls: '' },
};

function _arRender(panel, entry) {
  _arRememberNext(entry);
  const sid = panel.dataset.sessionId;
  const cwd = panel.dataset.cwd || '';
  const card = panel.querySelector('.card');
  if (!entry || !entry.enabled) {
    const prevPrompt   = entry && entry.prompt ? entry.prompt : '';
    const prevPoll     = entry && entry.pollInterval ? entry.pollInterval : 300;
    const prevIdle     = entry && entry.idleSeconds ? entry.idleSeconds : 90;
    const prevMax      = entry && entry.maxAttempts ? entry.maxAttempts : 12;
    const prevContinue = entry && entry.useContinue ? 'checked' : '';
    const prevHooks    = entry && entry.installHooks ? 'checked' : '';
    const stoppedNote  = entry && entry.stopReason
      ? `<div class="text-[10px] mb-2" style="color:#fca5a5">${t('이전 중단 사유')}: ${escapeHtml(entry.stopReason)}</div>`
      : '';
    card.innerHTML = `
      <div class="text-xs text-[var(--text-mute)] mb-2">
        ${t('이 세션이 토큰/레이트 한도로 멈추면 백그라운드 워커가 claude --resume 으로 자동 재시도합니다 (셸 while-loop 동등).')}
      </div>
      ${stoppedNote}
      <details class="mb-2">
        <summary class="text-[11px] text-[var(--text-dim)] cursor-pointer mb-2">${t('고급 설정')}</summary>
        <textarea id="arPrompt" class="input w-full text-xs mb-2" rows="3"
          placeholder="${t('재개 프롬프트 — 비우면 기본값 사용')}">${escapeHtml(prevPrompt)}</textarea>
        <div class="flex gap-2 items-center text-xs flex-wrap mb-2">
          <label class="text-[var(--text-dim)]">${t('재시도 간격(초)')}</label>
          <input id="arPoll" class="input w-24" type="number" min="30" max="3600" value="${prevPoll}" />
          <label class="text-[var(--text-dim)]">${t('정지 판정 idle(초)')}</label>
          <input id="arIdle" class="input w-24" type="number" min="30" value="${prevIdle}" />
          <label class="text-[var(--text-dim)]">${t('최대 재시도 횟수')}</label>
          <input id="arMax" class="input w-20" type="number" min="1" max="60" value="${prevMax}" />
        </div>
        <div class="flex gap-3 items-center text-xs flex-wrap mb-2">
          <label class="cursor-pointer flex items-center gap-1">
            <input type="checkbox" id="arUseContinue" ${prevContinue} />
            <span title="${t('--resume <id> 대신 --continue 사용')}">${t('--continue 모드')}</span>
          </label>
          <label class="cursor-pointer flex items-center gap-1">
            <input type="checkbox" id="arInstallHooks" ${prevHooks} />
            <span title="${t('Stop hook 으로 매 응답 시 스냅샷 저장 + SessionStart 로 자동 주입')}">${t('Stop+SessionStart Hook 자동 설치 (프로젝트)')}</span>
          </label>
        </div>
        <div class="flex gap-2 items-center text-xs flex-wrap">
          <label class="text-[var(--text-dim)] w-full text-[10px] uppercase">${t('알림 (선택) — 상태 전이 시 webhook')}</label>
          <input id="arSlackUrl" class="input flex-1 min-w-[200px] text-xs" type="url"
            placeholder="https://hooks.slack.com/..." value="${escapeHtml((entry && entry.notify && entry.notify.slack) || '')}" />
          <input id="arDiscordUrl" class="input flex-1 min-w-[200px] text-xs" type="url"
            placeholder="https://discord.com/api/webhooks/..." value="${escapeHtml((entry && entry.notify && entry.notify.discord) || '')}" />
        </div>
      </details>
      <button class="btn btn-accent text-xs" id="arInjectBtn" onclick="_arSubmit('${sid}', ${JSON.stringify(cwd).replace(/"/g, '&quot;')})">
        🔄 ${t('Auto-Resume 주입')}
      </button>
    `;
    return;
  }
  const lab = _AR_STATE_LABEL[entry.state] || { ko: entry.state, cls: '' };
  const nextRel = entry.nextAttemptAt ? Math.max(0, Math.round((entry.nextAttemptAt - Date.now()) / 1000)) : 0;
  const lastRel = entry.lastAttemptAt ? fmtRel(entry.lastAttemptAt) : t('아직 없음');
  const lastExit = entry.lastExitCode === null || entry.lastExitCode === undefined ? '—' : entry.lastExitCode;
  const reason = _AR_REASON_CHIP[entry.lastExitReason];
  const reasonChip = reason ? `<span class="chip ${reason.cls}">${t(reason.ko)}</span>` : '';
  const maxA = entry.maxAttempts || 12;
  const pct = Math.min(100, Math.round((entry.attempts / maxA) * 100));
  const barColor = pct < 50 ? '#86efac' : (pct < 80 ? '#fcd34d' : '#fca5a5');
  const stallCount = (entry.snapshotHashes || []).length;
  const fmtClock = (ms) => {
    if (!ms) return '';
    try { return new Date(ms).toLocaleTimeString(); } catch { return ''; }
  };
  const nextClock = entry.nextAttemptAt ? fmtClock(entry.nextAttemptAt) : '';
  const resetClock = entry.lastResetAt ? fmtClock(entry.lastResetAt) : '';
  const snapPreview = entry.snapshotPreview
    ? `<details class="mb-2">
         <summary class="text-[10px] text-[var(--text-dim)] cursor-pointer">${t('Stop hook 스냅샷 미리보기')}</summary>
         <pre class="text-[10px] whitespace-pre-wrap bg-black/20 p-2 rounded mt-1 max-h-40 overflow-auto">${escapeHtml(entry.snapshotPreview)}</pre>
       </details>`
    : '';
  card.innerHTML = `
    <div class="flex items-center gap-2 mb-2 flex-wrap">
      <span class="chip ${lab.cls}" id="arStateChip">${t(lab.ko)}</span>
      ${reasonChip}
      <span class="chip">${t('시도')} ${entry.attempts}/${maxA}</span>
      ${entry.state === 'waiting' && nextRel > 0
        ? `<span class="chip chip-warn">${t('다음 시도까지')} ${nextRel}s${nextClock ? ' (' + nextClock + ')' : ''}</span>`
        : ''}
      ${resetClock ? `<span class="chip">${t('리셋')} ${resetClock}</span>` : ''}
    </div>
    <div class="h-1.5 bg-white/5 rounded overflow-hidden mb-3">
      <div style="width:${pct}%; height:100%; background:${barColor}; transition: width .3s;"></div>
    </div>
    <div class="grid grid-cols-2 gap-3 text-[10px] text-[var(--text-dim)] mb-2">
      <div><span class="uppercase">${t('재시도 간격')}:</span> ${entry.pollInterval}s</div>
      <div><span class="uppercase">${t('정지 idle')}:</span> ${entry.idleSeconds}s</div>
      <div><span class="uppercase">${t('마지막 시도')}:</span> ${lastRel} · exit=${lastExit}</div>
      <div><span class="uppercase">${t('스냅샷 해시 기록')}:</span> ${stallCount}/5${stallCount >= 3 ? ' ⚠' : ''}</div>
    </div>
    <details class="mb-2">
      <summary class="text-[10px] text-[var(--text-dim)] cursor-pointer">${t('재개 프롬프트')}</summary>
      <pre class="text-[11px] whitespace-pre-wrap bg-black/20 p-2 rounded mt-1">${escapeHtml(entry.prompt || '')}</pre>
    </details>
    ${snapPreview}
    ${entry.lastError ? `
      <details class="mb-2">
        <summary class="text-[10px] cursor-pointer" style="color:#fca5a5">${t('마지막 오류 출력')}</summary>
        <pre class="text-[10px] whitespace-pre-wrap bg-black/20 p-2 rounded mt-1 max-h-40 overflow-auto" style="color:#fca5a5">${escapeHtml(entry.lastError)}</pre>
      </details>
    ` : ''}
    ${entry.stopReason ? `<div class="text-[10px] mb-2" style="color:#fcd34d">⚠ ${escapeHtml(entry.stopReason)}</div>` : ''}
    <div class="flex gap-2 flex-wrap">
      <button class="btn text-xs" id="arCancelBtn" onclick="_arCancel('${sid}')" style="color:#fca5a5">
        ⏹ ${t('Auto-Resume 중단')}
      </button>
      ${entry.installHooks ? `
        <button class="btn text-xs" onclick="_arUninstallHooks(${JSON.stringify(cwd).replace(/"/g, '&quot;')}, '${sid}')">
          🪝 ${t('Hook 제거')}
        </button>` : `
        <button class="btn text-xs" onclick="_arInstallHooksOnly(${JSON.stringify(cwd).replace(/"/g, '&quot;')}, '${sid}')">
          🪝 ${t('Hook 설치')}
        </button>`}
    </div>
  `;
}

async function _arInstallHooksOnly(cwd, sid) {
  try {
    const r = await api('/api/auto_resume/install_hooks', { method:'POST', body: JSON.stringify({ cwd }) });
    if (r.ok) { toast(t('Hook 설치 완료'), 'ok'); _arLoad(sid); }
    else      { toast(r.error || t('실패'), 'err'); }
  } catch (e) { toast(e.message, 'err'); }
}

async function _arUninstallHooks(cwd, sid) {
  try {
    const r = await api('/api/auto_resume/uninstall_hooks', { method:'POST', body: JSON.stringify({ cwd }) });
    if (r.ok) { toast(t('Hook 제거 완료'), 'ok'); _arLoad(sid); }
    else      { toast(r.error || t('실패'), 'err'); }
  } catch (e) { toast(e.message, 'err'); }
}
window._arInstallHooksOnly = _arInstallHooksOnly;
window._arUninstallHooks   = _arUninstallHooks;

async function _arSubmit(sessionId, cwd) {
  const promptEl   = document.getElementById('arPrompt');
  const pollEl     = document.getElementById('arPoll');
  const idleEl     = document.getElementById('arIdle');
  const maxEl      = document.getElementById('arMax');
  const contEl     = document.getElementById('arUseContinue');
  const hooksEl    = document.getElementById('arInstallHooks');
  const slackEl    = document.getElementById('arSlackUrl');
  const discordEl  = document.getElementById('arDiscordUrl');
  const body = {
    sessionId,
    cwd: cwd || '',
    prompt: promptEl ? promptEl.value : '',
    pollInterval: pollEl ? Number(pollEl.value) || 300 : 300,
    idleSeconds: idleEl ? Number(idleEl.value) || 90 : 90,
    maxAttempts: maxEl ? Number(maxEl.value) || 12 : 12,
    useContinue: !!(contEl && contEl.checked),
    installHooks: !!(hooksEl && hooksEl.checked),
    notify: {
      slack:   slackEl ? (slackEl.value || '').trim() : '',
      discord: discordEl ? (discordEl.value || '').trim() : '',
    },
  };
  try {
    const r = await api('/api/auto_resume/set', { method: 'POST', body: JSON.stringify(body) });
    if (r.ok) {
      toast(t('Auto-Resume 주입 완료'), 'ok');
      _arLoad(sessionId);
    } else {
      toast(r.error || t('실패'), 'err');
    }
  } catch (e) { toast(e.message, 'err'); }
}

async function _arCancel(sessionId) {
  if (!confirm(t('Auto-Resume 워커를 중단할까요?'))) return;
  try {
    const r = await api('/api/auto_resume/cancel', { method: 'POST', body: JSON.stringify({ sessionId }) });
    if (r.ok) {
      toast(t('Auto-Resume 중단됨'), 'ok');
      _arLoad(sessionId);
    } else {
      toast(r.error || t('실패'), 'err');
    }
  } catch (e) { toast(e.message, 'err'); }
}

let _arPollTimer = null;
let _arTickerTimer = null;
let _arNextAttemptAtCache = 0;

function _arSchedulePoll(sessionId, active) {
  if (_arPollTimer) { clearTimeout(_arPollTimer); _arPollTimer = null; }
  if (_arTickerTimer) { clearInterval(_arTickerTimer); _arTickerTimer = null; }
  if (!active) return;
  // Full re-fetch every 5s — picks up state transitions / new attempts.
  _arPollTimer = setTimeout(() => {
    const panel = document.getElementById('autoResumePanel');
    if (panel && panel.dataset.sessionId === sessionId) _arLoad(sessionId);
  }, 5000);
  // 1s ticker — surgically rewrites the "next attempt in Ns" chip so the
  // countdown looks live instead of jumping by 5s. Cheap: just sets one
  // textContent, no fetch.
  _arTickerTimer = setInterval(() => {
    const panel = document.getElementById('autoResumePanel');
    if (!panel || panel.dataset.sessionId !== sessionId) {
      clearInterval(_arTickerTimer); _arTickerTimer = null; return;
    }
    if (!_arNextAttemptAtCache) return;
    const left = Math.max(0, Math.round((_arNextAttemptAtCache - Date.now()) / 1000));
    const chips = panel.querySelectorAll('.chip.chip-warn');
    chips.forEach(c => {
      // Match the "다음 시도까지 Ns (HH:MM:SS)" chip created by _arRender
      if (/\d+s/.test(c.textContent)) {
        c.textContent = c.textContent.replace(/\d+s/, left + 's');
      }
    });
  }, 1000);
}

// Save next-attempt epoch from each render so the 1s ticker can compute
// the live countdown without re-fetching.
function _arRememberNext(entry) {
  _arNextAttemptAtCache = (entry && entry.state === 'waiting' && entry.nextAttemptAt) ? entry.nextAttemptAt : 0;
}

window._arSubmit = _arSubmit;
window._arCancel = _arCancel;
window._arLoad   = _arLoad;

async function drawSessionTimeline(tl) {
  const el = document.getElementById('sessionTimelineGraph');
  if (!el) return;
  if (typeof vis === 'undefined') {
    try { await window._loadVendor('vis'); } catch (_) { return; }
  }
  if (typeof vis === 'undefined') return;
  const colorByKind = {
    session: { background:'#d97757', border:'#fb923c', font:'#fff' },
    prompt:  { background:'#7dd3fc', border:'#38bdf8', font:'#0c4a6e' },
    agent:   { background:'#a78bfa', border:'#8b5cf6', font:'#fff' },
    tool:    { background:'#27272a', border:'#52525b', font:'#d4d4d8' },
  };
  const shapeByKind = { session:'square', prompt:'diamond', agent:'hexagon', tool:'dot' };
  const nodes = tl.nodes.map(n => ({
    id: n.id,
    label: n.label,
    shape: shapeByKind[n.kind] || 'dot',
    color: colorByKind[n.kind] || colorByKind.tool,
    font: { color:(colorByKind[n.kind]||colorByKind.tool).font, size: n.kind==='session'?13:11 },
    title: `${n.kind}\n${n.label}\n${n.meta && n.meta.tokens ? 'tokens: '+fmtTokens(n.meta.tokens) : ''}`,
    size: n.kind === 'session' ? 22 : (n.kind === 'agent' ? 18 : (n.kind === 'prompt' ? 16 : 8)),
  }));
  const edges = tl.edges.map(e => ({ from: e.src, to: e.dst, arrows:'to', color:{color:'#3f3f46'} }));
  const network = new vis.Network(el, { nodes: new vis.DataSet(nodes), edges: new vis.DataSet(edges) }, {
    layout: { hierarchical: { direction:'LR', sortMethod:'directed', nodeSpacing: 70, levelSeparation: 110 } },
    physics: false,
    interaction: { hover:true, zoomView:false, dragView:true, dragNodes:false },
    edges: { smooth: { type:'cubicBezier', forceDirection:'horizontal', roundness:0.4 } },
  });
}

// ────────────────────────────────────────────────────────────────
// AGENTS + GRAPH
// ────────────────────────────────────────────────────────────────
VIEWS.agents = async () => {
  const [list, graph, modelRes, hyperList] = await Promise.all([
    cachedApi('/api/agents', 20000),
    api('/api/agents/graph?days=60'),
    api('/api/subagent/model-choices'),
    api('/api/hyper-agents/list').catch(() => ({items:[]})),
  ]);
  // Map agent id -> enabled bool, used by renderAgentCard for the ⚡ chip color.
  window.__hyperAgentsMap = {};
  (hyperList.items || []).forEach(h => { window.__hyperAgentsMap[h.name] = !!h.enabled; });
  state.data.agents = list;
  state.data.agentsGraph = graph;
  window.__subModelChoices = modelRes.choices || [];
  const agents = list.agents || [];
  const counts = list.counts || {};
  const q = (state.data.agentFilter || '').toLowerCase();
  const onlyEnabled = !!state.data.agentOnlyEnabled;
  let filtered = q ? agents.filter(a => (a.name+a.description+a.id+(a.source||'')).toLowerCase().includes(q)) : agents.slice();
  if (onlyEnabled) filtered = filtered.filter(a => a.scope !== 'plugin' || a.pluginEnabled);

  const groups = { global: [], builtin: [], plugin: [] };
  filtered.forEach(a => { (groups[a.scope] || (groups[a.scope] = [])).push(a); });

  const scopeLabel = { global: '🔧 전역 (~/.claude/agents)', builtin: '⚡ 빌트인 (Claude Code)', plugin: '🔌 플러그인' };
  const scopeOrder = ['global', 'builtin', 'plugin'];

  const modelBg = (m) => ({
    inherit: 'rgba(255,255,255,0.06)',
    haiku: 'rgba(125,211,252,0.18)',
    sonnet: 'rgba(217,119,87,0.18)',
    opus: 'rgba(244,114,182,0.18)',
  })[m] || 'rgba(217,119,87,0.14)';
  const renderAgentCard = a => {
    const readOnly = a.scope === 'builtin';
    const selectorScope = a.scope;
    const displayName = a.name || a.invokeId || a.id || '(이름 없음)';
    const invoke = a.invokeId || a.id || '';
    const safeId = escapeHtml(a.id);
    const scopeBadge = (() => {
      if (a.scope === 'global')  return '<span class="chip chip-ok text-[9px]">✓ 사용자 설정</span>';
      if (a.scope === 'builtin') return '<span class="chip text-[9px]">⚡ 빌트인</span>';
      if (a.scope === 'plugin') {
        if (a.pluginEnabled) return '<span class="chip text-[9px]" style="background:rgba(217,119,87,0.12);">🔌 플러그인 제공</span>';
        return `<button class="chip chip-warn text-[9px] cursor-pointer hover:brightness-125"
                onclick="event.stopPropagation();togglePluginFromAgent('${escapeHtml(a.pluginKey||'')}', true)">비활성 플러그인 ▶ 활성화</button>`;
      }
      return '';
    })();
    const actionButtons = (() => {
      if (a.scope === 'global') {
        const hyperOn = (window.__hyperAgentsMap || {})[a.id];
        const hyperBtn = `<button class="chip text-[9px] cursor-pointer ${hyperOn?'chip-accent':''}"
                onclick='event.stopPropagation();openHyperAgent("${safeId}")'
                title="${t('Hyper Agent — 자동 정교화 토글/설정')}"
                style="${hyperOn?'background:rgba(244,114,182,0.28);color:#fff;':'background:rgba(244,114,182,0.12);'}">⚡ ${hyperOn?'ON':'Hyper'}</button>`;
        return hyperBtn + `<button class="btn text-[9px]" onclick='event.stopPropagation();deleteGlobalAgent("${safeId}")' style="color:#fca5a5">삭제</button>`;
      }
      if (a.scope === 'plugin' && a.pluginEnabled) {
        return `<button class="chip text-[9px] cursor-pointer"
                onclick="event.stopPropagation();togglePluginFromAgent('${escapeHtml(a.pluginKey||'')}', false)" style="color:#fcd34d">비활성화</button>`;
      }
      return '';
    })();
    const modelControl = readOnly
      ? `<span class="chip text-[10px]" style="background:${modelBg(a.model)};">🔒 ${escapeHtml(a.model||'inherit')}</span>`
      : `<select class="input text-[10px] py-1 flex-1"
                style="background:${modelBg(a.model)};"
                onclick="event.stopPropagation();"
                onchange="event.stopPropagation();setSubagentModel('${selectorScope}','${safeId}', this.value)">
           ${(window.__subModelChoices || []).map(m => `<option value="${escapeHtml(m.id)}" ${a.model===m.id?'selected':''}>${escapeHtml(m.label)}</option>`).join('')}
         </select>`;
    return `
      <div class="card p-4 hover-lift cursor-pointer flex flex-col" onclick="viewAgent('${safeId}')">
        <!-- 1행: 이름 (최상단, 카드 전체 폭) -->
        <div class="flex items-center gap-2 mb-1">
          <div class="font-semibold text-sm truncate flex-1" title="${escapeHtml(displayName)}">${escapeHtml(displayName)}</div>
          ${scopeBadge}
          ${actionButtons}
        </div>
        <!-- 2행: 호출 id (마켓프리픽스 포함) -->
        <div class="text-[10px] mono text-[var(--text-dim)] truncate mb-2" title="${escapeHtml(a.source||a.id||'')}">${escapeHtml(invoke)}</div>
        <!-- 3행: 설명 (현재 UI 언어 기준) -->
        <div class="text-xs text-[var(--text-mute)] line-clamp-3 mb-2" style="min-height:3.2em;">${escapeHtml(_localDesc(a) || '—')}</div>
        <!-- 4행: 도구 -->
        <div class="mb-2 flex-1">${(a.tools||[]).slice(0,6).map(t => `<span class="tag-tool">${escapeHtml(t)}</span>`).join('')}</div>
        <!-- 5행: 모델 (별도 줄, 풀폭) -->
        <div class="flex items-center gap-2 pt-2 border-t border-[var(--border)]">
          <span class="text-[10px] text-[var(--text-dim)] whitespace-nowrap">모델</span>
          ${modelControl}
        </div>
        ${a.scope === 'plugin' && !a.pluginEnabled ? '<div class="text-[10px] text-[var(--warn)] mt-2">⚠️ 이 플러그인은 현재 비활성화 — Claude Code 에서 호출되지 않습니다. 플러그인 탭에서 토글</div>' : ''}
      </div>`;
  };

  return `
    <div class="mb-4 flex items-start justify-between gap-3 flex-wrap">
      <div>
        <h1 class="text-2xl font-bold">에이전트 & 상호작용 그래프</h1>
        <p class="text-sm text-[var(--text-mute)] mt-1"><b>활성(사용자 설정 ${counts.global||0} + 빌트인 ${counts.builtin||0}) = ${(counts.global||0)+(counts.builtin||0)}개</b> · 플러그인 제공 ${counts.pluginEnabled||0}/${counts.plugin||0} (별도)</p>
        <div class="text-xs mt-1 flex gap-2 flex-wrap">
          ${_localizedDescStatus(agents)}
          <span class="text-[10px] text-[var(--text-dim)]">💡 플러그인이 <b>비활성</b>이면 에이전트 카드는 보이지만 Claude Code에서 호출되지 않습니다.</span>
        </div>
      </div>
      <div class="flex gap-2">
        <button class="btn text-xs" onclick="openCreateAgent()">＋ 전역 에이전트</button>
        ${_localizeBtnHtml('agent', agents)}
        <a class="btn text-xs" href="${DOCS_BASE}sub-agents" target="_blank" rel="noopener">📖</a>
      </div>
    </div>
    <div class="card p-3 mb-3 text-[11px] text-[var(--text-mute)] flex items-center gap-2">
      <span class="text-base">💡</span>
      <span>그래프 노드는 <b>클릭</b>해서 상세 · 비활성 플러그인 에이전트는 뱃지 클릭으로 즉시 활성화 · 전역 에이전트는 우측 상단 "＋" 로 추가, 카드에서 삭제</span>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-3 gap-4 mb-5">
      <div class="card p-2 lg:col-span-2" style="height: 560px; position: relative;">
        <div class="absolute top-3 left-3 flex items-center gap-2 z-10 flex-wrap">
          <span class="chip chip-accent">🧠 Claude Core</span>
          <span class="chip">🤝 에이전트</span>
          <span class="chip">🛠 도구</span>
          <span class="text-[10px] text-[var(--text-dim)] ml-2">노드 클릭 시 상세</span>
        </div>
        <div id="agentNetwork" style="width:100%; height:100%;"></div>
      </div>
      <div class="card p-4 overflow-y-auto" style="max-height: 560px;">
        <div class="text-xs uppercase text-[var(--text-dim)] mb-3">가장 많이 호출된 에이전트</div>
        ${Object.entries(aggregateAgentCalls(graph)).sort((a,b)=>b[1]-a[1]).slice(0,20).map(([n,c]) => `
          <div class="flex justify-between py-1.5 border-b border-[var(--border)]">
            <span class="text-xs">${escapeHtml(n)}</span>
            <span class="mono text-xs font-bold gradient-text">${c}</span>
          </div>`).join('') || '<div class="empty text-xs">호출 기록 없음</div>'}
      </div>
    </div>

    <!-- v2.41.0 — Agent Teams: pre-baked rosters of agents to spawn together. -->
    <div class="card p-4 mb-5">
      <div class="flex items-center justify-between mb-3">
        <div>
          <h3 class="text-sm font-semibold flex items-center gap-2">👥 ${t('에이전트 팀')}</h3>
          <p class="text-[11px] text-[var(--text-mute)]">${t('자주 같이 쓰는 에이전트들을 묶어 한 번에 spawn — 예: Frontend Crew = ui-designer + frontend-dev + code-reviewer')}</p>
        </div>
        <button class="btn-primary btn text-xs" onclick="openTeamEditor()">＋ ${t('새 팀')}</button>
      </div>
      <div id="teamsGrid" class="grid gap-3" style="grid-template-columns:repeat(auto-fill, minmax(260px, 1fr));">
        <div class="empty text-xs" style="grid-column:1/-1;">${t('로딩…')}</div>
      </div>
    </div>

    <div class="mb-4 flex items-center gap-2 flex-wrap">
      <input id="agentQ" class="input max-w-[280px]" placeholder="에이전트 검색…" value="${escapeHtml(q)}" />
      <label class="flex items-center gap-1 text-xs text-[var(--text-mute)]">
        <input type="checkbox" id="agentOnlyEnabled" ${state.data.agentOnlyEnabled?'checked':''}/> 활성 플러그인만
      </label>
      <span class="text-xs text-[var(--text-dim)]">${filtered.length} / ${agents.length} 표시</span>
    </div>

    ${scopeOrder.map(sc => (groups[sc]||[]).length ? `
      <div class="mb-5">
        <h3 class="text-xs uppercase tracking-widest text-[var(--text-dim)] mb-2">${scopeLabel[sc]||sc} · ${groups[sc].length}</h3>
        <div class="grid-list">
          ${groups[sc].map(renderAgentCard).join('')}
        </div>
      </div>
    ` : '').join('')}

    ${agents.length === 0 ? '<div class="card empty">에이전트가 설치되지 않았습니다.</div>' : ''}
  `;
};
AFTER.agents = () => {
  drawAgentGraph(state.data.agentsGraph || { nodes: [], edges: [] });
  const qEl = document.getElementById('agentQ');
  if (qEl) {
    let d;
    qEl.addEventListener('input', e => {
      clearTimeout(d);
      d = setTimeout(() => { state.data.agentFilter = e.target.value; renderView(); }, 200);
    });
  }
  const chk = document.getElementById('agentOnlyEnabled');
  if (chk) chk.onchange = e => { state.data.agentOnlyEnabled = e.target.checked; renderView(); };
  _loadTeams();
};

// v2.41.0 — Agent Teams: load + render the saved teams grid in the Agents tab.
async function _loadTeams() {
  const grid = document.getElementById('teamsGrid');
  if (!grid) return;
  try {
    const r = await api('/api/agent-teams/list');
    const items = (r && r.items) || [];
    if (!items.length) {
      grid.innerHTML = `<div class="empty text-xs" style="grid-column:1/-1;">${escapeHtml(t('아직 팀이 없습니다. 우측 상단 ＋ 새 팀 으로 만들어보세요.'))}</div>`;
      return;
    }
    grid.innerHTML = items.map(team => {
      const memberChips = (team.agents || []).map(m => {
        const cls = m.exists ? 'chip' : 'chip chip-warn';
        const title = m.exists ? '' : t('에이전트가 디스크에 없음');
        return `<span class="${cls} text-[10px]" title="${escapeHtml(title)}">${escapeHtml(m.name)}${m.scope === 'project' ? ' 📁' : ''}</span>`;
      }).join(' ');
      const missing = team.missingCount || 0;
      return `<div class="card p-3 hover-lift" style="background:rgba(167,139,250,0.05);">
        <div class="flex items-center justify-between mb-2">
          <div class="font-semibold text-sm truncate flex-1" title="${escapeHtml(team.name)}">${escapeHtml(team.name)}</div>
          <span class="text-[10px] text-[var(--text-dim)] mono ml-2">${escapeHtml(team.id)}</span>
        </div>
        ${team.description ? `<div class="text-[11px] text-[var(--text-mute)] mb-2 line-clamp-2" style="min-height:2.6em;">${escapeHtml(team.description)}</div>` : '<div class="text-[11px] text-[var(--text-mute)] mb-2" style="min-height:2.6em;">&nbsp;</div>'}
        <div class="flex flex-wrap gap-1 mb-3" style="min-height:24px;">${memberChips}</div>
        ${missing ? `<div class="text-[10px] text-[#fca5a5] mb-2">⚠ ${missing} ${t('명 디스크에 없음')}</div>` : ''}
        <div class="flex gap-1 flex-wrap pt-2 border-t border-[var(--border)]">
          <button class="btn text-[10px]" data-team-id="${escapeHtml(team.id)}" onclick="_spawnTeam(this.dataset.teamId)">🚀 ${t('Spawn')}</button>
          <button class="btn text-[10px]" data-team-id="${escapeHtml(team.id)}" onclick="openTeamEditor(this.dataset.teamId)">${t('편집')}</button>
          <button class="btn text-[10px]" style="color:#fca5a5;" data-team-id="${escapeHtml(team.id)}" onclick="_deleteTeam(this.dataset.teamId)">${t('삭제')}</button>
        </div>
      </div>`;
    }).join('');
  } catch (e) {
    grid.innerHTML = `<div class="empty text-xs" style="grid-column:1/-1;color:#fca5a5;">${escapeHtml(t('팀 로드 실패: ') + (e.message || ''))}</div>`;
  }
}

function openTeamEditor(teamId) {
  // Builds a minimal modal with a name input, description textarea, and a
  // multi-select of available agents (global + project + builtin). On save,
  // POSTs to /api/agent-teams/save.
  const allAgents = (state.data.agents && state.data.agents.agents) || [];
  // Pre-fill if editing
  let initial = { id: '', name: '', description: '', agents: [] };
  if (teamId) {
    api('/api/agent-teams/get/' + encodeURIComponent(teamId)).then(r => {
      if (r && r.ok && r.team) {
        initial = {
          id: r.team.id,
          name: r.team.name,
          description: r.team.description,
          agents: r.team.agents || [],
        };
        _renderTeamEditorModal(initial, allAgents);
      } else {
        toast(t('팀 로드 실패'), 'err');
      }
    });
    return;
  }
  _renderTeamEditorModal(initial, allAgents);
}

function _renderTeamEditorModal(initial, allAgents) {
  const selectedNames = new Set((initial.agents || []).map(a => a.name + '|' + (a.scope || 'global')));
  const agentOptions = allAgents.map(a => {
    const key = (a.name || a.id) + '|' + (a.scope || 'global');
    const checked = selectedNames.has(key);
    return `<label class="flex items-center gap-2 py-1 px-2 cursor-pointer hover:bg-white/5" style="border-radius:6px;">
      <input type="checkbox" data-name="${escapeHtml(a.name || a.id)}" data-scope="${escapeHtml(a.scope || 'global')}" ${checked ? 'checked' : ''}/>
      <span class="text-xs">${escapeHtml(a.name || a.id)}</span>
      <span class="text-[10px] text-[var(--text-dim)] ml-auto">${escapeHtml(a.scope || 'global')}</span>
    </label>`;
  }).join('') || `<div class="empty text-xs">${t('사용 가능한 에이전트가 없습니다')}</div>`;
  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <div>
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">👥 ${t('에이전트 팀')}</div>
        <h2 class="text-lg font-bold">${initial.id ? t('팀 편집') : t('새 팀')}</h2>
      </div>
      <button class="btn-ghost btn" onclick="closeModal()">✕</button>
    </div>
    <div class="p-5 overflow-y-auto" style="max-height:75vh;">
      <input type="hidden" id="teamId" value="${escapeHtml(initial.id || '')}">
      <label class="block mb-3">
        <div class="text-xs font-semibold mb-1">${t('팀 이름')} *</div>
        <input id="teamName" class="input w-full" value="${escapeHtml(initial.name || '')}" placeholder="${t('예: Frontend Crew')}">
      </label>
      <label class="block mb-3">
        <div class="text-xs font-semibold mb-1">${t('설명')}</div>
        <textarea id="teamDesc" class="input w-full" rows="2">${escapeHtml(initial.description || '')}</textarea>
      </label>
      <div class="text-xs font-semibold mb-1">${t('멤버')} *</div>
      <div class="card p-2" style="max-height:300px;overflow-y:auto;">${agentOptions}</div>
      <div class="flex gap-2 mt-4 pt-3 border-t border-[var(--border)]">
        <button class="btn-primary btn" onclick="_saveTeamFromModal()">💾 ${t('저장')}</button>
        <button class="btn" onclick="closeModal()">${t('취소')}</button>
      </div>
    </div>
  `);
}

async function _saveTeamFromModal() {
  const id   = (document.getElementById('teamId') || {}).value || '';
  const name = (document.getElementById('teamName') || {}).value.trim();
  const desc = (document.getElementById('teamDesc') || {}).value || '';
  if (!name) { toast(t('팀 이름이 필요합니다'), 'err'); return; }
  const agents = Array.from(document.querySelectorAll('.modal input[type=checkbox][data-name]'))
    .filter(c => c.checked)
    .map(c => ({ name: c.dataset.name, scope: c.dataset.scope || 'global' }));
  if (!agents.length) { toast(t('최소 한 명의 에이전트가 필요합니다'), 'err'); return; }
  try {
    const r = await api('/api/agent-teams/save', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ id: id || undefined, name, description: desc, agents }),
    });
    if (r.ok) {
      toast(r.isNew ? t('팀 생성 완료') : t('팀 업데이트 완료'), 'ok');
      closeModal();
      _loadTeams();
    } else {
      toast(t('저장 실패: ') + (r.error || ''), 'err');
    }
  } catch (e) { toast(t('저장 실패: ') + e.message, 'err'); }
}

async function _deleteTeam(teamId) {
  if (!confirm(t('이 팀을 삭제할까요? (멤버 에이전트는 그대로 유지됩니다)'))) return;
  try {
    const r = await api('/api/agent-teams/delete', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ id: teamId }),
    });
    if (r.ok) { toast(t('삭제 완료'), 'ok'); _loadTeams(); }
    else      toast(t('삭제 실패: ') + (r.error || ''), 'err');
  } catch (e) { toast(t('삭제 실패: ') + e.message, 'err'); }
}

async function _spawnTeam(teamId) {
  try {
    const r = await api('/api/agent-teams/spawn', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ id: teamId }),
    });
    if (!r.ok) { toast(t('Spawn 실패: ') + (r.error || ''), 'err'); return; }
    const items = r.spawn || [];
    const skipped = r.skipped || [];
    showModal(`
      <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
        <div>
          <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">🚀 ${t('팀 Spawn')}</div>
          <h2 class="text-lg font-bold">${escapeHtml(t('각 멤버를 어떻게 띄울지 복사·실행'))}</h2>
        </div>
        <button class="btn-ghost btn" onclick="closeModal()">✕</button>
      </div>
      <div class="p-5 overflow-y-auto" style="max-height:75vh;">
        ${items.length === 0 ? `<div class="empty">${escapeHtml(t('실행 가능한 멤버 없음'))}</div>` : items.map((it, i) => `
          <div class="card p-3 mb-2">
            <div class="flex items-center gap-2 mb-1">
              <span class="font-semibold text-sm">${escapeHtml(it.name)}</span>
              <span class="chip text-[10px]">${escapeHtml(it.scope)}</span>
              ${it.role ? `<span class="text-[10px] text-[var(--text-dim)]">${escapeHtml(it.role)}</span>` : ''}
            </div>
            <pre class="mono" style="white-space:pre-wrap;background:rgba(0,0,0,0.3);padding:8px;border-radius:6px;font-size:11px;">${escapeHtml(it.claudeCmd)}</pre>
          </div>
        `).join('')}
        ${skipped.length ? `
          <div class="card p-3 mt-3" style="background:rgba(239,68,68,0.05);border-color:rgba(239,68,68,0.3);">
            <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">${t('건너뛴 멤버')}</div>
            ${skipped.map(s => `<div class="text-xs"><span class="mono">${escapeHtml(s.name)}</span> — ${escapeHtml(s.reason)}</div>`).join('')}
          </div>` : ''}
      </div>
    `);
  } catch (e) { toast(t('Spawn 실패: ') + e.message, 'err'); }
}

function aggregateAgentCalls(graph) {
  const counts = {};
  (graph.edges||[]).forEach(e => {
    if (!String(e.dst).startsWith('tool:')) {
      counts[e.dst] = (counts[e.dst]||0) + e.weight;
    }
  });
  return counts;
}
async function drawAgentGraph(g) {
  if (typeof vis === 'undefined') {
    try { await window._loadVendor('vis'); } catch (_) { return; }
  }
  if (typeof vis === 'undefined') return;
  return _drawAgentGraphImpl(g);
}
function _drawAgentGraphImpl(g) {
  const container = document.getElementById('agentNetwork');
  if (!container || !window.vis) return;
  const nodes = new vis.DataSet((g.nodes||[]).map(n => ({
    id: n.id, label: n.label || n.id,
    shape: n.kind === 'core' ? 'hexagon' : (n.kind === 'tool' ? 'box' : 'dot'),
    size: n.kind === 'core' ? 34 : (n.kind === 'tool' ? 14 : 22),
    kind: n.kind,
    color: n.kind === 'core'
      ? { background: '#a78bfa', border: '#f472b6', highlight: { background: '#f472b6', border: '#fb923c' } }
      : n.kind === 'tool'
      ? { background: 'rgba(103,232,249,0.18)', border: '#67e8f9', highlight: { background: '#67e8f9', border: '#ffffff' } }
      : { background: 'rgba(244,114,182,0.14)', border: '#f472b6', highlight: { background: '#f472b6', border: '#ffffff' } },
    font: { color: '#e7e7ea', size: n.kind === 'core' ? 13 : 11 },
  })));
  const edges = new vis.DataSet((g.edges||[]).map(e => ({
    from: e.src, to: e.dst, value: e.weight,
    color: { color: 'rgba(167,139,250,0.35)', highlight: '#f472b6', opacity: 0.6 },
    arrows: 'to', smooth: { type: 'continuous' },
    title: `${e.src} → ${String(e.dst).replace(/^tool:/,'')} : ${e.weight}회`,
  })));
  // v2.33.6 — stabilization 가벼운 설정 + adaptiveTimestep 으로 20+ 노드에서도 1초 이내 정착
  const net = new vis.Network(container, { nodes, edges }, {
    physics: {
      enabled: true,
      solver: 'barnesHut',
      barnesHut: { gravitationalConstant: -3000, springLength: 110, springConstant: 0.05, avoidOverlap: 0.2 },
      stabilization: { iterations: 120, updateInterval: 25, onlyDynamicEdges: false, fit: true },
      adaptiveTimestep: true,
      timestep: 0.5,
    },
    interaction: { hover: true, selectable: true, tooltipDelay: 120, zoomView: false, dragView: true, dragNodes: true, navigationButtons: false, keyboard: false },
    edges: { scaling: { min: 1, max: 8 }, smooth: { enabled: true, type: 'continuous', roundness: 0.3 } },
    nodes: { shapeProperties: { interpolation: false } },
  });
  container.style.cursor = 'pointer';
  net.once('stabilizationIterationsDone', () => {
    try { net.setOptions({ physics: { enabled: false } }); net.fit({ animation: false }); } catch {}
  });
  const nodeIdx = new Map((g.nodes||[]).map(n => [n.id, n]));
  const handleNode = (nid) => {
    const node = nodeIdx.get(nid);
    if (!node) {
      // fallback: tool:<name> prefix 만 있는 경우
      if (typeof nid === 'string' && nid.startsWith('tool:')) {
        showToolDetailModal(nid.slice(5), g);
      } else {
        viewAgent(String(nid));
      }
      return;
    }
    if (node.kind === 'tool')      showToolDetailModal(String(nid).replace(/^tool:/, ''), g);
    else if (node.kind === 'agent') viewAgent(String(nid));
    else if (node.kind === 'core')  showCoreModal(g);
  };
  net.on('click', params => {
    if (params.nodes && params.nodes.length) handleNode(params.nodes[0]);
  });
  net.on('selectNode', params => {
    if (params.nodes && params.nodes.length) handleNode(params.nodes[0]);
  });
  net.on('doubleClick', params => {
    if (params.nodes && params.nodes.length) handleNode(params.nodes[0]);
  });
}

function showToolDetailModal(toolName, g) {
  const incoming = (g.edges||[]).filter(e => e.dst === `tool:${toolName}`);
  const total = incoming.reduce((a,b)=>a+b.weight, 0);
  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <div>
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">도구</div>
        <h2 class="text-lg font-bold mono">${escapeHtml(toolName)}</h2>
        <div class="text-xs text-[var(--text-mute)] mt-1">최근 60일 총 ${total}회 호출 · ${incoming.length}개 에이전트가 사용</div>
      </div>
      <button class="btn-ghost btn" onclick="closeModal()">✕</button>
    </div>
    <div class="p-5 overflow-y-auto">
      <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">사용한 에이전트</div>
      ${incoming.sort((a,b)=>b.weight-a.weight).map(e => `
        <div class="flex justify-between py-2 border-b border-[var(--border)] cursor-pointer hover:bg-white/5 px-2 rounded"
             onclick="closeModal();viewAgent('${escapeHtml(e.src)}')">
          <span class="text-sm">${escapeHtml(e.src)}</span>
          <span class="mono text-sm gradient-text font-bold">${e.weight}</span>
        </div>`).join('') || '<div class="empty text-xs">호출 기록 없음</div>'}
    </div>
  `);
}

function showCoreModal(g) {
  const outgoing = (g.edges||[]).filter(e => e.src === 'claude');
  const total = outgoing.reduce((a,b)=>a+b.weight, 0);
  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <div>
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">Claude Core</div>
        <h2 class="text-lg font-bold">메인 Claude (Orchestrator)</h2>
        <div class="text-xs text-[var(--text-mute)] mt-1">최근 60일 총 ${total}회 에이전트 위임 · ${outgoing.length}개 에이전트 활용</div>
      </div>
      <button class="btn-ghost btn" onclick="closeModal()">✕</button>
    </div>
    <div class="p-5 overflow-y-auto">
      <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">위임한 에이전트</div>
      ${outgoing.sort((a,b)=>b.weight-a.weight).map(e => `
        <div class="flex justify-between py-2 border-b border-[var(--border)] cursor-pointer hover:bg-white/5 px-2 rounded"
             onclick="closeModal();viewAgent('${escapeHtml(e.dst)}')">
          <span class="text-sm">${escapeHtml(e.dst)}</span>
          <span class="mono text-sm gradient-text font-bold">${e.weight}</span>
        </div>`).join('') || '<div class="empty text-xs">위임 기록 없음</div>'}
    </div>
  `);
}

async function togglePluginFromAgent(pluginKey, enable) {
  if (!pluginKey) { toast('pluginKey 없음', 'err'); return; }
  const r = await api('/api/plugins/toggle', {
    method:'POST', headers:{'Content-Type':'application/json'},
    body: JSON.stringify({ id: pluginKey, enable }),
  });
  if (r.ok) {
    toast(`'${pluginKey}' ${enable?'활성화됨':'비활성화됨'}`, 'ok');
    renderView();
  } else toast(errMsg(r), 'err');
}

async function deleteGlobalAgent(id) {
  const ok = await confirmModal({
    title: t('전역 에이전트 삭제'),
    message: `'${id}' — ~/.claude/agents/${id}.md ` + t('파일이 제거됩니다.'),
    confirmLabel: t('삭제'), danger: true,
  });
  if (!ok) return;
  const r = await api('/api/agents/delete', {
    method:'POST', headers:{'Content-Type':'application/json'},
    body: JSON.stringify({ id }),
  });
  if (r.ok) { toast('삭제됨', 'ok'); renderView(); }
  else toast(errMsg(r), 'err');
}

function openCreateAgent() {
  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <h2 class="font-semibold">＋ 전역 에이전트 추가</h2>
      <button class="btn-ghost btn" onclick="closeModal()">✕</button>
    </div>
    <div class="p-5 space-y-3">
      <div>
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">이름 (파일명, 소문자-하이픈)</div>
        <input id="nagName" class="input" placeholder="예: pr-describer" />
      </div>
      <div>
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">description (에이전트 호출 조건 한 줄)</div>
        <input id="nagDesc" class="input" placeholder="예: PR 설명 자동 생성. Use when the user asks to describe a PR." />
      </div>
      <div class="grid grid-cols-2 gap-3">
        <div>
          <div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">model</div>
          <select id="nagModel" class="input">
            ${(window.__subModelChoices || [
              {id:'inherit', label:'inherit'}, {id:'haiku', label:'Haiku'}, {id:'sonnet', label:'Sonnet'}, {id:'opus', label:'Opus'}
            ]).map(m => `<option value="${escapeHtml(m.id)}" ${m.id==='inherit'?'selected':''}>${escapeHtml(m.label)}</option>`).join('')}
          </select>
        </div>
        <div>
          <div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">tools (콤마)</div>
          <input id="nagTools" class="input" value="Read, Grep, Glob, Edit, Write, Bash" />
        </div>
      </div>
      <div>
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">본문 (에이전트 프롬프트)</div>
        <textarea id="nagContent" class="input" style="min-height:220px;" placeholder="너는 ... 역할이다. 다음 원칙을 지킨다:\n\n1. ...\n2. ..."></textarea>
      </div>
    </div>
    <div class="p-4 border-t border-[var(--border)] flex justify-end gap-2">
      <button class="btn" onclick="closeModal()">취소</button>
      <button class="btn-primary btn" id="nagCreateBtn">＋ 생성</button>
    </div>
  `);
  document.getElementById('nagCreateBtn').onclick = async () => {
    const name = document.getElementById('nagName').value.trim();
    const description = document.getElementById('nagDesc').value.trim();
    const model = document.getElementById('nagModel').value;
    const tools = document.getElementById('nagTools').value.split(',').map(x=>x.trim()).filter(Boolean);
    const content = document.getElementById('nagContent').value;
    if (!name) { toast('이름 필수', 'warn'); return; }
    const r = await api('/api/agents/create', {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({ name, description, model, tools, content }),
    });
    if (r.ok) { toast(`'${r.name}' 생성됨`, 'ok'); closeModal(); renderView(); }
    else toast(errMsg(r), 'err');
  };
}

async function viewAgent(id) {
  const a = await api('/api/agents/' + encodeURIComponent(id));
  if (a.error) { toast(errMsg(a), 'err'); return; }
  if (a.readOnly) {
    showModal(`
      <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
        <div>
          <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">🔒 빌트인 에이전트</div>
          <h2 class="text-lg font-bold">${escapeHtml(a.name)}</h2>
          <div class="text-xs text-[var(--text-mute)] mt-1">${escapeHtml(a.description||'')}</div>
        </div>
        <button class="btn-ghost btn" onclick="closeModal()">✕</button>
      </div>
      <div class="p-5 overflow-y-auto">
        <div class="text-sm text-[var(--text-mute)] mb-3">${escapeHtml(a.content)}</div>
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">사용 가능 도구</div>
        <div>${(a.tools||[]).map(t => `<span class="tag-tool">${escapeHtml(t)}</span>`).join('') || '—'}</div>
        <div class="text-[11px] uppercase text-[var(--text-dim)] mt-4 mb-2">모델</div>
        <div class="mono text-sm">${escapeHtml(a.model||'inherit')}</div>
      </div>
    `);
    return;
  }
  showEditModal({
    title: `에이전트 편집 — ${a.name}`,
    raw: a.raw,
    save: async (v) => api('/api/agents/' + encodeURIComponent(id), {
      method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ raw: v })
    }),
  });
}

// ────────────────────────────────────────────────────────────────
// HYPER AGENT — auto-refining sub-agent settings (v2.39.0)
// ────────────────────────────────────────────────────────────────
async function openHyperAgent(name, cwd) {
  const safe = encodeURIComponent(name);
  let metaP, histP;
  if (cwd) {
    // Project scope — cwd doesn't fit in URL → POST endpoints
    metaP = api('/api/hyper-agents/get', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({name, cwd})
    }).catch(e => ({error: String(e)}));
    histP = api('/api/hyper-agents/history', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({name, cwd})
    }).catch(() => ({history:[]}));
  } else {
    metaP = api('/api/hyper-agents/get/' + safe).catch(e => ({error: String(e)}));
    histP = api('/api/hyper-agents/history/' + safe).catch(() => ({history:[]}));
  }
  const [meta, hist] = await Promise.all([metaP, histP]);
  if (meta.error) { toast(t('Hyper Agent 로드 실패: ') + meta.error, 'err'); return; }
  const ag = meta.agent || {};
  const history = (hist.history || []).slice().reverse();
  showModal(_hyperModalHTML(name, ag, history, cwd));
  _hyperBindControls(name, cwd);
}

function _hyperEsc(s) { return escapeHtml(s == null ? '' : String(s)); }

function _hyperModalHTML(name, ag, history, cwd) {
  const targets = ag.refineTargets || ['systemPrompt'];
  const hasTarget = (k) => targets.includes(k) ? 'checked' : '';
  const triggerOpts = ['manual','after_session','interval','any','cron'].map(opt =>
    `<option value="${opt}" ${ag.trigger===opt?'selected':''}>${_hyperEsc(opt)}</option>`).join('');
  const providerOpts = (window.__subModelChoices || []).map(m =>
    `<option value="claude:${_hyperEsc(m.id)}" ${ag.refineProvider==='claude:'+m.id?'selected':''}>claude:${_hyperEsc(m.id)}</option>`).join('');

  return `
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between" style="background:linear-gradient(135deg, rgba(244,114,182,0.1), rgba(167,139,250,0.06));">
      <div>
        <div class="text-[11px] uppercase tracking-widest" style="color:#f9a8d4;">⚡ ${t('Hyper Agent')}</div>
        <h2 class="text-lg font-bold">${_hyperEsc(name)}</h2>
        <div class="text-xs text-[var(--text-mute)] mt-1">${t('서브 에이전트의 시스템 프롬프트·툴·디스크립션을 메타 LLM이 주기적으로 다듬습니다.')}</div>
      </div>
      <button class="btn-ghost btn" onclick="closeModal()" aria-label="닫기">✕</button>
    </div>
    <div class="p-5 overflow-y-auto" style="max-height: 70vh;" id="hyperModalBody">
      <div class="card p-4 mb-3" style="background:rgba(0,0,0,0.15);">
        <div class="flex items-center justify-between">
          <div>
            <div class="font-semibold text-sm">${t('자동 정교화 활성화')}</div>
            <div class="text-[11px] text-[var(--text-dim)] mt-1">${t('OFF 상태에서도 "지금 다듬기" 버튼은 사용 가능합니다.')}</div>
          </div>
          <div id="hyperToggle" class="qs-toggle ${ag.enabled?'on':''}" data-enabled="${ag.enabled?'1':'0'}" role="switch" aria-checked="${!!ag.enabled}" tabindex="0"></div>
        </div>
      </div>

      <label class="block mb-3">
        <div class="text-xs font-semibold mb-1">${t('목표 (Objective)')}</div>
        <textarea id="hyperObjective" class="input w-full" rows="3"
          placeholder="${t('예: 응답을 더 간결하게, 액션 위주로. 또는 특정 도메인 지식 강조.')}">${_hyperEsc(ag.objective)}</textarea>
      </label>

      <div class="grid grid-cols-1 sm:grid-cols-3 gap-2 mb-3">
        <label class="card p-2 cursor-pointer flex items-center gap-2">
          <input type="checkbox" id="hyperTgt_systemPrompt" ${hasTarget('systemPrompt')}/>
          <span class="text-xs">${t('시스템 프롬프트')}</span>
        </label>
        <label class="card p-2 cursor-pointer flex items-center gap-2">
          <input type="checkbox" id="hyperTgt_tools" ${hasTarget('tools')}/>
          <span class="text-xs">${t('툴 목록')}</span>
        </label>
        <label class="card p-2 cursor-pointer flex items-center gap-2">
          <input type="checkbox" id="hyperTgt_description" ${hasTarget('description')}/>
          <span class="text-xs">${t('디스크립션')}</span>
        </label>
      </div>

      <div class="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-3">
        <label class="block">
          <div class="text-xs font-semibold mb-1">${t('트리거')}</div>
          <select id="hyperTrigger" class="input w-full">${triggerOpts}</select>
          <div class="text-[10px] mt-1" style="color:var(--text-dim);">${t('manual=수동만 / after_session=세션 종료 시 / interval=시간 주기 / any=둘 다')}</div>
        </label>
        <label class="block">
          <div class="text-xs font-semibold mb-1">${t('Refine 프로바이더')}</div>
          <select id="hyperProvider" class="input w-full">${providerOpts}<option value="claude:opus" ${ag.refineProvider==='claude:opus'?'selected':''}>claude:opus</option></select>
          <div class="text-[10px] mt-1" style="color:var(--text-dim);">${t('메타 LLM (Opus 권장)')}</div>
        </label>
      </div>

      <div class="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-3">
        <label class="block">
          <div class="text-xs font-semibold mb-1">${t('최소 세션 간격')}</div>
          <input id="hyperMinSessions" type="number" class="input w-full" value="${ag.minSessionsBetween||5}" min="0" max="1000"/>
          <div class="text-[10px] mt-1" style="color:var(--text-dim);">${t('after_session 트리거 디바운스')}</div>
        </label>
        <label class="block">
          <div class="text-xs font-semibold mb-1">${t('예산 (USD)')}</div>
          <input id="hyperBudget" type="number" step="0.5" class="input w-full" value="${ag.budgetUSD||5}" min="0"/>
          <div class="text-[10px] mt-1" style="color:var(--text-dim);">${t('총 누적 비용 한도 (도달 시 정지)')}</div>
        </label>
        <div class="block">
          <div class="text-xs font-semibold mb-1">${t('누적 사용 / 정교화')}</div>
          <div class="text-sm mono" id="hyperSpent">$${(ag.spentUSD||0).toFixed(4)} · ${ag.totalRefinements||0}회</div>
        </div>
      </div>

      <div class="flex flex-wrap gap-2 pt-2" style="border-top:1px solid var(--border);">
        <button id="hyperSave" class="btn-primary btn">${t('💾 저장')}</button>
        <button id="hyperRefineDry" class="btn">${t('👁 Dry-run 미리보기')}</button>
        <button id="hyperRefine" class="btn" style="background:rgba(244,114,182,0.18);">${t('⚡ 지금 다듬기')}</button>
      </div>
      <div id="hyperLastError" class="text-[11px] mt-2" style="color:#fca5a5;">${ag.lastError ? '⚠️ ' + _hyperEsc(ag.lastError) : ''}</div>

      <div class="mt-5">
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)] mb-2">${t('정교화 이력')} (${history.length})</div>
        <div id="hyperHistory" class="grid gap-2">
          ${history.map(h => _hyperHistoryRow(name, h, cwd)).join('') || `<div class="empty text-xs">${t('아직 정교화 이력이 없습니다.')}</div>`}
        </div>
      </div>
    </div>
  `;
}

function _hyperHistoryRow(name, h, cwd) {
  const dt = h.ts ? new Date(h.ts).toLocaleString() : '—';
  const trigger = _hyperEsc(h.trigger || '');
  const score = (h.scoreBefore != null && h.scoreAfter != null)
    ? `<span class="chip text-[10px]">${(+h.scoreBefore).toFixed(2)} → ${(+h.scoreAfter).toFixed(2)}</span>`
    : '';
  const targets = (h.appliedTargets || []).map(t2 => `<span class="tag-tool">${_hyperEsc(t2)}</span>`).join('');
  const cost = h.costUSD ? `$${(+h.costUSD).toFixed(4)}` : '—';
  const tokens = h.tokens ? `${h.tokens} tok` : '—';
  const error = h.error ? `<div class="text-[11px] mt-1" style="color:#fca5a5;">⚠️ ${_hyperEsc(h.error)}</div>` : '';
  const dryFlag = h.dryRun ? '<span class="chip chip-warn text-[10px]">dry-run</span>' : '';
  const cwdArg = cwd ? `, ${JSON.stringify(cwd)}` : '';
  const rollback = (!h.dryRun && h.backupPath && h.appliedTargets && h.appliedTargets.length)
    ? `<button class="btn text-[10px]" onclick="_hyperRollback('${_hyperEsc(name)}', ${+h.ts}${cwdArg})">↩ ${t('롤백')}</button>`
    : '';
  const showDiff = (h.diff && Object.keys(h.diff).length)
    ? `<button class="btn text-[10px]" onclick="_hyperToggleDiff(this)">📋 diff</button>`
    : '';
  const diffData = h.diff ? jsonAttr(h.diff) : '';
  return `
    <div class="card p-3" data-diff="${diffData}">
      <div class="flex items-center gap-2 flex-wrap">
        <span class="text-[11px] mono">${_hyperEsc(dt)}</span>
        <span class="chip text-[10px]">${trigger}</span>
        ${dryFlag}
        ${score}
        ${targets}
        <span class="text-[10px] text-[var(--text-dim)] ml-auto">${cost} · ${tokens}</span>
      </div>
      ${h.rationale ? `<div class="text-[12px] mt-1.5" style="color:var(--text-mute);">${_hyperEsc(h.rationale)}</div>` : ''}
      ${error}
      <div class="mt-2 flex gap-2">
        ${showDiff}
        ${rollback}
      </div>
      <pre class="hyper-diff" style="display:none;white-space:pre-wrap;font-size:10.5px;background:rgba(0,0,0,0.3);padding:8px;border-radius:6px;margin-top:8px;max-height:300px;overflow:auto;"></pre>
    </div>
  `;
}

function _hyperToggleDiff(btn) {
  const card = btn.closest('.card');
  const pre  = card.querySelector('.hyper-diff');
  if (!pre) return;
  if (pre.style.display === 'none') {
    let diff = {};
    try { diff = JSON.parse(card.getAttribute('data-diff') || '{}'); } catch {}
    const out = [];
    for (const k of Object.keys(diff)) {
      out.push('## ' + k);
      out.push('--- before ---');
      out.push(typeof diff[k].before === 'string' ? diff[k].before : JSON.stringify(diff[k].before, null, 2));
      out.push('+++ after +++');
      out.push(typeof diff[k].after  === 'string' ? diff[k].after  : JSON.stringify(diff[k].after, null, 2));
      out.push('');
    }
    pre.textContent = out.join('\n');
    pre.style.display = '';
  } else {
    pre.style.display = 'none';
  }
}

function _hyperCollectPatch() {
  const targets = [];
  if (document.getElementById('hyperTgt_systemPrompt').checked) targets.push('systemPrompt');
  if (document.getElementById('hyperTgt_tools').checked)        targets.push('tools');
  if (document.getElementById('hyperTgt_description').checked)  targets.push('description');
  return {
    enabled:            document.getElementById('hyperToggle').dataset.enabled === '1',
    objective:          document.getElementById('hyperObjective').value,
    refineTargets:      targets.length ? targets : ['systemPrompt'],
    trigger:            document.getElementById('hyperTrigger').value,
    refineProvider:     document.getElementById('hyperProvider').value,
    minSessionsBetween: parseInt(document.getElementById('hyperMinSessions').value, 10) || 5,
    budgetUSD:          parseFloat(document.getElementById('hyperBudget').value) || 5,
  };
}

function _hyperBindControls(name, cwd) {
  const tg = document.getElementById('hyperToggle');
  if (tg) {
    const flip = () => {
      const next = tg.dataset.enabled !== '1';
      tg.dataset.enabled = next ? '1' : '0';
      tg.classList.toggle('on', next);
      tg.setAttribute('aria-checked', String(next));
    };
    tg.onclick = flip;
    tg.onkeydown = e => { if (e.key === ' ' || e.key === 'Enter') { e.preventDefault(); flip(); } };
  }
  const save = document.getElementById('hyperSave');
  if (save) save.onclick = async () => {
    save.disabled = true; save.textContent = '...';
    try {
      const body = { name, patch: _hyperCollectPatch() };
      if (cwd) body.cwd = cwd;
      const r = await api('/api/hyper-agents/configure', {
        method: 'POST', headers: {'Content-Type': 'application/json'},
        body: JSON.stringify(body),
      });
      if (r.ok) {
        toast(t('저장됨'), 'ok');
        // Only mirror global into the visible-on-list map; project entries
        // get refreshed via the projectAgents view's own fetch.
        if (!cwd) { window.__hyperAgentsMap = window.__hyperAgentsMap || {}; window.__hyperAgentsMap[name] = r.agent.enabled; }
      }
      else toast(t('저장 실패: ') + (r.error || ''), 'err');
    } catch (e) { toast(t('저장 실패: ') + e.message, 'err'); }
    finally { save.disabled = false; save.textContent = t('💾 저장'); }
  };
  const dry = document.getElementById('hyperRefineDry');
  if (dry) dry.onclick = () => _hyperRefineNow(name, true, cwd);
  const ref = document.getElementById('hyperRefine');
  if (ref) ref.onclick = () => _hyperRefineNow(name, false, cwd);
}

async function _hyperRefineNow(name, dryRun, cwd) {
  if (!dryRun && !confirm(t('이 에이전트를 지금 다듬을까요? 메타 LLM 호출 비용이 발생합니다.'))) return;
  const btn = document.getElementById(dryRun ? 'hyperRefineDry' : 'hyperRefine');
  if (btn) { btn.disabled = true; btn.textContent = '⏳ ' + t('진행 중'); }
  try {
    // Save current settings first so the worker uses the latest objective/targets
    const cfg = { name, patch: _hyperCollectPatch() };
    if (cwd) cfg.cwd = cwd;
    await api('/api/hyper-agents/configure', {
      method: 'POST', headers: {'Content-Type': 'application/json'},
      body: JSON.stringify(cfg),
    });
    const refineBody = { name, dryRun };
    if (cwd) refineBody.cwd = cwd;
    const r = await api('/api/hyper-agents/refine-now', {
      method: 'POST', headers: {'Content-Type': 'application/json'},
      body: JSON.stringify(refineBody),
    });
    if (r.ok) {
      toast(dryRun ? t('Dry-run 완료 — 제안 확인') : t('정교화 적용 완료'), 'ok');
      openHyperAgent(name, cwd);
    } else {
      toast(t('실패: ') + (r.error || ''), 'err');
      if (btn) { btn.disabled = false; btn.textContent = dryRun ? t('👁 Dry-run 미리보기') : t('⚡ 지금 다듬기'); }
    }
  } catch (e) {
    toast(t('실패: ') + e.message, 'err');
    if (btn) { btn.disabled = false; btn.textContent = dryRun ? t('👁 Dry-run 미리보기') : t('⚡ 지금 다듬기'); }
  }
}

async function _hyperRollback(name, ts, cwd) {
  if (!confirm(t('이 시점의 백업으로 에이전트를 되돌릴까요?'))) return;
  try {
    const body = { name, versionTs: ts };
    if (cwd) body.cwd = cwd;
    const r = await api('/api/hyper-agents/rollback', {
      method: 'POST', headers: {'Content-Type': 'application/json'},
      body: JSON.stringify(body),
    });
    if (r.ok) { toast(t('롤백 완료'), 'ok'); openHyperAgent(name, cwd); }
    else toast(t('롤백 실패: ') + (r.error || ''), 'err');
  } catch (e) { toast(t('롤백 실패: ') + e.message, 'err'); }
}

// ────────────────────────────────────────────────────────────────
// SKILLS
// ────────────────────────────────────────────────────────────────
VIEWS.skills = async () => {
  // v2.43.0 — global ↔ project scope. Project mode shows only the current
  // project's `<cwd>/.claude/skills/*` (no plugin / global mixing).
  const projects = await _ensureProjectsCache();
  const cfgScope = state.data.cfgScope || 'global';
  const cfgCwd = state.data.cfgCwd || (projects[0]?.path || '');
  const inProject = cfgScope === 'project' && cfgCwd;
  let skills;
  if (inProject) {
    const r = await api('/api/project/skills/list?cwd=' + encodeURIComponent(cfgCwd));
    skills = (r.skills || []).map(s => ({...s, scope: 'project', source: 'project', pluginEnabled: false}));
  } else {
    skills = await cachedApi('/api/skills', 60000);
  }
  state.data.skills = skills;
  const q = (state.data.skillsFilter || '').toLowerCase();
  const onlyEnabled = !!state.data.skillsOnlyEnabled;
  let filtered = skills.filter(s => !q || (s.name+s.description+s.id+(_localDesc(s)||'')).toLowerCase().includes(q));
  if (onlyEnabled) filtered = filtered.filter(s => s.scope === 'user');

  const groups = { user: [], plugin: [], project: [] };
  filtered.forEach(s => { (groups[s.scope] || (groups[s.scope] = [])).push(s); });

  const userN = skills.filter(s => s.scope === 'user').length;
  const pluginN = skills.filter(s => s.scope === 'plugin').length;
  const pluginEnabledN = skills.filter(s => s.scope === 'plugin' && s.pluginEnabled).length;
  const projectN = skills.filter(s => s.scope === 'project').length;

  const renderSkillCard = s => {
    const scopeBadge = s.scope === 'plugin'
      ? (s.pluginEnabled
          ? '<span class="chip text-[9px]" style="background:rgba(217,119,87,0.12);">🔌 ' + t('플러그인 제공') + '</span>'
          : `<button class="chip chip-warn text-[9px]" onclick="event.stopPropagation();togglePluginFromAgent('${escapeHtml(s.pluginKey||'')}', true)">${t('비활성 플러그인 ▶ 활성화')}</button>`)
      : (s.scope === 'project'
          ? '<span class="chip text-[9px]" style="background:rgba(125,211,252,0.18);">📁 ' + t('프로젝트') + '</span>'
          : '<span class="chip chip-ok text-[9px]">✓ ' + t('사용자 설정') + '</span>');
    const editFn = s.scope === 'project'
      ? `editProjectSkill('${escapeHtml(s.id)}')`
      : `editSkill('${escapeHtml(s.id)}')`;
    return `
      <div class="card p-4 hover-lift cursor-pointer" onclick="${editFn}">
        <div class="flex items-center gap-2 mb-1">
          <div class="font-semibold text-sm truncate flex-1">${escapeHtml(s.name)}</div>
          ${scopeBadge}
        </div>
        <div class="text-[10px] mono text-[var(--text-dim)] mb-2 truncate" title="${escapeHtml(s.source||'')}">${escapeHtml(s.id)}</div>
        <div class="text-xs text-[var(--text-mute)] line-clamp-3">${escapeHtml(_localDesc(s) || '—')}</div>
        ${s.scope === 'plugin' && !s.pluginEnabled ? '<div class="text-[10px] text-[var(--warn)] mt-2">⚠️ ' + t('이 플러그인은 비활성 — Claude Code 가 호출하지 않습니다.') + '</div>' : ''}
      </div>`;
  };

  const groupLabel = {
    user: '🔧 ' + t('전역') + ' (~/.claude/skills)',
    plugin: '🔌 ' + t('플러그인'),
    project: '📁 ' + t('프로젝트') + ' (' + (cfgCwd ? cfgCwd + '/.claude/skills' : '') + ')',
  };
  const groupOrder = inProject ? ['project'] : ['user', 'plugin'];
  const subtitle = inProject
    ? `<b>${t('프로젝트 스킬')} ${projectN}${t('개')}</b>`
    : `<b>${t('활성(사용자 설정)')} ${userN}${t('개')}</b> · ${t('플러그인 제공')} ${pluginEnabledN}/${pluginN} (${t('별도')}) · ${_localizedDescStatusText(skills)}`;

  return `
    ${_renderConfigScopeToggle({scope: cfgScope, cwd: cfgCwd, projects, label: t('스킬 스코프')})}
    <div class="mb-4 flex items-center justify-between gap-3 flex-wrap">
      <div>
        <h1 class="text-2xl font-bold">${t('스킬')}</h1>
        <p class="text-sm text-[var(--text-mute)] mt-1">${subtitle}</p>
      </div>
      <div class="flex gap-2">
        <input id="skillQ" class="input max-w-[260px]" placeholder="${t('스킬 검색…')}" value="${escapeHtml(state.data.skillsFilter||'')}" />
        ${inProject ? '' : `<label class="flex items-center gap-1 text-xs text-[var(--text-mute)]">
          <input type="checkbox" id="skillOnlyEnabled" ${onlyEnabled?'checked':''}/> ${t('사용자 설정만')}
        </label>`}
        ${inProject ? `<button class="btn-primary btn text-xs" onclick="newProjectSkill()">＋ ${t('새 스킬')}</button>` : _localizeBtnHtml('skill', skills)}
        <a class="btn text-xs" href="${DOCS_BASE}skills" target="_blank" rel="noopener">📖</a>
      </div>
    </div>
    ${groupOrder.map(g => (groups[g]||[]).length ? `
      <div class="mb-5">
        <h3 class="text-xs uppercase tracking-widest text-[var(--text-dim)] mb-2">${groupLabel[g]} · ${groups[g].length}</h3>
        <div class="grid-list">${groups[g].map(renderSkillCard).join('')}</div>
      </div>` : '').join('')}
    ${filtered.length === 0 ? `<div class="card empty" style="grid-column:1/-1;">${t('스킬 없음')}</div>` : ''}
  `;
};
AFTER.skills = () => {
  const el = document.getElementById('skillQ');
  if (el) {
    let d;
    el.addEventListener('input', e => {
      clearTimeout(d);
      d = setTimeout(() => { state.data.skillsFilter = e.target.value; renderView(); }, 200);
    });
  }
  const oe = document.getElementById('skillOnlyEnabled');
  if (oe) oe.addEventListener('change', e => { state.data.skillsOnlyEnabled = e.target.checked; renderView(); });
};
async function editSkill(id) {
  const s = await api('/api/skills/' + encodeURIComponent(id));
  if (s.error) { toast(t('스킬 로드 실패') + ': ' + s.error, 'err'); return; }
  const isReadOnly = !!s.readOnly;
  showEditModal({
    title: (isReadOnly ? '🔒 ' + t('플러그인 스킬 (read-only)') + ' — ' : t('스킬 편집') + ' — ') + s.name,
    raw: s.raw,
    readOnly: isReadOnly,
    save: isReadOnly ? null : async (v) => api('/api/skills/' + encodeURIComponent(id), {
      method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ raw: v })
    }),
  });
}
async function editProjectSkill(id) {
  const cwd = state.data.cfgCwd;
  if (!cwd) { toast(t('프로젝트가 선택되지 않았습니다'), 'err'); return; }
  const s = await api('/api/project/skill?cwd=' + encodeURIComponent(cwd) + '&id=' + encodeURIComponent(id));
  if (!s.ok) { toast(t('스킬 로드 실패') + ': ' + (s.error||''), 'err'); return; }
  showEditModal({
    title: '📁 ' + t('프로젝트 스킬 편집') + ' — ' + s.name,
    raw: s.raw,
    save: async (v) => api('/api/project/skill', {
      method: 'PUT', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ cwd, id, raw: v }),
    }),
    onAfterSave: () => renderView(),
  });
}
async function newProjectSkill() {
  const cwd = state.data.cfgCwd;
  if (!cwd) { toast(t('프로젝트가 선택되지 않았습니다'), 'err'); return; }
  const id = await promptModal({
    title: t('새 프로젝트 스킬'),
    message: t('스킬 ID — 영숫자 / 하이픈 / 언더스코어'),
    placeholder: 'my-skill',
    defaultValue: '',
    confirmLabel: t('생성'),
  });
  if (!id || !/^[a-zA-Z0-9_-]{1,64}$/.test(id)) {
    if (id) toast(t('잘못된 스킬 ID'), 'err');
    return;
  }
  const seed = `---\nname: ${id}\ndescription: \n---\n\n# ${id}\n\n`;
  const r = await api('/api/project/skill', {
    method: 'PUT', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ cwd, id, raw: seed }),
  });
  if (!r.ok) { toast(t('생성 실패') + ': ' + (r.error||''), 'err'); return; }
  toast(t('생성됨'), 'ok');
  renderView();
}
async function editProjectCommand(id) {
  const cwd = state.data.cfgCwd;
  if (!cwd) { toast(t('프로젝트가 선택되지 않았습니다'), 'err'); return; }
  const c = await api('/api/project/command?cwd=' + encodeURIComponent(cwd) + '&id=' + encodeURIComponent(id));
  if (!c.ok) { toast(t('명령어 로드 실패') + ': ' + (c.error||''), 'err'); return; }
  showEditModal({
    title: '📁 ' + t('프로젝트 명령어 편집') + ' — /' + (c.name || c.id),
    raw: c.raw,
    save: async (v) => api('/api/project/command', {
      method: 'PUT', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ cwd, id, raw: v }),
    }),
    onAfterSave: () => renderView(),
  });
}
async function newProjectCommand() {
  const cwd = state.data.cfgCwd;
  if (!cwd) { toast(t('프로젝트가 선택되지 않았습니다'), 'err'); return; }
  const id = await promptModal({
    title: t('새 프로젝트 명령어'),
    message: t("명령어 ID — '/' 대신 영숫자 / '-' / '_' / 하위경로는 ':' 사용"),
    placeholder: 'review',
    defaultValue: '',
    confirmLabel: t('생성'),
  });
  if (!id) return;
  const rel = id.replace(/:/g, '/');
  if (!/^[a-zA-Z0-9_-][a-zA-Z0-9_./-]{0,127}$/.test(rel)) {
    toast(t('잘못된 명령어 ID'), 'err'); return;
  }
  const seed = `---\nname: ${id}\ndescription: \n---\n\n# /${id}\n\n`;
  const r = await api('/api/project/command', {
    method: 'PUT', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ cwd, id, raw: seed }),
  });
  if (!r.ok) { toast(t('생성 실패') + ': ' + (r.error||''), 'err'); return; }
  toast(t('생성됨'), 'ok');
  renderView();
}
async function deleteProjectCommand(id) {
  const cwd = state.data.cfgCwd;
  if (!cwd) return;
  if (!await confirmModal({
    title: t('프로젝트 명령어 삭제'),
    message: '/' + id + ' — ' + t('이 명령어를 삭제할까요?'),
    confirmLabel: t('삭제'), danger: true,
  })) return;
  const r = await api('/api/project/command/delete', {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ cwd, id }),
  });
  toast(r.ok ? t('삭제됨') : (t('실패') + ': ' + (r.error||'')), r.ok?'ok':'err');
  if (r.ok) renderView();
}

// ────────────────────────────────────────────────────────────────
// COMMANDS
// ────────────────────────────────────────────────────────────────
VIEWS.commands = async () => {
  const projects = await _ensureProjectsCache();
  const cfgScope = state.data.cfgScope || 'global';
  const cfgCwd = state.data.cfgCwd || (projects[0]?.path || '');
  const inProject = cfgScope === 'project' && cfgCwd;
  let cmds;
  if (inProject) {
    const r = await api('/api/project/commands/list?cwd=' + encodeURIComponent(cfgCwd));
    cmds = (r.commands || []).map(c => ({
      ...c, scope: 'project',
      category: 'other', categoryLabel: '📁 ' + t('프로젝트'),
    }));
  } else {
    cmds = await cachedApi('/api/commands', 60000);
  }
  state.data.commands = cmds;
  const q = (state.data.cmdFilter || '').toLowerCase();
  const selCat = state.data.cmdCat || '';
  const onlyUntranslated = !!state.data.cmdOnlyUntranslated;

  const filtered = cmds.filter(c => {
    if (q) {
      const t = (c.name+' '+c.description+' '+c.id+' '+(_localDesc(c)||'')).toLowerCase();
      if (!t.includes(q)) return false;
    }
    if (selCat && c.category !== selCat) return false;
    if (onlyUntranslated && _localDesc(c)) return false;
    return true;
  });

  // 카테고리별 그룹
  const groups = {};
  filtered.forEach(c => { (groups[c.category] = groups[c.category] || []).push(c); });
  const catLabels = {};
  cmds.forEach(c => { catLabels[c.category] = c.categoryLabel; });
  const catOrder = Object.keys(groups).sort((a,b) => (groups[b].length) - (groups[a].length));

  // 카테고리 칩 (전체 명령어 기준 분포)
  const allCatCounts = {};
  cmds.forEach(c => { allCatCounts[c.category] = (allCatCounts[c.category]||0) + 1; });
  const catChips = Object.entries(allCatCounts)
    .sort((a,b) => b[1] - a[1])
    .map(([cid, n]) => `<button class="chip ${cid===selCat?'chip-accent':''}" onclick="setCmdCat('${cid}')">${catLabels[cid]||cid} <span class="ml-1 text-[9px] text-[var(--text-dim)]">${n}</span></button>`)
    .join('');

  return `
    ${_renderConfigScopeToggle({scope: cfgScope, cwd: cfgCwd, projects, label: t('명령어 스코프')})}
    <div class="mb-4 flex items-center justify-between gap-3 flex-wrap">
      <div>
        <h1 class="text-2xl font-bold">${t('슬래시 명령어')}</h1>
        <p class="text-sm text-[var(--text-mute)] mt-1">${cmds.length}${t('개 명령어')}${inProject ? '' : ' · ' + Object.keys(allCatCounts).length + t('개 카테고리') + ' · ' + _localizedDescStatusText(cmds)}</p>
      </div>
      <div class="flex gap-2 flex-wrap">
        <input id="cmdQ" class="input max-w-[260px]" placeholder="${t('검색…')}" value="${escapeHtml(state.data.cmdFilter||'')}" />
        ${inProject ? `<button class="btn-primary btn text-xs" onclick="newProjectCommand()">＋ ${t('새 명령어')}</button>` : `<label class="flex items-center gap-1 text-xs text-[var(--text-mute)]">
          <input type="checkbox" id="cmdOnlyUntr" ${onlyUntranslated?'checked':''}/> ${t('미번역만')}
        </label>
        ${_localizeBtnHtml('cmd', cmds)}`}
        <a class="btn text-xs" href="${DOCS_BASE}slash-commands" target="_blank" rel="noopener">📖</a>
      </div>
    </div>
    ${inProject ? '' : `<div class="card p-3 mb-4 flex flex-wrap gap-2">
      <button class="chip ${!selCat?'chip-accent':''}" onclick="setCmdCat('')">${t('전체')} ${cmds.length}</button>
      ${catChips}
    </div>`}

    ${catOrder.length ? catOrder.map(cid => `
      <div class="mb-5">
        <h3 class="text-xs uppercase tracking-widest text-[var(--text-dim)] mb-2">${catLabels[cid]||cid} · ${groups[cid].length}</h3>
        <div class="grid-list">
          ${groups[cid].map(c => {
            // v2.36.0 — Heuristic: ECC commands have plugin scope or path under
            // ~/.claude/plugins/cache/ecc/. Use this to route Run via Run Center.
            const isEcc = (c.scope === 'plugin') || /\/plugins\/cache\/ecc\//.test(c.path||'') || /^ecc[:/]/i.test(c.id||'');
            const cmdName = c.name || c.id;
            const itemId = isEcc ? `ecc:cmd:${cmdName.replace(/^\//, '')}` : '';
            const isProj = c.scope === 'project';
            const editFn = isProj ? `editProjectCommand('${escapeHtml(c.id)}')` : '';
            return `
            <div class="card p-4 hover-lift ${isProj?'cursor-pointer':''}" ${isProj?`onclick="${editFn}"`:''}>
              <div class="flex items-center gap-2 mb-2 flex-wrap">
                <span class="chip ${c.scope==='user'?'chip-ok':'chip-accent'}">${c.scope}</span>
                ${isEcc ? '<span class="chip" style="background:rgba(217,119,87,0.18);border-color:rgba(217,119,87,0.45);color:var(--text);">ECC</span>' : ''}
                <span class="font-semibold text-sm mono">/${escapeHtml(cmdName)}</span>
                ${isProj
                  ? `<button class="btn text-[10px] ml-auto" onclick="event.stopPropagation();deleteProjectCommand('${escapeHtml(c.id)}')" style="color:#fca5a5;">${t('삭제')}</button>`
                  : `<button class="btn text-[10px] ml-auto" onclick="_cmdQuickRun('${escapeHtml(itemId || cmdName)}', ${isEcc ? 'true' : 'false'}, '${escapeHtml(cmdName)}')" title="${t('대시보드에서 바로 실행')}">▶ ${t('실행')}</button>`}
              </div>
              <div class="text-xs text-[var(--text-mute)] line-clamp-3">${escapeHtml(_localDesc(c) || c.description || '—')}</div>
            </div>`;
          }).join('')}
        </div>
      </div>`).join('') : `<div class="card empty">${t('명령어 없음')}</div>`}
  `;
};
AFTER.commands = () => {
  const el = document.getElementById('cmdQ');
  if (el) {
    let d;
    el.addEventListener('input', e => {
      clearTimeout(d);
      d = setTimeout(() => { state.data.cmdFilter = e.target.value; renderView(); }, 200);
    });
  }
  const chk = document.getElementById('cmdOnlyUntr');
  if (chk) chk.onchange = e => { state.data.cmdOnlyUntranslated = e.target.checked; renderView(); };
};

function setCmdCat(cat) {
  state.data.cmdCat = cat;
  renderView();
}

// v2.36.0 — Run a slash command directly from the Commands tab. ECC commands
// route through Run Center (have full execution context); non-ECC just open
// the Run Center modal with a generic dispatch.
async function _cmdQuickRun(itemIdOrName, isEcc, cmdName) {
  if (!isEcc) {
    // Non-ECC: invoke as a freeform prompt — show the Run Center generic modal.
    const item = {
      id: 'cmd:' + cmdName,
      source: 'local',
      kind: 'command',
      name: '/' + cmdName,
      description: t('로컬 슬래시 명령 — 대시보드에서 1회성 실행'),
      category: 'general',
      invocation: t('You are dispatching the local slash command') + ' /' + cmdName + '. ' +
                  t('Treat the user goal as the argument to the command.'),
      favorite: false,
    };
    __rc.selectedItem = item;
    __rc.lastResult = null;
    // Inject into catalog cache so /api/run/execute can find it — but our
    // catalog is server-side. For non-ECC we open a workflow scaffold instead.
    toast(t('이 명령은 ECC가 아니라 즉시 실행 대신 워크플로우로 변환됩니다'), 'info');
    // Simulate the run-center "to-workflow" path with a 1-node session draft.
    const draft = {
      name:        `Cmd · /${cmdName}`,
      description: `Quick run of /${cmdName} via Commands tab`,
      nodes: [
        {id: 'n-rcs', type: 'start',   x: 80,  y: 200, title: 'Start',   data: {}},
        {id: 'n-rcr', type: 'session', x: 320, y: 200, title: '/' + cmdName,
         data: {subject: '/' + cmdName, description: t('Run the slash command') + ' /' + cmdName,
                assignee: 'claude:sonnet', inputsMode: 'concat'}},
        {id: 'n-rco', type: 'output',  x: 560, y: 200, title: 'Output',  data: {exportTo:''}},
      ],
      edges: [
        {id: 'e1', from: 'n-rcs', to: 'n-rcr', fromPort: 'out', toPort: 'in'},
        {id: 'e2', from: 'n-rcr', to: 'n-rco', fromPort: 'out', toPort: 'in'},
      ],
      viewport: {panX:0,panY:0,zoom:1},
      repeat: {enabled:false, maxIterations:1, intervalSeconds:0},
      notify: {slack:'', discord:''},
      policy: {tokenBudgetTotal:0, onBudgetExceeded:'stop', fallbackProvider:''},
    };
    const r = await api('/api/workflows/save', {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify(draft),
    });
    if (r.ok) {
      try { localStorage.setItem('__wf_open_id', r.id); } catch(_){}
      go('workflows');
    }
    return;
  }
  // ECC: open the Run Center modal pre-filled with this command.
  go('runCenter');
  // Wait for the catalog to populate, then open the item.
  let tries = 0;
  const tryOpen = () => {
    if (__rc.catalog.length) {
      _rcOpenItem(itemIdOrName);
    } else if (++tries < 20) {
      setTimeout(tryOpen, 150);
    } else {
      toast(t('카탈로그 로드 실패'), 'err');
    }
  };
  setTimeout(tryOpen, 200);
}

// ── description 다국어 헬퍼 ──
// 우선순위: description_<curLang> > description (원본). _curLang === 'ko' 일 때는
// descriptionKo (legacy 캐시) 도 fallback 으로 사용.
function _localDesc(item) {
  if (!item) return '';
  const lang = (typeof _curLang !== 'undefined' ? _curLang : 'ko');
  if (lang === 'en') return item.descriptionEn || item.description || '';
  if (lang === 'zh') return item.descriptionZh || item.description || '';
  // ko: description 이 한국어일 가능성 높음. 없으면 descriptionKo (legacy 영문→한국어 번역 캐시) 사용.
  return item.description || item.descriptionKo || '';
}
function _localDescField() {
  const lang = (typeof _curLang !== 'undefined' ? _curLang : 'ko');
  return lang === 'en' ? 'descriptionEn' : (lang === 'zh' ? 'descriptionZh' : 'descriptionKo');
}
function _hasLocalTranslation(item) {
  if (!item) return false;
  const lang = (typeof _curLang !== 'undefined' ? _curLang : 'ko');
  if (lang === 'ko') return !!item.description;  // 원본은 사실상 한국어
  return !!item[_localDescField()];
}
function _localizedDescStatusText(items) {
  const lang = (typeof _curLang !== 'undefined' ? _curLang : 'ko');
  const langName = { ko: '한글', en: 'English', zh: '中文' }[lang] || lang;
  const n = items.filter(_hasLocalTranslation).length;
  return `${langName} 번역 ${n}/${items.length}`;
}
function _localizedDescStatus(items) {
  const lang = (typeof _curLang !== 'undefined' ? _curLang : 'ko');
  const n = items.filter(_hasLocalTranslation).length;
  if (n === items.length) return `<span class="chip chip-ok">${_localizedDescStatusText(items)}</span>`;
  if (n === 0) return `<span class="chip chip-warn">⚠️ ${_localizedDescStatusText(items)}</span>`;
  return `<span class="chip">${_localizedDescStatusText(items)}</span>`;
}
function _localizeBtnHtml(kind, items) {
  const lang = (typeof _curLang !== 'undefined' ? _curLang : 'ko');
  const langName = { ko: '한국어', en: 'English', zh: '中文' }[lang] || lang;
  const missing = items.filter(it => !_hasLocalTranslation(it)).length;
  if (missing === 0) {
    return `<button class="btn text-xs" disabled style="opacity:0.5;">🌐 ${langName} ✓</button>`;
  }
  return `<button class="btn text-xs" onclick="translateAll('${kind}')">🌐 ${langName} 번역 (${missing})</button>`;
}

async function translateAll(kind) {
  const lang = (typeof _curLang !== 'undefined' ? _curLang : 'ko');
  const langName = { ko: '한국어', en: 'English', zh: '中文' }[lang] || lang;
  const label = { cmd: '명령어', skill: '스킬', plugin: '플러그인', agent: '에이전트' }[kind] || kind;
  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <div>
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">${langName} 일괄 번역</div>
        <h2 class="text-lg font-bold">${label} → ${langName}</h2>
      </div>
      <button class="btn-ghost btn" id="tbClose" onclick="__tbCancel=true;closeModal();">✕</button>
    </div>
    <div class="p-5 overflow-y-auto">
      <div id="tbStatus" class="text-sm mb-2">시작 중…</div>
      <div class="h-2 rounded-full bg-white/5 overflow-hidden mb-3"><div id="tbBar" style="height:100%; background:var(--grad); width:0%; transition: width 0.3s;"></div></div>
      <div id="tbLog" class="mono text-[10px] text-[var(--text-mute)] whitespace-pre-wrap max-h-[260px] overflow-y-auto p-2 bg-[var(--code-bg)] rounded"></div>
      <div class="text-[11px] text-[var(--text-dim)] mt-2">각 배치 50개씩 · Claude CLI 1회당 20~90초 · 중간에 창 닫으면 중단</div>
    </div>
  `, { keepMascot: true });
  if (typeof _mascotJumpOnModal === 'function') _mascotJumpOnModal();
  window.__tbCancel = false;
  let totalTranslated = 0;
  let batch = 0;
  const started = Date.now();
  const log = document.getElementById('tbLog');
  const logLine = (s) => { if (log) { log.textContent += s + '\n'; log.scrollTop = log.scrollHeight; } };
  try {
    while (!window.__tbCancel) {
      batch++;
      const bar = document.getElementById('tbBar');
      const st = document.getElementById('tbStatus');
      logLine(`[배치 ${batch}] Claude CLI 요청…`);
      const r = await api('/api/translate/batch', {
        method: 'POST', headers: {'Content-Type':'application/json'},
        body: JSON.stringify({ kind, limit: 50, targetLang: lang }),
      });
      if (r.error) {
        logLine(`  ❌ ${r.error}`);
        if (st) st.textContent = '오류: ' + r.error;
        toast('번역 실패: ' + r.error, 'err');
        break;
      }
      totalTranslated += r.translated || 0;
      const total = r.total || 0;
      const remaining = r.remaining || 0;
      const completed = total - remaining;
      logLine(`  ✅ +${r.translated}건 (누적 ${totalTranslated}) · 남은 ${remaining} · 요청 ${r.requested}`);
      if (bar && total) bar.style.width = Math.round((completed / total) * 100) + '%';
      if (st) st.textContent = `진행 ${completed}/${total} · 배치 ${batch} · 경과 ${Math.round((Date.now()-started)/1000)}초`;
      if (r.done || r.translated === 0) break;
    }
    if (!window.__tbCancel) {
      logLine(`\n🎉 완료! ${label} ${totalTranslated}개 ${langName} 번역 (${batch}배치, ${Math.round((Date.now()-started)/1000)}초)`);
      toast(`${label} ${totalTranslated}개 번역 완료`, 'ok');
      setTimeout(() => { closeModal(); renderView(); }, 1500);
    }
  } catch (e) {
    logLine(`❌ ${e.message}`);
    toast('번역 중 오류: '+e.message, 'err');
  }
}

// ────────────────────────────────────────────────────────────────
// PROMPT CACHE LAB (v2.2.0)
// Anthropic Messages API 의 cache_control 실험실 — 예시 원클릭, 토큰/비용 실측
// ────────────────────────────────────────────────────────────────
VIEWS.promptCache = async () => {
  const [ex, hist] = await Promise.all([
    api('/api/prompt-cache/examples'),
    api('/api/prompt-cache/history'),
  ]);
  state.data.pc = state.data.pc || {
    model: 'claude-sonnet-4-6',
    maxTokens: 1024,
    system: '[]',
    tools: '[]',
    messages: '[{"role":"user","content":"안녕"}]',
    lastResult: null,
  };
  const pc = state.data.pc;
  const last = pc.lastResult;
  const histItems = (hist && hist.items) || [];

  const exBtns = (ex.examples || []).map(e =>
    `<button class="chip" onclick="pcLoadExample('${e.id}')">${t(e.label)}</button>`
  ).join('');

  const usage = last && last.usage || {};
  const cost = last && last.cost || {};
  const usageTbl = last ? `
    <table class="w-full text-[11px] border-collapse">
      <tbody>
        <tr class="border-b border-[var(--border)]"><td class="py-1 text-[var(--text-dim)]">input_tokens</td><td class="py-1 text-right font-mono">${usage.input_tokens||0}</td></tr>
        <tr class="border-b border-[var(--border)]"><td class="py-1 text-[var(--text-dim)]">cache_creation_input_tokens</td><td class="py-1 text-right font-mono text-[var(--warn)]">${usage.cache_creation_input_tokens||0}</td></tr>
        <tr class="border-b border-[var(--border)]"><td class="py-1 text-[var(--text-dim)]">cache_read_input_tokens</td><td class="py-1 text-right font-mono text-[var(--ok)]">${usage.cache_read_input_tokens||0}</td></tr>
        <tr><td class="py-1 text-[var(--text-dim)]">output_tokens</td><td class="py-1 text-right font-mono">${usage.output_tokens||0}</td></tr>
      </tbody>
    </table>
  ` : `<div class="text-[11px] text-[var(--text-dim)]">${t('아직 실행한 결과가 없습니다')}</div>`;

  const costTbl = last ? `
    <div class="grid grid-cols-2 gap-2 text-[11px]">
      <div class="flex justify-between"><span class="text-[var(--text-dim)]">${t('입력 비용')}</span><span class="font-mono">$${(cost.usdInput||0).toFixed(6)}</span></div>
      <div class="flex justify-between"><span class="text-[var(--text-dim)]">${t('캐시 쓰기')}</span><span class="font-mono">$${(cost.usdCacheWrite||0).toFixed(6)}</span></div>
      <div class="flex justify-between"><span class="text-[var(--text-dim)]">${t('캐시 읽기')}</span><span class="font-mono">$${(cost.usdCacheRead||0).toFixed(6)}</span></div>
      <div class="flex justify-between"><span class="text-[var(--text-dim)]">${t('출력 비용')}</span><span class="font-mono">$${(cost.usdOutput||0).toFixed(6)}</span></div>
      <div class="flex justify-between col-span-2 pt-2 border-t border-[var(--border)]"><span class="font-semibold">${t('합계')}</span><span class="font-mono font-semibold">$${(cost.usdTotal||0).toFixed(6)}</span></div>
      <div class="flex justify-between col-span-2"><span class="text-[var(--ok)]">${t('캐시 절감 추정')}</span><span class="font-mono text-[var(--ok)]">-$${(cost.usdSaved||0).toFixed(6)}</span></div>
    </div>
  ` : '';

  const histList = histItems.slice(0, 10).map(h => {
    const tsStr = new Date((h.ts||0)*1000).toLocaleString();
    const icon = h.status === 'ok' ? '✅' : '❌';
    const cr = h.usage && h.usage.cache_read_input_tokens || 0;
    const cw = h.usage && h.usage.cache_creation_input_tokens || 0;
    return `<div class="text-[11px] py-1 border-b border-[var(--border)] flex justify-between gap-2">
      <span>${icon} <span class="text-[var(--text-dim)]">${tsStr}</span> · ${h.model||''}</span>
      <span class="font-mono text-[var(--text-dim)]">cw=${cw} · cr=${cr}</span>
    </div>`;
  }).join('') || `<div class="text-[11px] text-[var(--text-dim)]">${t('이력 없음')}</div>`;

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">🧊 ${t('프롬프트 캐시 실험실')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('Anthropic Messages API 의 cache_control 을 실측. cache_creation 은 캐시 쓰기, cache_read 는 캐시 히트 — 히트 비용은 1/10 수준입니다.')}
      </p>
    </div>

    <div class="mb-3 flex items-center gap-2 flex-wrap">
      <span class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('예시')}</span>
      ${exBtns}
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="space-y-3">
        <div class="flex items-center gap-2">
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider w-20">${t('모델')}</label>
          <select class="input flex-1" onchange="pcSet('model', this.value)">
            <option value="claude-opus-4-7" ${pc.model==='claude-opus-4-7'?'selected':''}>Opus 4.7</option>
            <option value="claude-sonnet-4-6" ${pc.model==='claude-sonnet-4-6'?'selected':''}>Sonnet 4.6</option>
            <option value="claude-haiku-4-5" ${pc.model==='claude-haiku-4-5'?'selected':''}>Haiku 4.5</option>
          </select>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('max_tokens')}</label>
          <input type="text" inputmode="numeric" class="input w-24" value="${pc.maxTokens}"
                 oninput="pcSet('maxTokens', parseInt((this.value||'').replace(/\\D/g,''))||1024)">
        </div>

        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('system (JSON 배열)')}</label>
          <textarea class="input font-mono text-[11px]" rows="4" oninput="pcSet('system', this.value)">${escapeHtml(pc.system)}</textarea>
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('tools (JSON 배열)')}</label>
          <textarea class="input font-mono text-[11px]" rows="4" oninput="pcSet('tools', this.value)">${escapeHtml(pc.tools)}</textarea>
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('messages (JSON 배열)')}</label>
          <textarea class="input font-mono text-[11px]" rows="8" oninput="pcSet('messages', this.value)">${escapeHtml(pc.messages)}</textarea>
        </div>

        <div class="flex items-center gap-2">
          <button class="btn btn-primary" onclick="pcRun()">▶ ${t('실행')}</button>
          <button class="btn" onclick="pcReset()">${t('초기화')}</button>
          <span id="pcStatus" class="text-[11px] text-[var(--text-dim)]"></span>
        </div>
      </div>

      <div class="space-y-3">
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('토큰 사용량')}</div>
          ${usageTbl}
        </div>
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('비용 상세 (USD)')}</div>
          ${costTbl}
        </div>
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('응답')}</div>
          <pre class="text-[11px] whitespace-pre-wrap max-h-64 overflow-auto">${last ? escapeHtml(last.output || (last.error || '(empty)')) : t('아직 실행한 결과가 없습니다')}</pre>
        </div>
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('최근 히스토리')} (${histItems.length})</div>
          ${histList}
        </div>
      </div>
    </div>
  `;
};

function pcSet(key, val) {
  state.data.pc = state.data.pc || {};
  state.data.pc[key] = val;
}
function pcReset() {
  state.data.pc = null;
  renderView();
}
async function pcLoadExample(id) {
  const r = await api('/api/prompt-cache/examples');
  const e = (r.examples || []).find(x => x.id === id);
  if (!e) return;
  state.data.pc = {
    model: e.model,
    maxTokens: e.maxTokens,
    system: JSON.stringify(e.system || [], null, 2),
    tools: JSON.stringify(e.tools || [], null, 2),
    messages: JSON.stringify(e.messages || [], null, 2),
    lastResult: null,
  };
  renderView();
}
async function pcRun() {
  const st = document.getElementById('pcStatus');
  if (st) st.textContent = t('호출 중…');
  const pc = state.data.pc || {};
  let system, tools, messages;
  try { system = JSON.parse(pc.system || '[]'); }
  catch (e) { toast(t('system JSON 오류') + ': ' + e.message, 'err'); if (st) st.textContent=''; return; }
  try { tools = JSON.parse(pc.tools || '[]'); }
  catch (e) { toast(t('tools JSON 오류') + ': ' + e.message, 'err'); if (st) st.textContent=''; return; }
  try { messages = JSON.parse(pc.messages || '[]'); }
  catch (e) { toast(t('messages JSON 오류') + ': ' + e.message, 'err'); if (st) st.textContent=''; return; }

  try {
    const r = await fetch('/api/prompt-cache/test', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ model: pc.model, maxTokens: pc.maxTokens, system, tools, messages }),
    }).then(x => x.json());

    if (r.needKey) {
      toast(t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요'), 'err');
      if (st) st.textContent = '';
      return;
    }
    state.data.pc.lastResult = r.ok ? { usage: r.usage, cost: r.cost, output: r.output, durationMs: r.durationMs } : { error: r.error || t('실행 실패') };
    if (st) st.textContent = r.ok ? `${r.durationMs}ms` : '';
    renderView();
  } catch (e) {
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (st) st.textContent = '';
  }
}

// ────────────────────────────────────────────────────────────────
// EXTENDED THINKING LAB (v2.3.0)
// thinking block 을 분리해서 시각화 · budget_tokens 슬라이더
// ────────────────────────────────────────────────────────────────
VIEWS.thinkingLab = async () => {
  const [ex, hist, ms] = await Promise.all([
    api('/api/thinking-lab/examples'),
    api('/api/thinking-lab/history'),
    api('/api/thinking-lab/models'),
  ]);
  state.data.tl = state.data.tl || {
    model: 'claude-sonnet-4-6',
    budgetTokens: 4096,
    maxTokens: 2048,
    prompt: '',
    lastResult: null,
    thinkingOpen: true,
  };
  const tl = state.data.tl;
  const last = tl.lastResult;
  const items = (hist && hist.items) || [];

  const exBtns = (ex.examples || []).map(e =>
    `<button class="chip" onclick="tlLoadExample('${e.id}')">${t(e.label)}</button>`
  ).join('');

  const modelOpts = (ms.models || []).map(m =>
    `<option value="${m.id}" ${tl.model===m.id?'selected':''} ${m.supported?'':'disabled'}>${m.label}${m.supported?'':' ('+t('비지원')+')'}</option>`
  ).join('');

  const usage = last && last.usage || {};

  const histList = items.slice(0, 10).map(h => {
    const tsStr = new Date((h.ts||0)*1000).toLocaleString();
    const icon = h.status === 'ok' ? '✅' : '❌';
    return `<div class="text-[11px] py-1 border-b border-[var(--border)] flex justify-between gap-2">
      <span>${icon} <span class="text-[var(--text-dim)]">${tsStr}</span> · ${h.model||''}</span>
      <span class="font-mono text-[var(--text-dim)]">budget=${h.budgetTokens||0}</span>
    </div>`;
  }).join('') || `<div class="text-[11px] text-[var(--text-dim)]">${t('이력 없음')}</div>`;

  const thinkingPanel = last && last.thinking ? `
    <details class="card p-3" ${tl.thinkingOpen?'open':''}>
      <summary class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider cursor-pointer">
        🧠 ${t('Thinking Block')} (${(last.thinkingBlocks||0)} ${t('블록')})
      </summary>
      <pre class="text-[11px] whitespace-pre-wrap mt-2 max-h-80 overflow-auto text-[var(--text-dim)]">${escapeHtml(last.thinking)}</pre>
    </details>
  ` : '';

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">🧠 ${t('Extended Thinking 실험실')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('Opus 4.7 / Sonnet 4.6 의 thinking block 과 최종 응답을 분리 시각화. budget_tokens 로 추론 길이 조절.')}
      </p>
    </div>

    <div class="mb-3 flex items-center gap-2 flex-wrap">
      <span class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('예시')}</span>
      ${exBtns}
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="space-y-3">
        <div class="flex items-center gap-2 flex-wrap">
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider w-20">${t('모델')}</label>
          <select class="input flex-1" onchange="tlSet('model', this.value)">${modelOpts}</select>
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider flex justify-between">
            <span>budget_tokens</span>
            <span class="font-mono">${tl.budgetTokens}</span>
          </label>
          <input type="range" min="1024" max="32000" step="512" value="${tl.budgetTokens}"
                 oninput="tlSet('budgetTokens', parseInt(this.value)); this.previousElementSibling.lastElementChild.textContent=this.value"
                 class="w-full">
        </div>
        <div class="flex items-center gap-2">
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider w-20">max_tokens</label>
          <input type="text" inputmode="numeric" class="input w-32" value="${tl.maxTokens}"
                 oninput="tlSet('maxTokens', parseInt((this.value||'').replace(/\\D/g,''))||2048)">
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('프롬프트')}</label>
          <textarea class="input text-[12px]" rows="10" oninput="tlSet('prompt', this.value)" placeholder="${t('질문을 입력하세요')}">${escapeHtml(tl.prompt || '')}</textarea>
        </div>
        <div class="flex items-center gap-2">
          <button class="btn btn-primary" onclick="tlRun()">▶ ${t('실행')}</button>
          <button class="btn" onclick="tlReset()">${t('초기화')}</button>
          <span id="tlStatus" class="text-[11px] text-[var(--text-dim)]"></span>
        </div>
      </div>

      <div class="space-y-3">
        ${thinkingPanel}
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">💬 ${t('최종 응답')}</div>
          <pre class="text-[11px] whitespace-pre-wrap max-h-96 overflow-auto">${last ? escapeHtml(last.output || (last.error || '(empty)')) : t('아직 실행한 결과가 없습니다')}</pre>
        </div>
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('토큰 사용량')}</div>
          ${last ? `
            <div class="grid grid-cols-2 gap-2 text-[11px]">
              <div class="flex justify-between"><span class="text-[var(--text-dim)]">input_tokens</span><span class="font-mono">${usage.input_tokens||0}</span></div>
              <div class="flex justify-between"><span class="text-[var(--text-dim)]">output_tokens</span><span class="font-mono">${usage.output_tokens||0}</span></div>
              <div class="flex justify-between"><span class="text-[var(--text-dim)]">${t('소요 시간')}</span><span class="font-mono">${last.durationMs||0}ms</span></div>
              <div class="flex justify-between"><span class="text-[var(--text-dim)]">stop_reason</span><span class="font-mono">${last.stopReason||'-'}</span></div>
            </div>` : `<div class="text-[11px] text-[var(--text-dim)]">${t('아직 실행한 결과가 없습니다')}</div>`}
        </div>
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('최근 히스토리')} (${items.length})</div>
          ${histList}
        </div>
      </div>
    </div>
  `;
};

function tlSet(key, val) {
  state.data.tl = state.data.tl || {};
  state.data.tl[key] = val;
}
function tlReset() {
  state.data.tl = null;
  renderView();
}
async function tlLoadExample(id) {
  const r = await api('/api/thinking-lab/examples');
  const e = (r.examples || []).find(x => x.id === id);
  if (!e) return;
  state.data.tl = {
    model: e.model,
    budgetTokens: e.budgetTokens,
    maxTokens: e.maxTokens,
    prompt: e.prompt,
    lastResult: null,
    thinkingOpen: true,
  };
  renderView();
}
async function tlRun() {
  const st = document.getElementById('tlStatus');
  if (st) st.textContent = t('호출 중…');
  const tl = state.data.tl || {};
  if (!(tl.prompt || '').trim()) {
    toast(t('프롬프트를 입력하세요'), 'err');
    if (st) st.textContent = '';
    return;
  }
  try {
    const r = await fetch('/api/thinking-lab/test', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify(tl),
    }).then(x => x.json());
    if (r.needKey) {
      toast(t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요'), 'err');
      if (st) st.textContent = '';
      return;
    }
    if (r.unsupported) {
      toast(t('Extended Thinking 은 Haiku 에서 지원되지 않습니다'), 'err');
      if (st) st.textContent = '';
      return;
    }
    state.data.tl.lastResult = r.ok
      ? { thinking: r.thinking, output: r.output, usage: r.usage, durationMs: r.durationMs, thinkingBlocks: r.thinkingBlocks, stopReason: r.stopReason }
      : { error: r.error || t('실행 실패') };
    if (st) st.textContent = r.ok ? `${r.durationMs}ms` : '';
    renderView();
  } catch (e) {
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (st) st.textContent = '';
  }
}

// ────────────────────────────────────────────────────────────────
// TOOL USE PLAYGROUND (v2.4.0)
// tool schema 정의 → 메시지 → tool_use 수신 → 사용자가 tool_result 수동 입력 → 다음 턴
// ────────────────────────────────────────────────────────────────
VIEWS.toolUseLab = async () => {
  const [tpl, hist] = await Promise.all([
    api('/api/tool-use-lab/templates'),
    api('/api/tool-use-lab/history'),
  ]);
  state.data.tu = state.data.tu || {
    model: 'claude-sonnet-4-6',
    maxTokens: 2048,
    tools: JSON.stringify((tpl.templates || []).slice(0, 1).map(x => x.tool), null, 2),
    messages: [],
    pendingInput: '',
    busy: false,
  };
  const tu = state.data.tu;

  const tplBtns = (tpl.templates || []).map(x =>
    `<button class="chip" onclick="tuAddTool('${x.id}')">+ ${x.label}</button>`
  ).join('');

  // messages 배열을 대화 버블 형태로 렌더
  const bubbles = (tu.messages || []).map((m, idx) => {
    const role = m.role;
    const content = Array.isArray(m.content) ? m.content : [{type:'text', text: String(m.content||'')}];
    const parts = content.map((c, ci) => {
      if (c.type === 'text') {
        return `<div class="text-[12px] whitespace-pre-wrap">${escapeHtml(c.text||'')}</div>`;
      }
      if (c.type === 'tool_use') {
        return `<div class="mt-1 p-2 bg-[var(--bg-alt)] border border-[var(--accent)] rounded text-[11px]">
          <div class="text-[var(--accent)] font-mono mb-1">🛠️ tool_use: ${c.name}</div>
          <pre class="font-mono text-[11px] whitespace-pre-wrap">${escapeHtml(JSON.stringify(c.input||{}, null, 2))}</pre>
          <div class="mt-2">
            <label class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider">${t('tool_result 수동 입력')}</label>
            <textarea id="tr_${idx}_${ci}" class="input text-[11px] font-mono" rows="2" placeholder='{"result":"..."}'></textarea>
            <button class="btn btn-sm mt-1" onclick="tuSubmitToolResult(${idx}, ${ci}, '${c.id}')">${t('제출')}</button>
          </div>
        </div>`;
      }
      if (c.type === 'tool_result') {
        const text = Array.isArray(c.content)
          ? c.content.map(x => x.text || JSON.stringify(x)).join('\n')
          : String(c.content || '');
        return `<div class="mt-1 p-2 bg-[var(--bg-alt)] border border-[var(--ok)] rounded text-[11px]">
          <div class="text-[var(--ok)] font-mono mb-1">✓ tool_result (${c.tool_use_id||''})</div>
          <pre class="font-mono text-[11px] whitespace-pre-wrap">${escapeHtml(text)}</pre>
        </div>`;
      }
      return `<div class="text-[11px] text-[var(--text-dim)]">[${c.type||'?'}]</div>`;
    }).join('');
    const badge = role === 'user' ? '👤' : '🤖';
    const align = role === 'user' ? 'justify-end' : 'justify-start';
    return `<div class="flex ${align} mb-2">
      <div class="max-w-[90%] p-2 rounded ${role==='user'?'bg-[var(--bg-hover)]':'card'}">
        <div class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider mb-1">${badge} ${role}</div>
        ${parts}
      </div>
    </div>`;
  }).join('');

  const awaitingToolResult = (() => {
    const last = tu.messages[tu.messages.length-1];
    if (!last || last.role !== 'assistant') return false;
    const arr = Array.isArray(last.content) ? last.content : [];
    return arr.some(c => c.type === 'tool_use');
  })();

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">🛠️ ${t('Tool Use 플레이그라운드')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('tool schema 를 JSON 으로 정의하고, Claude 가 tool_use 블록을 반환하면 그 자리에서 tool_result 를 수동 입력해 다음 턴을 진행합니다.')}
      </p>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="space-y-3">
        <div class="flex items-center gap-2 flex-wrap">
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('모델')}</label>
          <select class="input flex-1" onchange="tuSet('model', this.value)">
            <option value="claude-opus-4-7" ${tu.model==='claude-opus-4-7'?'selected':''}>Opus 4.7</option>
            <option value="claude-sonnet-4-6" ${tu.model==='claude-sonnet-4-6'?'selected':''}>Sonnet 4.6</option>
            <option value="claude-haiku-4-5" ${tu.model==='claude-haiku-4-5'?'selected':''}>Haiku 4.5</option>
          </select>
        </div>

        <div>
          <div class="flex items-center justify-between mb-1">
            <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('tools (JSON 배열)')}</label>
            <div class="flex gap-1 flex-wrap">${tplBtns}</div>
          </div>
          <textarea class="input font-mono text-[11px]" rows="10" oninput="tuSet('tools', this.value)">${escapeHtml(tu.tools || '[]')}</textarea>
        </div>

        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('사용자 메시지')}</label>
          <textarea class="input text-[12px]" rows="3" id="tuInput" oninput="tuSet('pendingInput', this.value)" placeholder="${t('Claude 에게 할 질문')}">${escapeHtml(tu.pendingInput || '')}</textarea>
        </div>

        <div class="flex items-center gap-2">
          <button class="btn btn-primary" onclick="tuSendUser()" ${awaitingToolResult?'disabled':''}>▶ ${t('전송')}</button>
          <button class="btn" onclick="tuReset()">${t('새 대화')}</button>
          <span id="tuStatus" class="text-[11px] text-[var(--text-dim)]"></span>
        </div>
        ${awaitingToolResult ? `<div class="text-[11px] text-[var(--warn)]">⚠️ ${t('tool_result 를 먼저 입력하세요')}</div>` : ''}
      </div>

      <div class="space-y-2 max-h-[700px] overflow-auto pr-1">
        ${bubbles || `<div class="text-[11px] text-[var(--text-dim)]">${t('대화가 비어 있습니다. 위 입력창에서 시작하세요.')}</div>`}
      </div>
    </div>
  `;
};

function tuSet(key, val) {
  state.data.tu = state.data.tu || {};
  state.data.tu[key] = val;
}
function tuReset() {
  const tu = state.data.tu || {};
  state.data.tu = { ...tu, messages: [], pendingInput: '' };
  renderView();
}
async function tuAddTool(id) {
  const r = await api('/api/tool-use-lab/templates');
  const tpl = (r.templates || []).find(x => x.id === id);
  if (!tpl) return;
  const tu = state.data.tu || {};
  let cur;
  try { cur = JSON.parse(tu.tools || '[]'); if (!Array.isArray(cur)) cur = []; }
  catch { cur = []; }
  if (!cur.find(x => x && x.name === tpl.tool.name)) cur.push(tpl.tool);
  tuSet('tools', JSON.stringify(cur, null, 2));
  renderView();
}
async function tuSendUser() {
  const tu = state.data.tu || {};
  const text = (tu.pendingInput || '').trim();
  if (!text) { toast(t('메시지를 입력하세요'), 'err'); return; }
  let tools;
  try { tools = JSON.parse(tu.tools || '[]'); }
  catch (e) { toast(t('tools JSON 오류') + ': ' + e.message, 'err'); return; }
  const msgs = [...(tu.messages || []), { role: 'user', content: text }];
  state.data.tu.messages = msgs;
  state.data.tu.pendingInput = '';
  await tuCallTurn(tools);
}
async function tuCallTurn(tools) {
  const tu = state.data.tu;
  const st = document.getElementById('tuStatus');
  if (st) st.textContent = t('호출 중…');
  try {
    const r = await fetch('/api/tool-use-lab/turn', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ model: tu.model, maxTokens: tu.maxTokens, tools, messages: tu.messages }),
    }).then(x => x.json());
    if (r.needKey) {
      toast(t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요'), 'err');
      if (st) st.textContent = '';
      return;
    }
    if (!r.ok) {
      toast((r.error || t('실행 실패')), 'err');
      if (st) st.textContent = '';
      return;
    }
    state.data.tu.messages.push({ role: 'assistant', content: r.assistantContent || [] });
    if (st) st.textContent = `${r.durationMs||0}ms · ${r.stopReason||''}`;
    renderView();
  } catch (e) {
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (st) st.textContent = '';
  }
}
async function tuSubmitToolResult(msgIdx, _blockIdx, toolUseId) {
  const ta = document.getElementById(`tr_${msgIdx}_${_blockIdx}`);
  const raw = (ta && ta.value || '').trim();
  if (!raw) { toast(t('tool_result 내용을 입력하세요'), 'err'); return; }
  const tu = state.data.tu;
  // 새 user 메시지에 tool_result 블록 추가
  tu.messages.push({
    role: 'user',
    content: [{ type: 'tool_result', tool_use_id: toolUseId, content: raw }],
  });
  let tools;
  try { tools = JSON.parse(tu.tools || '[]'); }
  catch (e) { toast(t('tools JSON 오류') + ': ' + e.message, 'err'); return; }
  await tuCallTurn(tools);
}

// ────────────────────────────────────────────────────────────────
// BATCH JOBS (v2.5.0) — Message Batches API 관리 탭
// 대용량 프롬프트 배치 제출 · 상태 폴링 · JSONL 결과 다운로드
// ────────────────────────────────────────────────────────────────
VIEWS.batchJobs = async () => {
  const [ex, lst, bud] = await Promise.all([
    api('/api/batch/examples'),
    api('/api/batch/list'),
    api('/api/batch/budget'),
  ]);
  state.data.bj = state.data.bj || {
    model: 'claude-haiku-4-5',
    maxTokens: 256,
    promptsText: '',
    selectedBatchId: '',
    lastResults: null,
  };
  const bj = state.data.bj;
  const budget = (bud && bud.budget) || { enabled: false, maxPerBatchUsd: 1.0, maxPerBatchTokens: 100000 };

  const exBtns = (ex.examples || []).map(e =>
    `<button class="chip" onclick="bjLoadExample('${e.id}')">${t(e.label)}</button>`
  ).join('');

  let batches = [];
  if (lst && lst.ok) batches = lst.data || [];
  const needKey = lst && lst.needKey;

  const batchRows = batches.slice(0, 20).map(b => {
    const status = b.processing_status || b.status || '?';
    const created = b.created_at ? new Date(b.created_at).toLocaleString() : '';
    const counts = b.request_counts || {};
    const selected = bj.selectedBatchId === b.id;
    return `<div class="py-2 border-b border-[var(--border)] ${selected?'bg-[var(--bg-hover)]':''}">
      <div class="flex justify-between items-center gap-2">
        <span class="font-mono text-[11px]">${b.id}</span>
        <span class="chip chip-sm">${status}</span>
      </div>
      <div class="text-[10px] text-[var(--text-dim)] mt-1">${created} · processed ${counts.processing||0}+${counts.succeeded||0}/${(counts.processing||0)+(counts.succeeded||0)+(counts.errored||0)+(counts.canceled||0)+(counts.expired||0)||'?'}</div>
      <div class="mt-1 flex gap-1">
        <button class="btn btn-sm" onclick="bjSelect('${b.id}')">${t('결과 보기')}</button>
        ${status==='in_progress' || status==='processing' ? `<button class="btn btn-sm" onclick="bjCancel('${b.id}')">${t('취소')}</button>` : ''}
      </div>
    </div>`;
  }).join('') || `<div class="text-[11px] text-[var(--text-dim)]">${t('배치 없음')}</div>`;

  const resultsPanel = bj.lastResults ? `
    <div class="text-[11px] text-[var(--text-dim)] mb-1">${t('결과')} ${bj.lastResults.count||0} ${t('건')} · ${bj.selectedBatchId}</div>
    <pre class="text-[10px] max-h-80 overflow-auto font-mono whitespace-pre-wrap">${escapeHtml(JSON.stringify(bj.lastResults.items||[], null, 2).slice(0, 8000))}</pre>
  ` : `<div class="text-[11px] text-[var(--text-dim)]">${t('배치를 선택해서 결과를 보세요')}</div>`;

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">📦 ${t('배치 작업')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('Message Batches API 로 여러 프롬프트를 병렬 제출하고 상태 · JSONL 결과를 확인.')}
      </p>
      ${needKey ? `<div class="mt-2 text-[11px] text-[var(--warn)]">⚠️ ${t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요')}</div>` : ''}
    </div>

    <div class="card p-3 mb-4 flex items-center gap-3 flex-wrap" style="border-left:3px solid ${budget.enabled?'var(--accent)':'var(--border)'};">
      <div class="text-[11px] ${budget.enabled?'':'text-[var(--text-dim)]'}">
        <span class="font-semibold">${budget.enabled ? '🚨 ' + t('비용 가드 ON') : '🔒 ' + t('비용 가드 OFF')}</span>
      </div>
      <div class="text-[11px] text-[var(--text-dim)] font-mono">
        ${t('Batch 당 한도')} · $${(budget.maxPerBatchUsd||0).toFixed(2)} · ${(budget.maxPerBatchTokens||0).toLocaleString()} tokens
      </div>
      <button class="btn btn-sm ml-auto" onclick="bjEditBudget()">⚙️ ${t('임계치 편집')}</button>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="space-y-3">
        <div class="flex items-center gap-2 flex-wrap">
          <span class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('예시')}</span>
          ${exBtns}
        </div>
        <div class="flex items-center gap-2">
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider w-20">${t('모델')}</label>
          <select class="input flex-1" onchange="bjSet('model', this.value)">
            <option value="claude-opus-4-7" ${bj.model==='claude-opus-4-7'?'selected':''}>Opus 4.7</option>
            <option value="claude-sonnet-4-6" ${bj.model==='claude-sonnet-4-6'?'selected':''}>Sonnet 4.6</option>
            <option value="claude-haiku-4-5" ${bj.model==='claude-haiku-4-5'?'selected':''}>Haiku 4.5</option>
          </select>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">max_tokens</label>
          <input type="text" inputmode="numeric" class="input w-24" value="${bj.maxTokens}"
                 oninput="bjSet('maxTokens', parseInt((this.value||'').replace(/\\D/g,''))||256)">
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('프롬프트 (한 줄에 하나)')}</label>
          <textarea class="input text-[12px] font-mono" rows="10" oninput="bjSet('promptsText', this.value)" placeholder="${t('예: 한국의 수도는?')}">${escapeHtml(bj.promptsText || '')}</textarea>
          <div class="text-[10px] text-[var(--text-dim)] mt-1">${t('최대 1000건')}</div>
        </div>
        <div class="flex items-center gap-2">
          <button class="btn btn-primary" onclick="bjSubmit()">🚀 ${t('배치 제출')}</button>
          <button class="btn" onclick="bjRefresh()">🔄 ${t('새로고침')}</button>
          <span id="bjStatus" class="text-[11px] text-[var(--text-dim)]"></span>
        </div>
      </div>

      <div class="space-y-3">
        <div class="card p-3">
          <div class="flex justify-between items-center mb-2">
            <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('최근 배치')} (${batches.length})</div>
          </div>
          <div class="max-h-80 overflow-auto">${batchRows}</div>
        </div>
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('결과 미리보기')}</div>
          ${resultsPanel}
        </div>
      </div>
    </div>
  `;
};

function bjSet(key, val) {
  state.data.bj = state.data.bj || {};
  state.data.bj[key] = val;
}
async function bjLoadExample(id) {
  const r = await api('/api/batch/examples');
  const e = (r.examples || []).find(x => x.id === id);
  if (!e) return;
  state.data.bj = {
    model: e.model,
    maxTokens: e.maxTokens,
    promptsText: (e.prompts || []).join('\n'),
    selectedBatchId: '',
    lastResults: null,
  };
  renderView();
}
async function bjSubmit() {
  const bj = state.data.bj || {};
  const prompts = (bj.promptsText || '').split('\n').map(s => s.trim()).filter(Boolean);
  if (!prompts.length) { toast(t('프롬프트를 1건 이상 입력하세요'), 'err'); return; }
  if (prompts.length > 1000) { toast(t('최대 1000건'), 'err'); return; }
  const ok = await confirmModal({
    title: t('배치 제출 확인'),
    message: t('총 {n} 건을 {model} 로 제출합니다. Anthropic API 요금이 발생할 수 있습니다. 계속할까요?').replace('{n}', prompts.length).replace('{model}', bj.model),
    confirmLabel: t('제출'),
  });
  if (!ok) return;
  const st = document.getElementById('bjStatus');
  if (st) st.textContent = t('제출 중…');
  try {
    const r = await fetch('/api/batch/create', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ model: bj.model, maxTokens: bj.maxTokens, prompts }),
    }).then(x => x.json());
    if (r.needKey) { toast(t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요'), 'err'); if (st) st.textContent=''; return; }
    if (r.budgetExceeded) {
      const est = r.estimate || {};
      await confirmModal({
        title: '🚨 ' + t('비용 가드 차단'),
        message: `${r.error}\n\n예상 비용: $${(est.usd||0).toFixed(4)} (정가 $${(est.usdFull||0).toFixed(4)} × 50% 배치 할인)\n예상 토큰: ${(est.totalTokens||0).toLocaleString()} (입력 ${(est.inputTokens||0).toLocaleString()} + 출력 ${(est.outputTokens||0).toLocaleString()})\n\n${t('임계치 편집 버튼으로 한도를 올리거나 프롬프트 수를 줄이세요.')}`,
        confirmLabel: t('확인'),
      });
      if (st) st.textContent = '';
      return;
    }
    if (!r.ok) { toast(r.error || t('제출 실패'), 'err'); if (st) st.textContent=''; return; }
    toast(t('배치 제출 완료') + ': ' + (r.batchId||''), 'ok');
    if (st) st.textContent = '';
    await bjRefresh();
  } catch (e) {
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (st) st.textContent = '';
  }
}
async function bjRefresh() {
  await renderView();
}
async function bjEditBudget() {
  const r = await api('/api/batch/budget');
  const cur = (r && r.budget) || { enabled: false, maxPerBatchUsd: 1.0, maxPerBatchTokens: 100000 };
  const html = `
    <div class="space-y-3 text-[12px]">
      <label class="flex items-center gap-2 cursor-pointer select-none">
        <input type="checkbox" id="bjBudEnabled" ${cur.enabled?'checked':''}>
        <span>${t('비용 가드 활성화')}</span>
      </label>
      <div>
        <label class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider">${t('Batch 당 최대 비용')} ($)</label>
        <input type="text" inputmode="decimal" id="bjBudUsd" class="input" value="${cur.maxPerBatchUsd}">
      </div>
      <div>
        <label class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider">${t('Batch 당 최대 토큰')}</label>
        <input type="text" inputmode="numeric" id="bjBudTokens" class="input" value="${cur.maxPerBatchTokens}">
      </div>
      <div class="text-[10px] text-[var(--text-dim)]">
        ${t('활성화 시 제출 전에 예상 비용/토큰을 계산해 한도 초과면 거부합니다. Anthropic Message Batches 는 정가의 50% 이므로 예상은 이미 할인가입니다.')}
      </div>
    </div>
  `;
  showModal(html, {
    title: '⚙️ ' + t('Batch 비용 가드'),
    narrow: true,
    buttons: [
      { label: t('취소'), action: 'cancel' },
      { label: t('저장'), primary: true, action: async () => {
          const enabled = document.getElementById('bjBudEnabled').checked;
          const usd = parseFloat(document.getElementById('bjBudUsd').value) || 0;
          const tokens = parseInt((document.getElementById('bjBudTokens').value||'').replace(/\D/g,'')) || 0;
          const r = await fetch('/api/batch/budget/set', {
            method: 'POST', headers: {'Content-Type':'application/json'},
            body: JSON.stringify({ enabled, maxPerBatchUsd: usd, maxPerBatchTokens: tokens }),
          }).then(x => x.json());
          if (r.ok) { toast(t('저장 완료'), 'ok'); closeModal(); renderView(); }
          else toast(r.error || t('저장 실패'), 'err');
        }
      },
    ],
  });
}
async function bjSelect(id) {
  state.data.bj = state.data.bj || {};
  state.data.bj.selectedBatchId = id;
  const r = await api('/api/batch/results?id=' + encodeURIComponent(id));
  if (!r.ok) {
    toast(r.error || t('결과 조회 실패') + ' (' + t('완료 전에는 결과가 비어있을 수 있습니다') + ')', 'err');
  }
  state.data.bj.lastResults = r.ok ? { items: r.items, count: r.count } : { items: [], count: 0 };
  renderView();
}
async function bjCancel(id) {
  const ok = await confirmModal({ title: t('배치 취소'), message: t('이 배치를 취소할까요?'), confirmLabel: t('취소'), danger: true });
  if (!ok) return;
  const r = await fetch('/api/batch/cancel', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({ id }),
  }).then(x => x.json());
  if (r.ok) toast(t('취소 요청됨'), 'ok'); else toast(r.error || t('취소 실패'), 'err');
  await bjRefresh();
}

// ────────────────────────────────────────────────────────────────
// API FILES (v2.6.0) — Anthropic Files API 관리
// 파일 업로드·목록·삭제 + 업로드한 파일을 메시지 document 로 reference
// ────────────────────────────────────────────────────────────────
VIEWS.apiFiles = async () => {
  const lst = await api('/api/api-files/list');
  state.data.af = state.data.af || {
    model: 'claude-sonnet-4-6',
    prompt: '',
    selectedFileId: '',
    lastOutput: null,
  };
  const af = state.data.af;
  const needKey = lst && lst.needKey;
  const files = (lst && lst.data) || [];

  const fileRows = files.slice(0, 30).map(f => {
    const sel = af.selectedFileId === f.id;
    const sz = (f.size_bytes || 0) / 1024;
    const szStr = sz >= 1024 ? (sz/1024).toFixed(2) + ' MB' : sz.toFixed(1) + ' KB';
    return `<div class="py-2 border-b border-[var(--border)] ${sel?'bg-[var(--bg-hover)]':''}">
      <div class="flex justify-between items-center gap-2">
        <span class="font-mono text-[11px] truncate" title="${f.filename||''}">${f.filename||f.id}</span>
        <span class="text-[10px] text-[var(--text-dim)] font-mono">${szStr}</span>
      </div>
      <div class="text-[10px] text-[var(--text-dim)] mt-1 truncate">${f.id} · ${f.mime_type||'?'}</div>
      <div class="mt-1 flex gap-1">
        <button class="btn btn-sm" onclick="afSelect('${f.id}')">${t('선택')}</button>
        <button class="btn btn-sm btn-danger" onclick="afDelete('${f.id}')">${t('삭제')}</button>
      </div>
    </div>`;
  }).join('') || `<div class="text-[11px] text-[var(--text-dim)]">${t('업로드된 파일이 없습니다')}</div>`;

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">📎 ${t('Files API')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('Anthropic 에 파일을 업로드하고, file_id 를 메시지에 document 로 reference 해서 질문을 던질 수 있습니다.')}
      </p>
      ${needKey ? `<div class="mt-2 text-[11px] text-[var(--warn)]">⚠️ ${t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요')}</div>` : ''}
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="space-y-3">
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('파일 업로드')}</div>
          <input type="file" id="afFileInput" class="input" onchange="afUpload()">
          <div class="text-[10px] text-[var(--text-dim)] mt-1">${t('최대 30MB · PDF / txt / md 권장')}</div>
          <div id="afUploadStatus" class="text-[11px] mt-2"></div>
        </div>

        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('파일로 질문 테스트')}</div>
          <div class="text-[10px] text-[var(--text-dim)] mb-2">${t('선택된 파일')}: <span class="font-mono">${af.selectedFileId || '-'}</span></div>
          <select class="input mb-2" onchange="afSet('model', this.value)">
            <option value="claude-opus-4-7" ${af.model==='claude-opus-4-7'?'selected':''}>Opus 4.7</option>
            <option value="claude-sonnet-4-6" ${af.model==='claude-sonnet-4-6'?'selected':''}>Sonnet 4.6</option>
            <option value="claude-haiku-4-5" ${af.model==='claude-haiku-4-5'?'selected':''}>Haiku 4.5</option>
          </select>
          <textarea class="input text-[12px]" rows="3" oninput="afSet('prompt', this.value)" placeholder="${t('이 문서의 핵심을 3줄로 요약해줘')}">${escapeHtml(af.prompt || '')}</textarea>
          <div class="mt-2 flex items-center gap-2">
            <button class="btn btn-primary" onclick="afAsk()" ${af.selectedFileId?'':'disabled'}>▶ ${t('질문 실행')}</button>
            <span id="afAskStatus" class="text-[11px] text-[var(--text-dim)]"></span>
          </div>
          ${af.lastOutput ? `<pre class="text-[11px] whitespace-pre-wrap mt-3 max-h-64 overflow-auto">${escapeHtml(af.lastOutput.output || af.lastOutput.error || '')}</pre>` : ''}
        </div>
      </div>

      <div class="space-y-3">
        <div class="card p-3">
          <div class="flex justify-between items-center mb-2">
            <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('업로드된 파일')} (${files.length})</div>
            <button class="btn btn-sm" onclick="renderView()">🔄 ${t('새로고침')}</button>
          </div>
          <div class="max-h-[600px] overflow-auto">${fileRows}</div>
        </div>
      </div>
    </div>
  `;
};

function afSet(key, val) {
  state.data.af = state.data.af || {};
  state.data.af[key] = val;
}
function afSelect(id) {
  state.data.af = state.data.af || {};
  state.data.af.selectedFileId = id;
  renderView();
}
async function afDelete(id) {
  const ok = await confirmModal({ title: t('파일 삭제'), message: t('이 파일을 삭제할까요?'), confirmLabel: t('삭제'), danger: true });
  if (!ok) return;
  const r = await fetch('/api/api-files/delete', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({ id }),
  }).then(x => x.json());
  if (r.ok) toast(t('삭제 완료'), 'ok'); else toast(r.error || t('삭제 실패'), 'err');
  renderView();
}
async function afUpload() {
  const inp = document.getElementById('afFileInput');
  const st = document.getElementById('afUploadStatus');
  const f = inp && inp.files && inp.files[0];
  if (!f) return;
  if (f.size > 30 * 1024 * 1024) { toast(t('최대 30MB'), 'err'); return; }
  if (st) st.textContent = t('업로드 중…') + ' (' + Math.round(f.size/1024) + ' KB)';
  const buf = await f.arrayBuffer();
  // base64 인코딩
  const bytes = new Uint8Array(buf);
  let bin = '';
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  const b64 = btoa(bin);
  try {
    const r = await fetch('/api/api-files/upload', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ filename: f.name, mime: f.type || 'application/octet-stream', base64: b64 }),
    }).then(x => x.json());
    if (r.needKey) { toast(t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요'), 'err'); if (st) st.textContent=''; return; }
    if (!r.ok) { toast(r.error || t('업로드 실패'), 'err'); if (st) st.textContent = '❌ ' + (r.error||''); return; }
    toast(t('업로드 완료') + ': ' + (r.fileId||''), 'ok');
    state.data.af = state.data.af || {};
    state.data.af.selectedFileId = r.fileId;
    if (st) st.textContent = '✅ ' + (r.fileId||'');
    renderView();
  } catch (e) {
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (st) st.textContent = '❌ ' + e.message;
  }
}
async function afAsk() {
  const af = state.data.af || {};
  if (!af.selectedFileId) { toast(t('먼저 파일을 선택하세요'), 'err'); return; }
  if (!(af.prompt||'').trim()) { toast(t('질문을 입력하세요'), 'err'); return; }
  const st = document.getElementById('afAskStatus');
  if (st) st.textContent = t('호출 중…');
  try {
    const r = await fetch('/api/api-files/test', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ model: af.model, prompt: af.prompt, fileId: af.selectedFileId }),
    }).then(x => x.json());
    if (r.needKey) { toast(t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요'), 'err'); if (st) st.textContent=''; return; }
    state.data.af.lastOutput = r.ok ? { output: r.output, durationMs: r.durationMs } : { error: r.error || t('실행 실패') };
    if (st) st.textContent = r.ok ? `${r.durationMs||0}ms` : '❌';
    renderView();
  } catch (e) {
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (st) st.textContent = '';
  }
}

// ────────────────────────────────────────────────────────────────
// VISION / PDF LAB (v2.7.0)
// 이미지/PDF 업로드 → Opus / Sonnet / Haiku 3 모델 병렬 비교
// ────────────────────────────────────────────────────────────────
VIEWS.visionLab = async () => {
  state.data.vl = state.data.vl || {
    mediaType: '',
    base64: '',
    filename: '',
    previewUrl: '',
    question: '이 파일의 내용을 설명해줘.',
    results: null,
    running: false,
  };
  const vl = state.data.vl;

  const preview = vl.previewUrl ? (
    vl.mediaType === 'application/pdf'
      ? `<div class="text-[11px] text-[var(--text-dim)]">📄 PDF: ${vl.filename} (${Math.round((vl.base64.length*3/4)/1024)} KB)</div>`
      : `<img src="${vl.previewUrl}" alt="preview" class="max-h-48 rounded border border-[var(--border)]">`
  ) : `<div class="text-[11px] text-[var(--text-dim)]">${t('이미지 또는 PDF 를 선택하세요')}</div>`;

  const resultCards = (vl.results && vl.results.results) ? vl.results.results.map(r => {
    const head = r.ok
      ? `<span class="text-[var(--ok)]">✓</span> ${r.model} · ${r.durationMs}ms`
      : `<span class="text-[var(--danger)]">✗</span> ${r.model}`;
    const body = r.ok ? (r.output || '(empty)') : (r.error || 'error');
    const usage = r.usage ? `<div class="text-[10px] text-[var(--text-dim)] mt-1">in=${r.usage.input_tokens||0} · out=${r.usage.output_tokens||0}</div>` : '';
    return `<div class="card p-3">
      <div class="text-[11px] font-mono mb-1">${head}</div>
      <pre class="text-[11px] whitespace-pre-wrap max-h-64 overflow-auto">${escapeHtml(body)}</pre>
      ${usage}
    </div>`;
  }).join('') : '';

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">👁️ ${t('Vision / PDF 실험실')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('이미지(PNG/JPG/WebP/GIF) 또는 PDF 를 올리고 같은 질문을 Opus / Sonnet / Haiku 3 모델에 병렬 전송 → 응답을 나란히 비교합니다.')}
      </p>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4 mb-4">
      <div class="space-y-3">
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('파일 선택')}</div>
          <input type="file" accept="image/png,image/jpeg,image/webp,image/gif,application/pdf" onchange="vlLoadFile(event)">
          <div class="text-[10px] text-[var(--text-dim)] mt-1">${t('최대 10MB')}</div>
          <div class="mt-3">${preview}</div>
        </div>

        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('질문')}</label>
          <textarea class="input text-[12px]" rows="3" oninput="vlSet('question', this.value)">${escapeHtml(vl.question || '')}</textarea>
        </div>

        <div class="flex items-center gap-2">
          <button class="btn btn-primary" onclick="vlRun()" ${vl.base64 && !vl.running ? '' : 'disabled'}>
            ▶ ${vl.running ? t('실행 중…') : t('3 모델 병렬 실행')}
          </button>
          <button class="btn" onclick="vlReset()">${t('초기화')}</button>
          <span id="vlStatus" class="text-[11px] text-[var(--text-dim)]"></span>
        </div>
      </div>

      <div class="space-y-3">
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('결과 요약')}</div>
          ${vl.results ? `
            <div class="text-[11px]">
              <div>${t('총 소요')}: <span class="font-mono">${vl.results.totalDurationMs}ms</span></div>
              <div>${t('모델 수')}: ${(vl.results.results||[]).length}</div>
            </div>` : `<div class="text-[11px] text-[var(--text-dim)]">${t('아직 결과가 없습니다')}</div>`}
        </div>
      </div>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-3 gap-4">${resultCards}</div>
  `;
};

function vlSet(key, val) {
  state.data.vl = state.data.vl || {};
  state.data.vl[key] = val;
}
function vlReset() {
  state.data.vl = null;
  renderView();
}
async function vlLoadFile(ev) {
  const f = ev.target.files && ev.target.files[0];
  if (!f) return;
  if (f.size > 10 * 1024 * 1024) { toast(t('최대 10MB'), 'err'); return; }
  const buf = await f.arrayBuffer();
  const bytes = new Uint8Array(buf);
  let bin = '';
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  const b64 = btoa(bin);
  const mt = f.type || 'application/octet-stream';
  // 미리보기 URL (이미지만 blob URL; PDF 는 메타만)
  let previewUrl = '';
  if (mt.startsWith('image/')) {
    previewUrl = 'data:' + mt + ';base64,' + b64;
  }
  state.data.vl = { ...(state.data.vl||{}), mediaType: mt, base64: b64, filename: f.name, previewUrl, results: null };
  renderView();
}
async function vlRun() {
  const vl = state.data.vl || {};
  if (!vl.base64) { toast(t('파일을 먼저 선택하세요'), 'err'); return; }
  if (!(vl.question||'').trim()) { toast(t('질문을 입력하세요'), 'err'); return; }
  vlSet('running', true);
  const st = document.getElementById('vlStatus');
  if (st) st.textContent = t('3 모델 병렬 호출 중…');
  try {
    const r = await fetch('/api/vision-lab/compare', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ mediaType: vl.mediaType, base64: vl.base64, question: vl.question }),
    }).then(x => x.json());
    vlSet('running', false);
    if (r.needKey) { toast(t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요'), 'err'); if (st) st.textContent=''; renderView(); return; }
    if (!r.ok) { toast(r.error || t('실행 실패'), 'err'); if (st) st.textContent=''; renderView(); return; }
    vlSet('results', r);
    if (st) st.textContent = `${r.totalDurationMs}ms`;
    renderView();
  } catch (e) {
    vlSet('running', false);
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (st) st.textContent = '';
    renderView();
  }
}

// ────────────────────────────────────────────────────────────────
// MODEL BENCHMARK (v2.8.0)
// 프롬프트 셋 × 선택 모델 교차 실행 → 지연/토큰/비용 집계
// ────────────────────────────────────────────────────────────────
VIEWS.modelBench = async () => {
  const data = await api('/api/model-bench/sets');
  state.data.mb = state.data.mb || {
    setId: 'basic-qa',
    modelIds: ['claude-haiku-4-5', 'claude-sonnet-4-6'],
    maxTokens: 512,
    results: null,
    running: false,
  };
  const mb = state.data.mb;
  const sets = data.sets || [];
  const models = data.models || [];
  const cur = sets.find(s => s.id === mb.setId) || sets[0];

  const setBtns = sets.map(s =>
    `<button class="chip ${mb.setId===s.id?'chip-accent':''}" onclick="mbSelectSet('${s.id}')">${t(s.label)}</button>`
  ).join('');

  const modelChecks = models.map(m => {
    const checked = mb.modelIds.includes(m.id);
    return `<label class="flex items-center gap-2 text-[11px] cursor-pointer select-none">
      <input type="checkbox" ${checked?'checked':''} onchange="mbToggleModel('${m.id}')">
      <span>${m.label}</span>
    </label>`;
  }).join('');

  const summaryRows = mb.results ? Object.entries(mb.results.summary || {}).map(([mid, s]) => {
    return `<tr class="border-b border-[var(--border)]">
      <td class="py-1 font-mono">${mid}</td>
      <td class="py-1 text-right">${s.count}</td>
      <td class="py-1 text-right">${s.avgMs}ms</td>
      <td class="py-1 text-right">${s.avgOut}</td>
      <td class="py-1 text-right font-mono">$${(s.totalCost||0).toFixed(6)}</td>
    </tr>`;
  }).join('') : '';

  const matrix = mb.results ? (mb.results.results || []).map(r => {
    const icon = r.ok ? '✅' : '❌';
    const body = r.ok ? (r.output || '').slice(0, 140) : (r.error || '');
    return `<tr class="border-b border-[var(--border)] align-top">
      <td class="py-2 pr-2 text-[11px] font-mono whitespace-nowrap">${icon} ${r.model||''}</td>
      <td class="py-2 pr-2 text-[11px]">${escapeHtml(r.prompt||'').slice(0, 60)}</td>
      <td class="py-2 pr-2 text-[11px] whitespace-pre-wrap">${escapeHtml(body)}</td>
      <td class="py-2 pr-2 text-[11px] text-right font-mono">${r.durationMs||0}ms</td>
      <td class="py-2 text-[11px] text-right font-mono">${r.ok ? '$' + (r.usdCost||0).toFixed(6) : '-'}</td>
    </tr>`;
  }).join('') : '';

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">🏁 ${t('모델 벤치마크')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('사전 정의 프롬프트 셋과 선택한 모델들을 교차 실행해 평균 지연 · 토큰 · 비용을 집계합니다.')}
      </p>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4 mb-4">
      <div class="space-y-3">
        <div>
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-1">${t('프롬프트 셋')}</div>
          <div class="flex gap-1 flex-wrap mb-2">${setBtns}</div>
          <div class="card p-3 text-[11px]">
            <div class="font-semibold mb-1">${t(cur?.label||'')}</div>
            <div class="text-[var(--text-dim)] mb-2">${t(cur?.description||'')}</div>
            <ol class="list-decimal pl-4 space-y-1">${(cur?.prompts||[]).map(p => `<li>${escapeHtml(p)}</li>`).join('')}</ol>
          </div>
        </div>

        <div>
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-1">${t('모델 선택')}</div>
          <div class="flex gap-3 flex-wrap">${modelChecks}</div>
        </div>

        <div class="flex items-center gap-2">
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">max_tokens</label>
          <input type="text" inputmode="numeric" class="input w-24" value="${mb.maxTokens}"
                 oninput="mbSet('maxTokens', parseInt((this.value||'').replace(/\\D/g,''))||512)">
        </div>

        <div class="flex items-center gap-2">
          <button class="btn btn-primary" onclick="mbRun()" ${mb.running?'disabled':''}>
            ▶ ${mb.running ? t('실행 중…') : t('벤치마크 실행')}
          </button>
          <button class="btn" onclick="mbDownload()" ${mb.results?'':'disabled'}>⬇ ${t('JSON 다운로드')}</button>
          <span id="mbStatus" class="text-[11px] text-[var(--text-dim)]"></span>
        </div>
      </div>

      <div class="space-y-3">
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('모델별 집계')}</div>
          ${mb.results ? `
            <table class="w-full text-[11px] border-collapse">
              <thead><tr class="border-b border-[var(--border)]">
                <th class="text-left py-1">${t('모델')}</th>
                <th class="text-right py-1">${t('성공')}</th>
                <th class="text-right py-1">${t('평균 지연')}</th>
                <th class="text-right py-1">${t('평균 출력 토큰')}</th>
                <th class="text-right py-1">${t('총 비용')}</th>
              </tr></thead>
              <tbody>${summaryRows}</tbody>
            </table>
            <div class="text-[10px] text-[var(--text-dim)] mt-2">${t('총 소요')}: ${mb.results.totalDurationMs}ms</div>
          ` : `<div class="text-[11px] text-[var(--text-dim)]">${t('아직 결과가 없습니다')}</div>`}
        </div>
      </div>
    </div>

    ${mb.results ? `
      <div class="card p-3">
        <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('개별 응답')} (${(mb.results.results||[]).length})</div>
        <div class="max-h-96 overflow-auto">
          <table class="w-full border-collapse">
            <thead><tr class="border-b border-[var(--border)]">
              <th class="text-left py-1 text-[11px]">${t('모델')}</th>
              <th class="text-left py-1 text-[11px]">${t('프롬프트')}</th>
              <th class="text-left py-1 text-[11px]">${t('응답')}</th>
              <th class="text-right py-1 text-[11px]">${t('지연')}</th>
              <th class="text-right py-1 text-[11px]">${t('비용')}</th>
            </tr></thead>
            <tbody>${matrix}</tbody>
          </table>
        </div>
      </div>
    ` : ''}
  `;
};

function mbSet(key, val) {
  state.data.mb = state.data.mb || {};
  state.data.mb[key] = val;
}
function mbSelectSet(id) {
  mbSet('setId', id);
  renderView();
}
function mbToggleModel(id) {
  const mb = state.data.mb;
  const i = mb.modelIds.indexOf(id);
  if (i >= 0) mb.modelIds.splice(i, 1);
  else mb.modelIds.push(id);
  renderView();
}
async function mbRun() {
  const mb = state.data.mb || {};
  const data = await api('/api/model-bench/sets');
  const s = (data.sets || []).find(x => x.id === mb.setId);
  if (!s) { toast(t('프롬프트 셋 없음'), 'err'); return; }
  if (!mb.modelIds.length) { toast(t('모델을 1개 이상 선택하세요'), 'err'); return; }
  const n = s.prompts.length * mb.modelIds.length;
  const ok = await confirmModal({
    title: t('벤치마크 실행 확인'),
    message: t('총 {n} 회 API 호출을 수행합니다 ({p} 프롬프트 × {m} 모델). 계속할까요?')
      .replace('{n}', n).replace('{p}', s.prompts.length).replace('{m}', mb.modelIds.length),
    confirmLabel: t('실행'),
  });
  if (!ok) return;

  mbSet('running', true);
  const st = document.getElementById('mbStatus');
  if (st) st.textContent = t('실행 중…');
  try {
    const r = await fetch('/api/model-bench/run', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ prompts: s.prompts, models: mb.modelIds, maxTokens: mb.maxTokens }),
    }).then(x => x.json());
    mbSet('running', false);
    if (r.needKey) { toast(t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요'), 'err'); if (st) st.textContent=''; renderView(); return; }
    if (!r.ok) { toast(r.error || t('실행 실패'), 'err'); if (st) st.textContent=''; renderView(); return; }
    mbSet('results', r);
    if (st) st.textContent = `${r.totalDurationMs}ms`;
    renderView();
  } catch (e) {
    mbSet('running', false);
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (st) st.textContent = '';
    renderView();
  }
}
function mbDownload() {
  const mb = state.data.mb;
  if (!mb || !mb.results) return;
  const blob = new Blob([JSON.stringify(mb.results, null, 2)], {type:'application/json'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = `model-bench-${Date.now()}.json`; a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

// ────────────────────────────────────────────────────────────────
// PROMPT LIBRARY (v2.16.0) — 프롬프트 템플릿 CRUD + 태그 검색
// ────────────────────────────────────────────────────────────────
VIEWS.promptLibrary = async () => {
  const data = await api('/api/prompt-library/list');
  state.data.pl = state.data.pl || { q: '', tag: '', editing: null };
  const pl = state.data.pl;
  const items = data.items || [];
  const allTags = data.tags || [];

  const q = (pl.q || '').toLowerCase();
  const filtered = items.filter(it => {
    if (pl.tag && !(it.tags||[]).includes(pl.tag)) return false;
    if (q) {
      const hay = (it.title + ' ' + it.body + ' ' + (it.tags||[]).join(' ')).toLowerCase();
      if (!hay.includes(q)) return false;
    }
    return true;
  });

  const tagChips = allTags.map(tg => `
    <button class="chip ${pl.tag===tg?'chip-accent':''}" onclick="plSet('tag', '${pl.tag===tg?'':tg}'); renderView()">#${escapeHtml(tg)}</button>
  `).join('');

  const editing = pl.editing;
  const editorPanel = editing ? `
    <div class="card p-3" style="border-left:3px solid var(--accent);">
      <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${editing.id ? t('수정') : t('새 프롬프트')}</div>
      <input class="input mb-2" placeholder="${t('제목')}" value="${escapeHtml(editing.title||'')}" oninput="plSetEdit('title', this.value)">
      <textarea class="input font-mono text-[11px] mb-2" rows="6" placeholder="${t('본문')}" oninput="plSetEdit('body', this.value)">${escapeHtml(editing.body||'')}</textarea>
      <input class="input mb-2" placeholder="${t('태그 (쉼표 구분)')}" value="${escapeHtml((editing.tags||[]).join(', '))}" oninput="plSetEdit('tagsRaw', this.value)">
      <input class="input mb-1" placeholder="${t('pl_keywords_placeholder', '트리거 키워드 (쉼표 구분, 예: ultrathink, deepsearch)')}" value="${escapeHtml((editing.keywords||[]).join(', '))}" oninput="plSetEdit('keywordsRaw', this.value)">
      <div class="text-[10px] mb-2" style="color:var(--text-dim)">${t('pl_keywords_hint', '워크플로우 session 노드 입력에 이 키워드가 포함되면 본 프롬프트가 시스템 프롬프트에 자동 주입됩니다.')}</div>
      <div class="flex gap-2 items-center">
        <select class="input" onchange="plSetEdit('model', this.value)">
          <option value="">${t('모델 미지정')}</option>
          <option value="claude-opus-4-7" ${editing.model==='claude-opus-4-7'?'selected':''}>Opus 4.7</option>
          <option value="claude-sonnet-4-6" ${editing.model==='claude-sonnet-4-6'?'selected':''}>Sonnet 4.6</option>
          <option value="claude-haiku-4-5" ${editing.model==='claude-haiku-4-5'?'selected':''}>Haiku 4.5</option>
        </select>
        <button class="btn btn-primary" onclick="plSave()">💾 ${t('저장')}</button>
        <button class="btn" onclick="plSet('editing', null); renderView()">${t('취소')}</button>
      </div>
    </div>
  ` : `
    <button class="btn btn-primary w-full" onclick="plNew()">+ ${t('새 프롬프트')}</button>
  `;

  const list = filtered.length ? filtered.map(it => `
    <div class="card p-3 flex flex-col gap-2" style="border-left:3px solid var(--accent);">
      <div class="flex items-start justify-between gap-2">
        <div class="font-semibold text-[13px]">${escapeHtml(it.title)}</div>
        <div class="flex gap-1">
          <button class="btn btn-sm" onclick="plCopy('${it.id}')" title="${t('본문 복사')}">📋</button>
          <button class="btn btn-sm" onclick="plEdit('${it.id}')" title="${t('수정')}">✏️</button>
          <button class="btn btn-sm" onclick="plDuplicate('${it.id}')" title="${t('복제')}">🗂️</button>
          <button class="btn btn-sm" onclick="plToWorkflow('${it.id}')" title="${t('워크플로우로')}">🔀</button>
          <button class="btn btn-sm btn-danger" onclick="plDelete('${it.id}')" title="${t('삭제')}">🗑️</button>
        </div>
      </div>
      <pre class="text-[11px] whitespace-pre-wrap max-h-32 overflow-auto text-[var(--text-mute)]">${escapeHtml(it.body||'').slice(0,800)}${(it.body||'').length>800?'…':''}</pre>
      <div class="flex items-center gap-1 flex-wrap">
        ${(it.tags||[]).map(tg => `<span class="chip" style="font-size:10px;">#${escapeHtml(tg)}</span>`).join('')}
        ${it.model ? `<span class="chip chip-sm" style="font-size:10px; background:rgba(217,119,87,0.1);">${escapeHtml(it.model)}</span>` : ''}
      </div>
    </div>
  `).join('') : `<div class="card p-6 text-center text-[11px] text-[var(--text-dim)]">${t('일치하는 프롬프트 없음')}</div>`;

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">📝 ${t('프롬프트 라이브러리')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('자주 쓰는 프롬프트를 태그와 함께 저장하고, 복사/복제/워크플로우 복제 버튼으로 바로 재활용합니다.')}
      </p>
    </div>

    <div class="flex items-center gap-2 mb-4 flex-wrap">
      <input class="input flex-1" style="min-width:240px;" placeholder="${t('제목/본문/태그 검색')}"
             value="${escapeHtml(pl.q||'')}" oninput="plSet('q', this.value); plDebouncedRender()">
      ${pl.tag ? `<button class="btn btn-sm" onclick="plSet('tag',''); renderView()">✕ #${escapeHtml(pl.tag)}</button>` : ''}
      <span class="text-[11px] text-[var(--text-dim)]">${filtered.length}/${items.length}</span>
    </div>
    ${allTags.length ? `<div class="flex items-center gap-1 flex-wrap mb-4">${tagChips}</div>` : ''}

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="space-y-3">${editorPanel}</div>
      <div class="space-y-3 max-h-[720px] overflow-auto pr-1">${list}</div>
    </div>
  `;
};

function plSet(k, v) { state.data.pl = state.data.pl || {}; state.data.pl[k] = v; }
function plSetEdit(k, v) {
  state.data.pl = state.data.pl || { editing: {} };
  state.data.pl.editing = state.data.pl.editing || {};
  state.data.pl.editing[k] = v;
}
let _plDebounce = null;
function plDebouncedRender() {
  if (_plDebounce) clearTimeout(_plDebounce);
  _plDebounce = setTimeout(() => { _plDebounce = null; renderView(); }, 250);
}
function plNew() {
  plSet('editing', { title: '', body: '', tags: [], tagsRaw: '', keywords: [], keywordsRaw: '', model: '' });
  renderView();
}
async function plEdit(pid) {
  const r = await api('/api/prompt-library/list');
  const it = (r.items || []).find(x => x.id === pid);
  if (!it) return;
  plSet('editing', {
    id: it.id, title: it.title, body: it.body,
    tags: it.tags || [], tagsRaw: (it.tags||[]).join(', '),
    keywords: it.keywords || [], keywordsRaw: (it.keywords||[]).join(', '),
    model: it.model || '',
  });
  renderView();
}
async function plSave() {
  const e = state.data.pl.editing || {};
  if (!(e.title||'').trim()) { toast(t('제목을 입력하세요'), 'err'); return; }
  if (!(e.body||'').trim()) { toast(t('본문을 입력하세요'), 'err'); return; }
  const tags = (e.tagsRaw != null ? String(e.tagsRaw) : (e.tags||[]).join(','))
    .split(/[,\n]/).map(x=>x.trim()).filter(Boolean);
  const keywords = (e.keywordsRaw != null ? String(e.keywordsRaw) : (e.keywords||[]).join(','))
    .split(/[,\n]/).map(x=>x.trim()).filter(Boolean);
  const body = { id: e.id || null, title: e.title, body: e.body, tags, keywords, model: e.model || null };
  const r = await fetch('/api/prompt-library/save', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify(body),
  }).then(x => x.json());
  if (r.ok) {
    toast(t('저장 완료'), 'ok');
    plSet('editing', null);
    renderView();
  } else {
    toast(r.error || t('저장 실패'), 'err');
  }
}
async function plDelete(pid) {
  const ok = await confirmModal({ title: t('삭제'), message: t('이 프롬프트를 삭제할까요?'), confirmLabel: t('삭제'), danger: true });
  if (!ok) return;
  const r = await fetch('/api/prompt-library/delete', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({ id: pid }),
  }).then(x => x.json());
  if (r.ok) { toast(t('삭제 완료'), 'ok'); renderView(); }
  else toast(r.error || t('삭제 실패'), 'err');
}
async function plDuplicate(pid) {
  const r = await fetch('/api/prompt-library/duplicate', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({ id: pid }),
  }).then(x => x.json());
  if (r.ok) { toast(t('복제 완료'), 'ok'); renderView(); }
  else toast(r.error || t('복제 실패'), 'err');
}
async function plCopy(pid) {
  const r = await api('/api/prompt-library/list');
  const it = (r.items || []).find(x => x.id === pid);
  if (!it) return;
  try {
    await navigator.clipboard.writeText(it.body || '');
    toast(t('클립보드에 복사됨'), 'ok');
  } catch (e) {
    toast(t('복사 실패'), 'err');
  }
}
async function plToWorkflow(pid) {
  const r = await fetch('/api/prompt-library/to-workflow', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({ id: pid }),
  }).then(x => x.json());
  if (r.ok) {
    toast(t('워크플로우 생성') + ': ' + escapeHtml(r.workflowName||''), 'ok');
    setTimeout(() => go('workflows'), 800);
  } else {
    toast(r.error || t('생성 실패'), 'err');
  }
}

// ────────────────────────────────────────────────────────────────
// EMBEDDING LAB (v2.15.0) — 여러 임베딩 프로바이더 cosine rank 비교
// ────────────────────────────────────────────────────────────────
VIEWS.embeddingLab = async () => {
  const [provs, exData] = await Promise.all([
    api('/api/embedding-lab/providers'),
    api('/api/embedding-lab/examples'),
  ]);
  state.data.el = state.data.el || {
    query: '',
    docs: [''],
    selections: (provs.providers || []).filter(p => p.available).map(p => ({
      providerId: p.id, model: p.defaultModel,
    })),
    lastResult: null,
  };
  const el = state.data.el;
  const providers = provs.providers || [];
  const examples = exData.examples || [];

  const providerCards = providers.map(p => {
    const sel = el.selections.find(s => s.providerId === p.id);
    const checked = !!sel;
    return `<label class="card p-2 flex items-start gap-2 cursor-pointer text-[11px]" style="${checked?'border-color:rgba(217,119,87,0.5);background:rgba(217,119,87,0.06);':''} ${p.available?'':'opacity-60'}">
      <input type="checkbox" ${checked?'checked':''} onchange="elToggleProvider('${p.id}')" style="margin-top:2px;">
      <div style="flex:1;">
        <div class="font-semibold">${p.icon} ${escapeHtml(p.label)}</div>
        <div class="text-[10px] text-[var(--text-dim)] mt-0.5">${p.available ? (sel ? escapeHtml(sel.model) : escapeHtml(p.defaultModel)) : t('키 미설정')}</div>
        ${checked ? `
          <select class="input mt-1" style="font-size:10px;padding:2px 4px;" onchange="elSetModel('${p.id}', this.value); event.stopPropagation()">
            ${p.modelOptions.map(m => `<option value="${m}" ${sel.model===m?'selected':''}>${m}</option>`).join('')}
          </select>` : ''}
      </div>
    </label>`;
  }).join('');

  const exBtns = examples.map(e =>
    `<button class="chip" onclick="elLoadExample('${e.id}')">${t(e.label)}</button>`
  ).join('');

  const docInputs = el.docs.map((d, i) => `
    <div class="flex items-center gap-1 mb-1">
      <span class="text-[10px] text-[var(--text-dim)] font-mono w-6 text-right">${i+1}</span>
      <input class="input flex-1 text-[12px]" value="${escapeHtml(d||'')}" oninput="elSetDoc(${i}, this.value)" placeholder="${t('문서 텍스트')}">
      <button class="btn btn-sm" onclick="elRemoveDoc(${i})" ${el.docs.length<=1?'disabled':''}>✕</button>
    </div>
  `).join('');

  // 결과 매트릭스
  const last = el.lastResult;
  let resultCards = '';
  if (last && last.ok) {
    const docs = last.docs || [];
    const ranksByProvider = (last.results || []).map(r => ({
      id: r.providerId, ok: r.ok, model: r.model, dims: r.dimensions || 0,
      sims: r.sims || [], ranks: r.ranks || [], error: r.error, duration: r.durationMs,
    }));
    // 각 문서의 rank 들이 얼마나 차이 나는지 — max rank - min rank
    const rankSpans = docs.map((_, di) => {
      const rs = ranksByProvider.filter(r => r.ok).map(r => r.ranks[di]);
      if (rs.length < 2) return 0;
      return Math.max(...rs) - Math.min(...rs);
    });

    resultCards = `
      <div class="overflow-x-auto">
        <table class="w-full text-[11px] border-collapse">
          <thead>
            <tr class="border-b border-[var(--border)]">
              <th class="text-left py-1 px-2">#</th>
              <th class="text-left py-1 px-2">${t('문서')}</th>
              ${ranksByProvider.map(r => `<th class="text-center py-1 px-2 font-mono">${escapeHtml(r.id)}<br><span class="text-[9px] text-[var(--text-dim)]">${r.ok ? (r.dims+'d · '+r.duration+'ms') : '❌'}</span></th>`).join('')}
              <th class="text-center py-1 px-2">${t('rank 차이')}</th>
            </tr>
          </thead>
          <tbody>
            ${docs.map((d, di) => `
              <tr class="border-b border-[var(--border)] ${rankSpans[di]>=2?'bg-[var(--bg-hover)]':''}">
                <td class="py-1 px-2 font-mono text-[var(--text-dim)]">${di+1}</td>
                <td class="py-1 px-2" style="max-width:320px;">${escapeHtml(d).slice(0,120)}${d.length>120?'…':''}</td>
                ${ranksByProvider.map(r => r.ok ? `
                  <td class="py-1 px-2 text-center font-mono ${r.ranks[di]===1?'text-[var(--ok)] font-bold':''}">
                    <span class="text-[10px]">#${r.ranks[di]}</span>
                    <span class="text-[9px] text-[var(--text-dim)] block">${(r.sims[di]||0).toFixed(3)}</span>
                  </td>` : `<td class="py-1 px-2 text-center text-[var(--text-dim)]">-</td>`).join('')}
                <td class="py-1 px-2 text-center font-mono ${rankSpans[di]>=2?'text-[var(--warn)] font-bold':'text-[var(--text-dim)]'}">±${rankSpans[di]}</td>
              </tr>
            `).join('')}
          </tbody>
        </table>
      </div>
      <div class="text-[10px] text-[var(--text-dim)] mt-2">${t('rank 차이 ≥ 2 인 문서는 하이라이트. 프로바이더간 의견이 크게 갈리는 항목.')}</div>
      ${ranksByProvider.filter(r => !r.ok).map(r => `
        <div class="text-[11px] text-[var(--danger)] mt-1">❌ ${escapeHtml(r.id)}: ${escapeHtml(r.error||'failed')}</div>
      `).join('')}
    `;
  } else if (last && !last.ok) {
    resultCards = `<div class="text-[11px] text-[var(--danger)]">${escapeHtml(last.error||'failed')}</div>`;
  } else {
    resultCards = `<div class="text-[11px] text-[var(--text-dim)]">${t('프로바이더 + 문서를 채우고 비교를 눌러주세요.')}</div>`;
  }

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">🧬 ${t('Embedding 비교 실험실')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('같은 쿼리/문서를 여러 임베딩 프로바이더에 돌려 cosine similarity 와 rank 를 비교합니다. 프로바이더간 rank 차이가 큰 문서는 자동 하이라이트.')}
      </p>
    </div>

    <div class="mb-3 flex items-center gap-2 flex-wrap">
      <span class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('예시')}</span>
      ${exBtns}
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="space-y-3">
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('쿼리')}</label>
          <input class="input" value="${escapeHtml(el.query||'')}" oninput="elSet('query', this.value)" placeholder="${t('쿼리 문장')}">
        </div>
        <div>
          <div class="flex items-center justify-between mb-1">
            <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('문서 리스트')} (${el.docs.length})</label>
            <button class="btn btn-sm" onclick="elAddDoc()" ${el.docs.length>=10?'disabled':''}>+ ${t('추가')}</button>
          </div>
          ${docInputs}
          <div class="text-[10px] text-[var(--text-dim)]">${t('최대 10개')}</div>
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-1 block">${t('프로바이더 선택')}</label>
          <div class="space-y-2">${providerCards}</div>
        </div>
        <div class="flex items-center gap-2">
          <button class="btn btn-primary" onclick="elRun()">▶ ${t('비교 실행')}</button>
          <button class="btn" onclick="elReset()">${t('초기화')}</button>
          <span id="elStatus" class="text-[11px] text-[var(--text-dim)]"></span>
        </div>
      </div>

      <div class="space-y-3">
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('rank 매트릭스')}</div>
          ${resultCards}
        </div>
      </div>
    </div>
  `;
};

function elSet(k, v) { state.data.el = state.data.el || {}; state.data.el[k] = v; }
function elSetDoc(i, v) {
  state.data.el = state.data.el || { docs: [] };
  state.data.el.docs[i] = v;
}
function elAddDoc() {
  state.data.el = state.data.el || { docs: [] };
  if (state.data.el.docs.length >= 10) return;
  state.data.el.docs.push('');
  renderView();
}
function elRemoveDoc(i) {
  state.data.el.docs.splice(i, 1);
  renderView();
}
function elToggleProvider(pid) {
  state.data.el = state.data.el || { selections: [] };
  const i = state.data.el.selections.findIndex(s => s.providerId === pid);
  if (i >= 0) state.data.el.selections.splice(i, 1);
  else {
    // default model — fetch providers cache 는 간단히 무시, 기본은 선택 시 default 설정을 서버가 알림
    state.data.el.selections.push({ providerId: pid, model: _elDefaultModel(pid) });
  }
  renderView();
}
function _elDefaultModel(pid) {
  return ({ voyage: 'voyage-3-large', 'openai-api': 'text-embedding-3-large', 'ollama-api': 'bge-m3' }[pid]) || '';
}
function elSetModel(pid, model) {
  const s = (state.data.el.selections || []).find(x => x.providerId === pid);
  if (s) s.model = model;
}
function elReset() { state.data.el = null; renderView(); }
async function elLoadExample(id) {
  const r = await api('/api/embedding-lab/examples');
  const e = (r.examples || []).find(x => x.id === id);
  if (!e) return;
  const provs = await api('/api/embedding-lab/providers');
  state.data.el = {
    query: e.query,
    docs: e.docs.slice(),
    selections: (provs.providers || []).filter(p => p.available).map(p => ({ providerId: p.id, model: p.defaultModel })),
    lastResult: null,
  };
  renderView();
}
async function elRun() {
  const el = state.data.el || {};
  const docs = (el.docs || []).filter(d => (d||'').trim());
  if (!(el.query||'').trim()) { toast(t('쿼리를 입력하세요'), 'err'); return; }
  if (docs.length < 2) { toast(t('문서 2개 이상 필요'), 'err'); return; }
  if (!(el.selections||[]).length) { toast(t('프로바이더 1개 이상 선택'), 'err'); return; }
  const st = document.getElementById('elStatus');
  if (st) st.textContent = t('호출 중…');
  try {
    const r = await fetch('/api/embedding-lab/compare', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ query: el.query, docs, selections: el.selections }),
    }).then(x => x.json());
    if (!r.ok) { toast(r.error || t('실행 실패'), 'err'); if (st) st.textContent=''; return; }
    state.data.el.lastResult = r;
    if (st) st.textContent = `${r.totalDurationMs||0}ms`;
    renderView();
  } catch (e) {
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (st) st.textContent = '';
  }
}

// ────────────────────────────────────────────────────────────────
// AGENT SDK SCAFFOLD (v2.14.0) — claude-agent-sdk 프로젝트 뼈대 생성
// ────────────────────────────────────────────────────────────────
VIEWS.agentSdkScaffold = async () => {
  const cat = await api('/api/scaffold/catalog');
  state.data.sc = state.data.sc || {
    name: 'my-claude-agent',
    path: '~/code',
    language: 'python',
    template: 'basic',
    lastResult: null,
  };
  const sc = state.data.sc;
  const langs = cat.languages || [];
  const templates = cat.templates || [];

  const last = sc.lastResult;

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">🧪 ${t('Agent SDK 스캐폴드')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('claude-agent-sdk Python/TS 프로젝트 뼈대를 생성합니다. 생성 후 Terminal 새 창에 초기화 명령이 붙여넣기되고, Enter 로 실제 설치를 실행합니다.')}
      </p>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="space-y-3">
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('프로젝트 이름')}</label>
          <input class="input font-mono" value="${escapeHtml(sc.name||'')}" oninput="scSet('name', this.value)" placeholder="my-claude-agent">
          <div class="text-[10px] text-[var(--text-dim)] mt-1">${t('영숫자/밑줄/하이픈 2~64자')}</div>
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('부모 경로 (홈 내부)')}</label>
          <input class="input font-mono" value="${escapeHtml(sc.path||'')}" oninput="scSet('path', this.value)" placeholder="~/code">
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-1 block">${t('언어')}</label>
          <div class="flex gap-2 flex-wrap">
            ${langs.map(l => `
              <button class="chip ${sc.language===l.id?'chip-accent':''}" onclick="scSet('language','${l.id}'); renderView()">
                ${escapeHtml(l.label)} <span class="text-[9px] text-[var(--text-dim)]">${escapeHtml(l.tool)}</span>
              </button>
            `).join('')}
          </div>
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-1 block">${t('템플릿')}</label>
          <div class="space-y-2">
            ${templates.map(tp => `
              <label class="card p-2 flex items-start gap-2 cursor-pointer text-[11px]" style="${sc.template===tp.id?'border-color:rgba(217,119,87,0.5);background:rgba(217,119,87,0.06);':''}">
                <input type="radio" name="scTpl" ${sc.template===tp.id?'checked':''} onchange="scSet('template','${tp.id}'); renderView()" style="margin-top:2px;">
                <div style="flex:1;">
                  <div class="font-semibold">${t(tp.label)}</div>
                  <div class="text-[var(--text-dim)] mt-0.5">${t(tp.description)}</div>
                </div>
              </label>
            `).join('')}
          </div>
        </div>
        <div class="flex items-center gap-2">
          <button class="btn btn-primary" onclick="scCreate()">🚀 ${t('생성')}</button>
          <button class="btn" onclick="scReset()">${t('초기화')}</button>
          <span id="scStatus" class="text-[11px] text-[var(--text-dim)]"></span>
        </div>
      </div>

      <div class="space-y-3">
        ${last ? (last.ok ? `
          <div class="card p-3" style="border-left:3px solid #4ade80;">
            <div class="font-semibold text-[13px] mb-1" style="color:#4ade80;">✅ ${t('생성 완료')}</div>
            <div class="text-[11px] mb-2">
              <span class="text-[var(--text-dim)]">${t('경로')}:</span>
              <code class="font-mono ml-1">${escapeHtml(last.path||'')}</code>
            </div>
            <div class="text-[11px] mb-2">
              <span class="text-[var(--text-dim)]">${t('언어')}:</span> ${escapeHtml(last.language||'')}
              <span class="ml-3 text-[var(--text-dim)]">${t('템플릿')}:</span> ${escapeHtml(last.template||'')}
            </div>
            <div class="text-[11px] mb-2">
              <span class="text-[var(--text-dim)]">${t('Terminal 열림')}:</span>
              ${last.terminalSpawned ? '✅' : '❌ (' + t('AppleScript 실패') + ')'}
            </div>
            <div class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider mt-3 mb-1">${t('실행할 명령 (Terminal 에서 Enter)')}</div>
            <pre class="text-[10px] font-mono whitespace-pre-wrap bg-[var(--bg-alt)] p-2 rounded border border-[var(--border)]">${escapeHtml(last.nextCommand||'')}</pre>
            <div class="mt-3">
              <button class="btn btn-sm" onclick="openFolderFromPath('${escapeHtml(last.path||'')}')">📂 ${t('폴더 열기')}</button>
            </div>
          </div>
        ` : `
          <div class="card p-3" style="border-left:3px solid #f87171;">
            <div class="font-semibold text-[13px] mb-1" style="color:#f87171;">❌ ${t('생성 실패')}</div>
            <div class="text-[11px] whitespace-pre-wrap">${escapeHtml(last.error||'')}</div>
          </div>
        `) : `
          <div class="card p-6 text-center text-[11px] text-[var(--text-dim)]">
            ${t('폼을 작성하고 생성을 눌러주세요.')}
          </div>
        `}
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('요구 도구')}</div>
          <div class="text-[11px] space-y-1">
            ${langs.map(l => `
              <div>
                <span class="font-mono font-semibold">${escapeHtml(l.tool)}</span> —
                <span class="text-[var(--text-dim)]">${escapeHtml(l.installHint)}</span>
              </div>
            `).join('')}
          </div>
          <div class="text-[10px] text-[var(--text-dim)] mt-2">
            ${t('자동 설치하지 않습니다. 없으면 생성 단계에서 친절한 에러 메시지가 표시됩니다.')}
          </div>
        </div>
      </div>
    </div>
  `;
};

function scSet(k, v) { state.data.sc = state.data.sc || {}; state.data.sc[k] = v; }
function scReset() { state.data.sc = null; renderView(); }
async function scCreate() {
  const sc = state.data.sc || {};
  if (!(sc.name||'').trim()) { toast(t('이름을 입력하세요'), 'err'); return; }
  const st = document.getElementById('scStatus');
  if (st) st.textContent = t('생성 중…');
  try {
    const r = await fetch('/api/scaffold/create', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify(sc),
    }).then(x => x.json());
    state.data.sc.lastResult = r;
    if (st) st.textContent = r.ok ? t('생성 완료') : '';
    renderView();
    if (r.ok) toast(t('프로젝트 생성 완료'), 'ok');
    else toast(r.error || t('생성 실패'), 'err');
  } catch (e) {
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (st) st.textContent = '';
  }
}
function openFolderFromPath(p) {
  fetch('/api/open-folder', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({ folderPath: p }),
  });
}

// ────────────────────────────────────────────────────────────────
// CITATIONS LAB (v2.13.0) — 문서 + citations.enabled → 인용 span
// ────────────────────────────────────────────────────────────────
VIEWS.citationsLab = async () => {
  const [ex, hist] = await Promise.all([
    api('/api/citations-lab/examples'),
    api('/api/citations-lab/history'),
  ]);
  state.data.ci = state.data.ci || {
    model: 'claude-sonnet-4-6',
    maxTokens: 1024,
    title: '',
    document: '',
    prompt: '',
    lastResult: null,
    hoveredCitIndex: -1,
  };
  const ci = state.data.ci;
  const examples = ex.examples || [];

  const exBtns = examples.map(e =>
    `<button class="chip" onclick="ciLoadExample('${e.id}')">${t(e.label)}</button>`
  ).join('');

  // 답변 렌더: text 세그먼트 + 각 citation pill
  const last = ci.lastResult;
  const segs = last && last.textSegments || [];
  const allCits = [];
  segs.forEach((seg, si) => {
    (seg.citations || []).forEach((c) => {
      allCits.push({
        segIdx: si,
        cited_text: c.cited_text || '',
        start: c.start_char_index ?? c.start_page_number ?? null,
        end: c.end_char_index ?? c.end_page_number ?? null,
        type: c.type || 'char_location',
      });
    });
  });

  const answerHtml = segs.map((seg, si) => {
    const pills = (seg.citations || []).map((c) => {
      const idx = allCits.findIndex(a => a.segIdx === si && a.cited_text === (c.cited_text||''));
      return `<sup class="wf-cite-pill" style="color:var(--accent);cursor:pointer;font-weight:600;margin-left:2px;" onmouseover="ciHoverCit(${idx})" onmouseout="ciHoverCit(-1)" title="${escapeHtml((c.cited_text||'').slice(0,200))}">[${idx+1}]</sup>`;
    }).join('');
    return `<span>${escapeHtml(seg.text||'').replace(/\n/g,'<br>')}${pills}</span>`;
  }).join('');

  // 문서 하이라이트: hoveredCitIndex 가 설정되면 해당 span 을 배경색으로
  const doc = ci.document || '';
  let docHtml;
  if (ci.hoveredCitIndex >= 0 && allCits[ci.hoveredCitIndex]) {
    const c = allCits[ci.hoveredCitIndex];
    const s = c.start || 0;
    const e = c.end != null ? c.end : (s + (c.cited_text||'').length);
    const safe = (x) => escapeHtml(x).replace(/\n/g,'<br>');
    docHtml = safe(doc.slice(0, s)) +
      `<mark style="background:rgba(217,119,87,0.4);border-radius:3px;padding:1px 2px;">${safe(doc.slice(s, e))}</mark>` +
      safe(doc.slice(e));
  } else {
    docHtml = escapeHtml(doc).replace(/\n/g,'<br>');
  }

  const histList = ((hist && hist.items) || []).slice(0, 8).map(h => {
    const ts = new Date((h.ts||0)*1000).toLocaleString();
    const icon = h.status === 'ok' ? '✅' : '❌';
    return `<div class="text-[11px] py-1 border-b border-[var(--border)]">
      ${icon} <span class="text-[var(--text-dim)]">${ts}</span> · ${escapeHtml(h.title||'(no title)')}
    </div>`;
  }).join('') || `<div class="text-[11px] text-[var(--text-dim)]">${t('이력 없음')}</div>`;

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">📑 ${t('Citations 플레이그라운드')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('문서를 제공하고 citations.enabled 로 정확한 인용 span 이 포함된 답변을 받습니다. 답변의 [N] 를 hover 하면 문서의 해당 구간이 하이라이트됩니다.')}
      </p>
    </div>

    <div class="mb-3 flex items-center gap-2 flex-wrap">
      <span class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('예시')}</span>
      ${exBtns}
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="space-y-3">
        <div class="flex items-center gap-2">
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider w-20">${t('모델')}</label>
          <select class="input flex-1" onchange="ciSet('model', this.value)">
            <option value="claude-opus-4-7" ${ci.model==='claude-opus-4-7'?'selected':''}>Opus 4.7</option>
            <option value="claude-sonnet-4-6" ${ci.model==='claude-sonnet-4-6'?'selected':''}>Sonnet 4.6</option>
          </select>
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('문서 제목 (선택)')}</label>
          <input class="input" value="${escapeHtml(ci.title||'')}" oninput="ciSet('title', this.value)" placeholder="About ...">
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('문서 본문')}</label>
          <textarea class="input text-[12px] font-mono" rows="10" oninput="ciSet('document', this.value); renderView()" placeholder="${t('문서 텍스트를 붙여넣으세요')}">${escapeHtml(ci.document||'')}</textarea>
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('질문')}</label>
          <textarea class="input text-[12px]" rows="3" oninput="ciSet('prompt', this.value)" placeholder="${t('문서 기반 질문')}">${escapeHtml(ci.prompt||'')}</textarea>
        </div>
        <div class="flex items-center gap-2">
          <button class="btn btn-primary" onclick="ciRun()">▶ ${t('실행')}</button>
          <button class="btn" onclick="ciReset()">${t('초기화')}</button>
          <span id="ciStatus" class="text-[11px] text-[var(--text-dim)]"></span>
        </div>
      </div>

      <div class="space-y-3">
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">💬 ${t('답변')} ${last ? `<span class="ml-2 text-[10px] text-[var(--text-dim)]">${last.durationMs||0}ms · ${(allCits||[]).length} ${t('인용')}</span>` : ''}</div>
          <div class="text-[12px] leading-6">${last ? answerHtml : `<span class="text-[var(--text-dim)]">${t('아직 실행한 결과가 없습니다')}</span>`}</div>
        </div>
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">📄 ${t('원문')}${allCits.length > 0 ? ` <span class="text-[10px] text-[var(--text-dim)]">(${t('답변의 [N] hover')})</span>` : ''}</div>
          <div class="text-[11px] leading-5 max-h-80 overflow-auto whitespace-pre-wrap">${docHtml || `<span class="text-[var(--text-dim)]">${t('문서를 붙여넣으세요')}</span>`}</div>
        </div>
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('최근 히스토리')}</div>
          ${histList}
        </div>
      </div>
    </div>
  `;
};

function ciSet(k, v) { state.data.ci = state.data.ci || {}; state.data.ci[k] = v; }
function ciReset() { state.data.ci = null; renderView(); }
function ciHoverCit(idx) {
  state.data.ci = state.data.ci || {};
  state.data.ci.hoveredCitIndex = idx;
  renderView();
}
async function ciLoadExample(id) {
  const r = await api('/api/citations-lab/examples');
  const e = (r.examples || []).find(x => x.id === id);
  if (!e) return;
  state.data.ci = {
    model: e.model, maxTokens: 1024,
    title: e.title, document: e.document, prompt: e.prompt,
    lastResult: null, hoveredCitIndex: -1,
  };
  renderView();
}
async function ciRun() {
  const ci = state.data.ci || {};
  if (!(ci.document||'').trim()) { toast(t('문서를 입력하세요'), 'err'); return; }
  if (!(ci.prompt||'').trim()) { toast(t('질문을 입력하세요'), 'err'); return; }
  const sEl = document.getElementById('ciStatus');
  if (sEl) sEl.textContent = t('호출 중…');
  try {
    const r = await fetch('/api/citations-lab/test', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify(ci),
    }).then(x => x.json());
    if (r.needKey) { toast(t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요'), 'err'); if (sEl) sEl.textContent=''; return; }
    if (!r.ok) { toast(r.error || t('실행 실패'), 'err'); if (sEl) sEl.textContent=''; return; }
    state.data.ci.lastResult = r;
    state.data.ci.hoveredCitIndex = -1;
    if (sEl) sEl.textContent = `${r.durationMs||0}ms`;
    renderView();
  } catch (e) {
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (sEl) sEl.textContent = '';
  }
}

// ────────────────────────────────────────────────────────────────
// CLAUDE DOCS HUB (v2.12.0) — docs.anthropic.com 색인 + 검색
// ────────────────────────────────────────────────────────────────
// v2.33.7 — claudeDocs 북마크 (localStorage 저장)
function _cdLoadBookmarks() {
  try { return new Set(JSON.parse(localStorage.getItem('cd-bookmarks') || '[]')); }
  catch { return new Set(); }
}
function _cdSaveBookmarks(set) {
  try { localStorage.setItem('cd-bookmarks', JSON.stringify([...set])); } catch {}
}
function cdToggleBookmark(url) {
  const set = _cdLoadBookmarks();
  if (set.has(url)) set.delete(url); else set.add(url);
  _cdSaveBookmarks(set);
  renderView();
}
window.cdToggleBookmark = cdToggleBookmark;

VIEWS.claudeDocs = async () => {
  state.data.cd = state.data.cd || { q: '', onlyBookmarks: false };
  const cd = state.data.cd;
  const url = cd.q ? `/api/claude-docs/search?q=${encodeURIComponent(cd.q)}` : '/api/claude-docs/list';
  const data = await api(url);
  const bookmarks = _cdLoadBookmarks();
  let cats = data.categories || [];
  if (cd.onlyBookmarks) {
    cats = cats.map(c => ({ ...c, items: (c.items || []).filter(it => bookmarks.has(it.url)) }))
               .filter(c => c.items.length > 0);
  }
  const total = cats.reduce((a, c) => a + (c.items||[]).length, 0);

  const renderCard = (it) => {
    const starred = bookmarks.has(it.url);
    return `
    <div class="card p-3 flex flex-col gap-1" style="border-left:3px solid ${starred?'#fbbf24':'var(--accent)'};">
      <div class="flex items-start justify-between gap-2">
        <div class="font-semibold text-[13px]" style="color:var(--text);">${escapeHtml(it.title)}</div>
        <button class="btn-ghost btn text-[13px] px-1.5 py-0" onclick="cdToggleBookmark(${JSON.stringify(it.url).replace(/"/g,'&quot;')})" title="${starred?t('북마크 해제'):t('북마크 추가')}" aria-label="${starred?t('북마크 해제'):t('북마크 추가')}">${starred?'★':'☆'}</button>
      </div>
      <div class="text-[11px] text-[var(--text-mute)] flex-1">${escapeHtml(it.summary)}</div>
      <div class="flex items-center gap-2 mt-1">
        <a href="${it.url}" target="_blank" class="btn btn-sm">🔗 ${t('외부 열기')}</a>
        ${it.relatedTab ? `<button class="btn btn-sm" onclick="go('${it.relatedTab}')">→ ${t('관련 탭')}</button>` : ''}
      </div>
      <div class="text-[9px] text-[var(--text-dim)] font-mono truncate">${escapeHtml(it.url)}</div>
    </div>`;
  };

  const sections = cats.map(cat => `
    <div class="mb-6">
      <h2 class="text-sm font-semibold mb-2" style="color:var(--text);">${escapeHtml(cat.label)} <span class="text-[10px] text-[var(--text-dim)]">(${(cat.items||[]).length})</span></h2>
      <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
        ${(cat.items||[]).map(renderCard).join('')}
      </div>
    </div>
  `).join('') || `<div class="card p-6 text-center text-[11px] text-[var(--text-dim)]">${cd.onlyBookmarks ? t('북마크한 문서 없음') : t('검색 결과 없음')}</div>`;

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">📖 Claude Docs Hub</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('Anthropic 공식 문서 주요 페이지를 카테고리별로 색인. 검색어로 필터링하고 관련 대시보드 탭으로 바로 이동할 수 있습니다.')}
      </p>
    </div>

    <div class="flex items-center gap-2 mb-4 flex-wrap">
      <input class="input flex-1" placeholder="${t('키워드로 검색 (제목/요약/URL)')}"
             value="${escapeHtml(cd.q || '')}"
             oninput="cdSet('q', this.value); cdRender()">
      <button class="chip ${cd.onlyBookmarks?'chip-accent':''}" onclick="cdSet('onlyBookmarks', !state.data.cd.onlyBookmarks); renderView()">★ ${t('북마크')} ${bookmarks.size}</button>
      <span class="text-[11px] text-[var(--text-dim)]">${total}${t('건')}</span>
      ${cd.q ? `<button class="btn btn-sm" onclick="cdSet('q',''); renderView()">✕ ${t('지우기')}</button>` : ''}
    </div>

    ${sections}
  `;
};

function cdSet(k, v) {
  state.data.cd = state.data.cd || {};
  state.data.cd[k] = v;
}
let _cdRenderTimer = null;
function cdRender() {
  // 검색 debounce — 300ms
  if (_cdRenderTimer) clearTimeout(_cdRenderTimer);
  _cdRenderTimer = setTimeout(() => { _cdRenderTimer = null; renderView(); }, 300);
}

// ────────────────────────────────────────────────────────────────
// SERVER-SIDE TOOLS (v2.11.0)
// Anthropic hosted tools: web_search + code_execution
// ────────────────────────────────────────────────────────────────
VIEWS.serverTools = async () => {
  const [cat, hist] = await Promise.all([
    api('/api/server-tools/catalog'),
    api('/api/server-tools/history'),
  ]);
  state.data.st = state.data.st || {
    model: 'claude-sonnet-4-6',
    maxTokens: 2048,
    prompt: '',
    enabled: ['web_search'],
    lastResult: null,
  };
  const st = state.data.st;
  const tools = cat.tools || [];
  const examples = cat.examples || [];

  const exBtns = examples.map(e =>
    `<button class="chip" onclick="stLoadExample('${e.id}')">${t(e.label)}</button>`
  ).join('');

  const toolChecks = tools.map(tool => {
    const checked = st.enabled.includes(tool.id);
    const modelSupported = tool.supportedModels.includes(st.model);
    return `<label class="flex items-start gap-2 text-[11px] cursor-pointer select-none p-2 rounded border border-[var(--border)] ${modelSupported?'':'opacity-50'}" style="${checked?'background:rgba(217,119,87,0.08);border-color:rgba(217,119,87,0.4);':''}">
      <input type="checkbox" ${checked?'checked':''} ${modelSupported?'':'disabled'} onchange="stToggleTool('${tool.id}')" style="margin-top:2px;">
      <div style="flex:1;">
        <div class="font-semibold" style="font-size:12px;">${t(tool.label)}</div>
        <div class="text-[var(--text-dim)] mt-0.5">${t(tool.description)}</div>
        <div class="text-[10px] text-[var(--text-dim)] mt-1 font-mono">${tool.apiType}</div>
        ${!modelSupported ? `<div class="text-[10px] text-[var(--warn)] mt-1">⚠ ${t('현재 모델에서 미지원')}</div>` : ''}
      </div>
    </label>`;
  }).join('');

  const last = st.lastResult;
  const blocks = last && (last.output || last.serverToolUses?.length || last.toolResults?.length);

  const histList = ((hist && hist.items) || []).slice(0, 8).map(h => {
    const ts = new Date((h.ts||0)*1000).toLocaleString();
    const icon = h.status === 'ok' ? '✅' : '❌';
    return `<div class="text-[11px] py-1 border-b border-[var(--border)]">
      ${icon} <span class="text-[var(--text-dim)]">${ts}</span> · ${(h.enabledTools||[]).join('+')} · ${h.durationMs||0}ms
    </div>`;
  }).join('') || `<div class="text-[11px] text-[var(--text-dim)]">${t('이력 없음')}</div>`;

  return `
    <div class="mb-4">
      <h1 class="text-2xl font-bold">🧰 ${t('Claude 공식 내장 Tools')}</h1>
      <p class="text-sm text-[var(--text-mute)] mt-1">
        ${t('Anthropic 서버가 직접 실행하는 hosted tool (web_search / code_execution) 을 활성화하고 응답 블록을 분류 시각화합니다.')}
      </p>
    </div>

    <div class="mb-3 flex items-center gap-2 flex-wrap">
      <span class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('예시')}</span>
      ${exBtns}
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="space-y-3">
        <div class="flex items-center gap-2 flex-wrap">
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider w-20">${t('모델')}</label>
          <select class="input flex-1" onchange="stSet('model', this.value); renderView()">
            <option value="claude-opus-4-7" ${st.model==='claude-opus-4-7'?'selected':''}>Opus 4.7</option>
            <option value="claude-sonnet-4-6" ${st.model==='claude-sonnet-4-6'?'selected':''}>Sonnet 4.6</option>
          </select>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">max_tokens</label>
          <input type="text" inputmode="numeric" class="input w-24" value="${st.maxTokens}"
                 oninput="stSet('maxTokens', parseInt((this.value||'').replace(/\\D/g,''))||2048)">
        </div>
        <div>
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('활성화할 도구')}</div>
          <div class="space-y-2">${toolChecks}</div>
        </div>
        <div>
          <label class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider">${t('프롬프트')}</label>
          <textarea class="input text-[12px]" rows="5" oninput="stSet('prompt', this.value)" placeholder="${t('도구를 활용할 질문')}">${escapeHtml(st.prompt||'')}</textarea>
        </div>
        <div class="flex items-center gap-2">
          <button class="btn btn-primary" onclick="stRun()">▶ ${t('실행')}</button>
          <button class="btn" onclick="stReset()">${t('초기화')}</button>
          <span id="stStatus" class="text-[11px] text-[var(--text-dim)]"></span>
        </div>
      </div>

      <div class="space-y-3 max-h-[720px] overflow-auto pr-1">
        ${blocks ? `
          ${(last.serverToolUses||[]).map(u => `
            <div class="card p-3" style="border-left:3px solid #a78bfa;">
              <div class="text-[11px] text-[var(--accent)] font-mono mb-1">🛠️ server_tool_use · ${escapeHtml(u.name||'')}</div>
              <pre class="text-[10px] font-mono whitespace-pre-wrap text-[var(--text-dim)]">${escapeHtml(JSON.stringify(u.input||{}, null, 2))}</pre>
            </div>
          `).join('')}
          ${(last.toolResults||[]).map(r => `
            <div class="card p-3" style="border-left:3px solid #4ade80;">
              <div class="text-[11px] font-mono mb-1" style="color:#4ade80;">✓ ${escapeHtml(r.kind||'tool_result')}</div>
              <pre class="text-[10px] font-mono whitespace-pre-wrap max-h-60 overflow-auto">${escapeHtml(typeof r.content === 'string' ? r.content : JSON.stringify(r.content, null, 2)).slice(0, 2000)}</pre>
            </div>
          `).join('')}
          ${last.output ? `
            <div class="card p-3">
              <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">💬 ${t('최종 응답')}</div>
              <pre class="text-[11px] whitespace-pre-wrap">${escapeHtml(last.output)}</pre>
              ${last.usage ? `<div class="text-[10px] text-[var(--text-dim)] font-mono mt-2">in=${last.usage.input_tokens||0} · out=${last.usage.output_tokens||0} · ${last.durationMs||0}ms</div>` : ''}
            </div>
          ` : ''}
        ` : `<div class="card p-6 text-center text-[11px] text-[var(--text-dim)]">${t('아직 실행한 결과가 없습니다')}</div>`}
        <div class="card p-3">
          <div class="text-[11px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('최근 히스토리')}</div>
          ${histList}
        </div>
      </div>
    </div>
  `;
};

function stSet(key, val) {
  state.data.st = state.data.st || {};
  state.data.st[key] = val;
}
function stReset() { state.data.st = null; renderView(); }
function stToggleTool(tid) {
  const st = state.data.st;
  const i = st.enabled.indexOf(tid);
  if (i >= 0) st.enabled.splice(i, 1);
  else st.enabled.push(tid);
  renderView();
}
async function stLoadExample(id) {
  const r = await api('/api/server-tools/catalog');
  const e = (r.examples || []).find(x => x.id === id);
  if (!e) return;
  state.data.st = {
    model: e.model,
    maxTokens: 2048,
    prompt: e.prompt,
    enabled: e.enabledTools.slice(),
    lastResult: null,
  };
  renderView();
}
async function stRun() {
  const st = state.data.st || {};
  if (!(st.prompt||'').trim()) { toast(t('프롬프트를 입력하세요'), 'err'); return; }
  if (!(st.enabled||[]).length) { toast(t('도구를 1개 이상 활성화하세요'), 'err'); return; }
  const sEl = document.getElementById('stStatus');
  if (sEl) sEl.textContent = t('호출 중…');
  try {
    const r = await fetch('/api/server-tools/run', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify(st),
    }).then(x => x.json());
    if (r.needKey) { toast(t('ANTHROPIC_API_KEY 미설정 — AI 프로바이더 탭에서 저장하세요'), 'err'); if (sEl) sEl.textContent=''; return; }
    if (r.unsupported) { toast(r.error, 'err'); if (sEl) sEl.textContent=''; return; }
    if (!r.ok) { toast(r.error || t('실행 실패'), 'err'); if (sEl) sEl.textContent=''; return; }
    state.data.st.lastResult = r;
    if (sEl) sEl.textContent = `${r.durationMs||0}ms`;
    renderView();
  } catch (e) {
    toast(t('네트워크 오류') + ': ' + e.message, 'err');
    if (sEl) sEl.textContent = '';
  }
}

// ────────────────────────────────────────────────────────────────
// HOOKS + PERMISSIONS
// ────────────────────────────────────────────────────────────────
const HOOK_EVENTS = ['SessionStart', 'SessionEnd', 'UserPromptSubmit', 'PreToolUse', 'PostToolUse', 'Stop', 'SubagentStop', 'Notification'];
// ────────────────────────────────────────────────────────────────
// EVENT FORWARDER (v2.29.0) — Claude Code hooks → 외부 HTTP POST
// ────────────────────────────────────────────────────────────────
VIEWS.eventForwarder = async () => {
  const [meta, list] = await Promise.all([
    api('/api/event-forwarder/meta'),
    api('/api/event-forwarder/list'),
  ]);
  if (!meta.ok || !list.ok) return `<div class="card p-6 text-[12px]">${t('데이터를 불러오지 못했습니다')}</div>`;
  const events = meta.events || [];
  const allowed = meta.allowedHosts || [];
  const forwarders = list.forwarders || [];

  const rows = forwarders.map((f, i) => `
    <tr class="border-b border-[var(--border)]">
      <td class="py-1 px-2 font-mono text-[11px]">${escapeHtml(f.event)}</td>
      <td class="py-1 px-2 font-mono text-[10px]" style="color:var(--text-dim)">${escapeHtml(f.matcher||'-')}</td>
      <td class="py-1 px-2 font-mono text-[10px] break-all">${escapeHtml(f.url)}</td>
      <td class="py-1 px-2 text-right">
        <button class="btn text-[10px]" onclick="_fwdRemove('${escapeHtml(f.event)}',${f.groupIdx},${f.subIdx})" style="color:#fca5a5;border-color:rgba(248,113,113,0.3);">🗑</button>
      </td>
    </tr>
  `).join('') || `<tr><td colspan="4" class="py-4 text-center text-[11px]" style="color:var(--text-dim)">${t('fwd_empty', '등록된 forwarder 가 없습니다')}</td></tr>`;

  return `
    ${viewHeader('📤 Event Forwarder', t('fwd_subtitle', 'Claude Code hooks 이벤트를 외부 HTTP endpoint 로 포워딩 — 화이트리스트 호스트만 허용, settings.json 자동 백업.'), 'eventForwarder')}

    <div class="card p-5 mb-4">
      <h3 class="text-base font-semibold mb-3">➕ ${t('fwd_add_heading', '새 Forwarder 추가')}</h3>
      <div class="grid grid-cols-1 md:grid-cols-4 gap-2 mb-2">
        <select id="fwdEvent" class="input text-[12px]">
          ${events.map(e => `<option value="${e}">${e}</option>`).join('')}
        </select>
        <input id="fwdMatcher" class="input text-[12px]" placeholder="${t('fwd_matcher_placeholder', 'matcher (예: Bash, *, 비워두면 all)')}">
        <input id="fwdUrl" class="input text-[12px] md:col-span-2" placeholder="https://hooks.slack.com/... 또는 https://webhook.site/...">
      </div>
      <div class="flex items-center gap-2 flex-wrap">
        <button class="btn btn-primary text-[12px]" onclick="_fwdAdd()">📤 ${t('fwd_add_btn', 'Forwarder 추가')}</button>
        <span class="text-[10px]" style="color:var(--text-dim)">${t('fwd_allowed_hosts', '허용 호스트')}: ${allowed.map(h => `<code>${escapeHtml(h)}</code>`).join(' · ')}</span>
      </div>
    </div>

    <div class="card p-4">
      <h3 class="text-base font-semibold mb-2">📋 ${t('fwd_list_heading', '등록된 Forwarder')}</h3>
      <table class="w-full text-[11px] border-collapse">
        <thead><tr class="border-b border-[var(--border)]">
          <th class="text-left py-1 px-2">${t('이벤트')}</th>
          <th class="text-left py-1 px-2">${t('fwd_matcher_col', '매처')}</th>
          <th class="text-left py-1 px-2">URL</th>
          <th class="text-right py-1 px-2">${t('fwd_action_col', '작업')}</th>
        </tr></thead>
        <tbody>${rows}</tbody>
      </table>
      <div class="text-[10px] mt-3" style="color:var(--text-dim)">
        ${t('fwd_hint', 'forwarder 는 settings.json 의 hooks 섹션에 curl 명령으로 등록됩니다. 매 변경 시 자동 백업 생성.')}
      </div>
    </div>
  `;
};

async function _fwdAdd() {
  const event = document.getElementById('fwdEvent').value;
  const matcher = document.getElementById('fwdMatcher').value.trim();
  const url = document.getElementById('fwdUrl').value.trim();
  if (!url) { toast(t('URL 을 먼저 입력하세요'), 'err'); return; }
  try {
    const r = await api('/api/event-forwarder/add', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ event, matcher, url }),
    });
    if (!r.ok) { toast(errMsg(r), 'err'); return; }
    toast(t('fwd_added', 'Forwarder 추가됨'), 'ok');
    renderView();
  } catch (e) { toast(String(e), 'err'); }
}

async function _fwdRemove(event, groupIdx, subIdx) {
  const ok = await confirmModal(t('fwd_remove_confirm', '이 forwarder 를 settings.json 에서 제거합니다. 계속할까요?'));
  if (!ok) return;
  try {
    const r = await api('/api/event-forwarder/remove', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ event, groupIdx, subIdx }),
    });
    if (!r.ok) { toast(errMsg(r), 'err'); return; }
    toast(t('fwd_removed', '제거됨'), 'ok');
    renderView();
  } catch (e) { toast(String(e), 'err'); }
}

// v2.42.3 — `/api/hooks/recent-blocks` walks ~90 MB of jsonl transcripts,
// adding ~1 s to the first Hooks tab paint. Cache the result in JS memory
// so re-renders (filter changes, deletes) reuse it; the initial fetch is
// deferred to AFTER.hooks so the page paints immediately.
let __hooksRecentBlocks = null;
let __hooksRecentBlocksFetching = false;

VIEWS.hooks = async () => {
  // v2.43.0 — surface project hooks (which live inside <cwd>/.claude/
  // settings.json[hooks]) when a project is selected. Editing remains in
  // the Settings tab to keep the JSON shape authoritative.
  const projects = await _ensureProjectsCache();
  const cfgScope = state.data.cfgScope || 'global';
  const cfgCwd = state.data.cfgCwd || (projects[0]?.path || '');
  const inProject = cfgScope === 'project' && cfgCwd;
  let projectHookSummary = null;
  if (inProject) {
    try {
      const [psr, plr] = await Promise.all([
        api('/api/project/settings?cwd=' + encodeURIComponent(cfgCwd)),
        api('/api/project/settings-local?cwd=' + encodeURIComponent(cfgCwd)),
      ]);
      const countHooks = (data) => {
        const h = (data && data.hooks) || {};
        let n = 0;
        Object.values(h).forEach(items => {
          if (Array.isArray(items)) {
            items.forEach(it => {
              if (it && Array.isArray(it.hooks)) n += it.hooks.length;
              else if (it) n += 1;
            });
          }
        });
        return n;
      };
      projectHookSummary = {
        cwd: cfgCwd,
        projectN: countHooks(psr.data),
        projectExists: !!psr.exists,
        projectLocalN: countHooks(plr.data),
        projectLocalExists: !!plr.exists,
      };
    } catch (e) { /* non-fatal */ }
  }
  const [s, hooksAll] = await Promise.all([
    api('/api/settings'),
    api('/api/hooks'),
  ]);
  const recentBlocks = __hooksRecentBlocks || {items: [], totalEvents: 0, scanned: 0};
  window.__settingsSnapshot = s;
  const rawHooks = s.hooks || {};
  // 사용자 훅(편집 가능): settings.json 에서 인덱스 보존하며 평탄화
  const userFlat = [];
  Object.keys(rawHooks).sort().forEach(ev => {
    (rawHooks[ev] || []).forEach((item, i) => {
      const matcher = item.matcher || '';
      const subs = item.hooks || [];
      if (subs.length) {
        subs.forEach((sh, j) => userFlat.push({ event: ev, scope: 'user', groupIdx: i, subIdx: j, matcher, ...sh }));
      } else {
        userFlat.push({ event: ev, scope: 'user', groupIdx: i, subIdx: -1, matcher, ...item });
      }
    });
  });
  // 플러그인 훅(read-only)
  const pluginFlat = (hooksAll.hooks || []).filter(h => h.scope === 'plugin');
  const counts = hooksAll.counts || {};

  const allEvents = Array.from(new Set([...userFlat, ...pluginFlat].map(h => h.event))).sort();
  const orderedEvents = HOOK_EVENTS.filter(ev => allEvents.includes(ev)).concat(allEvents.filter(ev => !HOOK_EVENTS.includes(ev)));

  // v2.40.3 — synthesise the human-readable hook name shown by Claude Code's
  // `/hooks` command. Priority: explicit id → explicit name → derived from
  // event + matcher (or "(no matcher)").
  const _hookDisplayName = (x) => x.id || x.name
    || (x.event + (x.matcher ? ' · ' + x.matcher : ' · (no matcher)'));
  const renderUserCard = (x) => `
    <div class="rounded-lg bg-white/5 p-3 text-xs border border-[var(--border)]" style="display:flex; align-items:flex-start; gap:0.75rem; min-width:0; max-width:100%; overflow:hidden;">
      <div style="flex:1 1 0; min-width:0; max-width:100%; overflow:hidden;">
        <div class="font-semibold text-sm mb-1 mono" style="overflow-wrap:anywhere;">${escapeHtml(_hookDisplayName(x))}</div>
        <div class="flex items-center gap-2 mb-1 flex-wrap"><span class="chip chip-ok text-[9px]" style="white-space:nowrap;">✓ 사용자 설정</span></div>
        ${x.matcher ? `<div class="mb-1" style="overflow-wrap:anywhere;"><span class="text-[var(--text-dim)]">matcher:</span> <span class="mono">${escapeHtml(x.matcher)}</span></div>`:''}
        ${x.type ? `<div class="mb-1"><span class="text-[var(--text-dim)]">type:</span> <span class="mono">${escapeHtml(x.type)}</span></div>`:''}
        ${x.command ? `<div class="mb-1"><div class="text-[var(--text-dim)] mb-1">cmd:</div><pre class="mono" style="display:block; box-sizing:border-box; width:100%; max-width:100%; margin:0; white-space:pre-wrap; overflow-wrap:anywhere; word-break:break-word; max-height:200px; overflow-y:auto; overflow-x:hidden; background:rgba(0,0,0,0.3); padding:6px 8px; border-radius:6px; font-size:11px;">${escapeHtml(x.command)}</pre></div>`:''}
        ${x.timeout ? `<div><span class="text-[var(--text-dim)]">timeout:</span> ${x.timeout}ms</div>`:''}
      </div>
      <div class="flex flex-col gap-1 flex-shrink-0">
        <button class="btn text-[10px]" onclick="openHookDetail(this.dataset.detail)" data-detail="${jsonAttr(x)}">${t('🔬 상세')}</button>
        <button class="btn text-[10px]" onclick="openHookEditor(JSON.parse(this.dataset.payload))" data-payload="${jsonAttr({scope:"user", event:x.event, groupIdx:x.groupIdx, subIdx:x.subIdx, matcher:x.matcher||"", type:x.type||"command", command:x.command||"", timeout:x.timeout})}">수정</button>
        <button class="btn text-[10px]" style="color:#fca5a5" onclick="deleteHook(JSON.parse(this.dataset.payload))" data-payload="${jsonAttr({scope:"user", event:x.event, groupIdx:x.groupIdx, subIdx:x.subIdx})}">삭제</button>
      </div>
    </div>`;

  const renderPluginCard = (x) => {
    const badge = x.pluginEnabled
      ? '<span class="chip text-[9px]" style="background:rgba(217,119,87,0.12); white-space:nowrap;">🔌 플러그인 제공</span>'
      : `<button class="chip chip-warn text-[9px]" style="white-space:nowrap;" onclick="togglePluginFromAgent('${escapeHtml(x.pluginKey||'')}', true)">비활성 플러그인 ▶ 활성화</button>`;
    const editPayload = jsonAttr({scope:"plugin", pluginKey:x.pluginKey, event:x.event, groupIdx:x.groupIdx, subIdx:x.subIdx, matcher:x.matcher||"", type:x.type||"command", command:x.command||"", timeout:x.timeout});
    const delPayload = jsonAttr({scope:"plugin", pluginKey:x.pluginKey, event:x.event, groupIdx:x.groupIdx, subIdx:x.subIdx});
    return `
    <div class="rounded-lg p-3 text-xs border border-[var(--border)]" style="display:flex; align-items:flex-start; gap:0.75rem; background:rgba(217,119,87,0.06); min-width:0; max-width:100%; overflow:hidden;">
      <div style="flex:1 1 0; min-width:0; max-width:100%; overflow:hidden;">
        <div class="font-semibold text-sm mb-1 mono" style="overflow-wrap:anywhere;">${escapeHtml(_hookDisplayName(x))}</div>
        <div class="flex items-center gap-2 mb-1 flex-wrap">
          ${badge}
          <span class="text-[10px] mono text-[var(--text-dim)] truncate" style="max-width:200px;">${escapeHtml(x.source||'')}</span>
        </div>
        ${x.description ? `<div class="text-[var(--text)] mb-1" style="overflow-wrap:anywhere;">${escapeHtml(x.description)}</div>`:''}
        ${x.matcher ? `<div class="mb-1" style="overflow-wrap:anywhere;"><span class="text-[var(--text-dim)]">matcher:</span> <span class="mono">${escapeHtml(x.matcher)}</span></div>`:''}
        ${x.type ? `<div class="mb-1"><span class="text-[var(--text-dim)]">type:</span> <span class="mono">${escapeHtml(x.type)}</span></div>`:''}
        ${x.command ? `<div class="mb-1"><div class="text-[var(--text-dim)] mb-1">cmd:</div><pre class="mono" style="display:block; box-sizing:border-box; width:100%; max-width:100%; margin:0; white-space:pre-wrap; overflow-wrap:anywhere; word-break:break-word; max-height:200px; overflow-y:auto; overflow-x:hidden; background:rgba(0,0,0,0.3); padding:6px 8px; border-radius:6px; font-size:11px;">${escapeHtml(x.command)}</pre></div>`:''}
        ${x.timeout ? `<div><span class="text-[var(--text-dim)]">timeout:</span> ${x.timeout}ms</div>`:''}
      </div>
      <div class="flex flex-col gap-1 flex-shrink-0">
        <button class="btn text-[10px]" onclick="openHookDetail(this.dataset.detail)" data-detail="${jsonAttr(x)}">${t('🔬 상세')}</button>
        <button class="btn text-[10px]" title="플러그인 hooks.json 직접 수정" onclick="openHookEditor(JSON.parse(this.dataset.payload))" data-payload="${editPayload}">수정</button>
        <button class="btn text-[10px]" style="color:#fca5a5" onclick="deleteHook(JSON.parse(this.dataset.payload))" data-payload="${delPayload}">삭제</button>
      </div>
    </div>`;
  };

  // v2.40.2 — emergency UX upgrade: search · scope · event filter · risk chip
  // · "panic" disable for risky PreToolUse(Edit|Write|Bash) hooks. With 100+
  // plugin hooks installed, the previous flat list was unscannable.
  const _hRiskRe = /\b(Edit|Write|Bash|MultiEdit|NotebookEdit)\b/;
  const isRisky = (h) => h.event === 'PreToolUse' && (h.matcher && _hRiskRe.test(h.matcher));

  const q       = (state.data.hooksFilter || '').toLowerCase().trim();
  const scopeF  = state.data.hooksScope  || 'all';   // all | user | plugin
  const eventF  = state.data.hooksEvent  || '';      // '' | <event>
  const riskOnly = !!state.data.hooksRiskOnly;

  const matches = (h) => {
    if (scopeF !== 'all' && h.scope !== scopeF) return false;
    if (eventF && h.event !== eventF) return false;
    if (riskOnly && !isRisky(h)) return false;
    if (!q) return true;
    const hay = [h.event, h.matcher, h.command, h.type, h.source, h.pluginKey, h.description, h.id]
      .filter(Boolean).join(' ').toLowerCase();
    return hay.includes(q);
  };

  const userFiltered   = userFlat.filter(matches);
  const pluginFiltered = pluginFlat.filter(matches);
  const totalShown     = userFiltered.length + pluginFiltered.length;
  const totalAll       = userFlat.length + pluginFlat.length;
  const riskCount = [...userFlat, ...pluginFlat].filter(isRisky).length;

  // wrap user/plugin renderers to add a 🚨 chip + danger background for risky entries.
  const _decorateRisk = (html, h) => isRisky(h)
    ? html.replace('class="rounded-lg', 'data-risk="1" class="rounded-lg')
          .replace('">', `" style="border-color: rgba(239,68,68,0.45); box-shadow: 0 0 0 1px rgba(239,68,68,0.15);">`)
          .replace('<div class="flex items-center gap-2 mb-1 flex-wrap">',
                   `<div class="flex items-center gap-2 mb-1 flex-wrap"><span class="chip chip-warn text-[9px]" style="background:rgba(239,68,68,0.2);color:#fca5a5;white-space:nowrap;" title="${t('PreToolUse + Edit/Write/Bash 매처 — 작업이 막히는 원인일 가능성')}">🚨 ${t('위험')}</span>`)
    : html;

  const eventChip = (ev) => {
    const c = orderedEvents.includes(ev) ? [...userFlat, ...pluginFlat].filter(h => h.event === ev).length : 0;
    const active = eventF === ev;
    return `<button class="chip text-[10px] cursor-pointer" style="${active?'background:var(--accent);color:#fff;':''}"
      onclick="state.data.hooksEvent='${active?'':escapeHtml(ev)}';renderView();">${escapeHtml(ev)} <span class="text-[9px] opacity-70">${c}</span></button>`;
  };

  return `
    ${_renderConfigScopeToggle({scope: cfgScope, cwd: cfgCwd, projects, label: t('훅 스코프')})}
    ${inProject && projectHookSummary ? `
      <div class="card p-3 mb-3" style="background:rgba(125,211,252,0.08); border-color:rgba(125,211,252,0.3);">
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)] mb-1.5 flex items-center gap-2">
          <span>📁</span> <span>${t('프로젝트 훅')}</span>
          <span class="text-[10px]" style="text-transform:none;letter-spacing:0;color:var(--text-mute);">${escapeHtml(projectHookSummary.cwd)}/.claude/</span>
        </div>
        <div class="text-xs text-[var(--text-mute)]">
          <span class="mono">settings.json</span>: <b>${projectHookSummary.projectN}</b>${t('개')}${projectHookSummary.projectExists?'':' '+t('(파일 없음)')}
          · <span class="mono">settings.local.json</span>: <b>${projectHookSummary.projectLocalN}</b>${t('개')}${projectHookSummary.projectLocalExists?'':' '+t('(파일 없음)')}
          · <button class="btn text-[10px]" onclick="state.data.cfgScope='project';go('settings');">▶ ${t('Settings 탭에서 편집')}</button>
        </div>
        <div class="text-[10px] mt-1" style="color:var(--text-dim);">${t('아래 목록은 글로벌 + 플러그인 훅. 프로젝트 훅은 settings.json 의 hooks 키로 편집합니다.')}</div>
      </div>
    ` : ''}
    <div class="mb-4 flex items-center justify-between gap-2 flex-wrap">
      <div>
        <h1 class="text-2xl font-bold">${t('훅 (Hooks)')}</h1>
        <p class="text-sm text-[var(--text-mute)] mt-1"><b>${t('활성(사용자 설정)')} ${counts.user||userFlat.length}${t('개')}</b> · ${t('플러그인 제공')} ${counts.pluginEnabled||0}/${counts.plugin||pluginFlat.length} (${t('별도')}) · ${allEvents.length}${t('개 이벤트')}${riskCount?` · <span style="color:#fca5a5;">🚨 ${t('위험')} ${riskCount}${t('개')}</span>`:''}</p>
      </div>
      <div class="flex gap-2">
        ${riskCount ? `<button class="btn text-xs" style="background:rgba(239,68,68,0.18);color:#fca5a5;border:1px solid rgba(239,68,68,0.4);" onclick="_panicDisableRiskyHooks()" title="${t('PreToolUse + Edit/Write/Bash 매처를 가진 모든 훅을 한 번에 비활성화 (삭제)')}">🚨 ${t('위험 훅 일괄 비활성화')}</button>`:''}
        <button class="btn text-xs" onclick="startFeatureRecommend('hooks')">🤖 AI 추천</button>
        <button class="btn text-xs" onclick="_openHookPresets()">📚 ${t('프리셋')}</button>
        <button class="btn-primary btn" onclick="openHookEditor()">＋ 새 훅 추가</button>
        <a class="btn text-xs" href="${DOCS_BASE}hooks" target="_blank" rel="noopener">📖</a>
      </div>
    </div>

    <!-- v2.40.4 — Hook Detective: paste any block-error message, auto-extract
         hook id, scroll its card into view + pulse highlight. -->
    <div class="card p-3 mb-3" style="background:rgba(59,130,246,0.06); border-color:rgba(59,130,246,0.3);">
      <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)] mb-1.5 flex items-center gap-2">
        <span>🔍</span> <span>${t('Hook Detective')}</span>
        <span class="text-[10px]" style="text-transform:none;letter-spacing:0;color:var(--text-mute);">${t('차단 에러 메시지를 붙여넣으면 어떤 훅인지 자동 식별')}</span>
      </div>
      <textarea id="hookDetectiveInput" class="input w-full mono text-[11px]" rows="2" placeholder="${t('PreToolUse:Edit hook returned blocking error from command: …')}"></textarea>
      <div id="hookDetectiveResult" class="text-[11px] mt-1.5" style="min-height:18px;color:var(--text-dim);"></div>
    </div>

    <!-- v2.40.4 — Recent Blocks: top-N hook ids that recently blocked work.
         v2.42.3 — wrapped in a host div so the lazy-loaded data can be
         injected after first paint without rebuilding the whole view. -->
    <div id="hooksRecentBlocksHost">${_renderRecentBlocksPanel(recentBlocks)}</div>

    <!-- v2.40.2 — search + filter bar (always visible, no flyout). -->
    <div class="card p-3 mb-3" style="display:flex;flex-direction:column;gap:8px;">
      <div class="flex items-center gap-2 flex-wrap">
        <input id="hookSearch" class="input flex-1 min-w-[220px]" type="search" placeholder="${t('훅 검색 — 매처 / 명령 / 플러그인 / 설명')}…" value="${escapeHtml(q)}" />
        <div class="flex items-center gap-1">
          ${['all','user','plugin'].map(sc => `<button class="chip text-[10px] cursor-pointer" style="${scopeF===sc?'background:var(--accent);color:#fff;':''}" onclick="state.data.hooksScope='${sc}';renderView();">${({all:t('전체'),user:t('사용자'),plugin:t('플러그인')})[sc]}</button>`).join('')}
        </div>
        <label class="flex items-center gap-1 text-xs cursor-pointer" style="color:#fca5a5;">
          <input type="checkbox" id="hooksRiskOnly" ${riskOnly?'checked':''}/> 🚨 ${t('위험 훅만')}
        </label>
        ${(q||eventF||scopeF!=='all'||riskOnly)?`<button class="btn text-[10px]" onclick="state.data.hooksFilter='';state.data.hooksEvent='';state.data.hooksScope='all';state.data.hooksRiskOnly=false;renderView();">✕ ${t('필터 초기화')}</button>`:''}
        <span class="text-[10px] text-[var(--text-dim)]">${totalShown}/${totalAll} ${t('표시')}</span>
      </div>
      <div class="flex items-center gap-1 flex-wrap">
        <span class="text-[10px] text-[var(--text-dim)] mr-1">${t('이벤트')}:</span>
        ${orderedEvents.map(eventChip).join('')}
      </div>
    </div>

    ${totalShown ? orderedEvents.map(ev => {
      const userGroup = userFiltered.filter(h => h.event === ev);
      const pluginGroup = pluginFiltered.filter(h => h.event === ev);
      if (!userGroup.length && !pluginGroup.length) return '';
      return `
      <div class="card p-4 mb-3">
        <div class="flex items-center justify-between mb-3">
          <div class="font-semibold text-sm flex items-center gap-2">
            <span class="chip chip-accent">${escapeHtml(ev)}</span>
            <span class="text-[var(--text-mute)]">전역 ${userGroup.length} · 플러그인 ${pluginGroup.length}</span>
          </div>
        </div>
        <div class="space-y-2">
          ${userGroup.map(h => _decorateRisk(renderUserCard(h), h)).join('')}
          ${pluginGroup.map(h => _decorateRisk(renderPluginCard(h), h)).join('')}
        </div>
      </div>`;
    }).join('') : (totalAll
      ? `<div class="card empty">${t('필터에 매치되는 훅 없음')} — <button class="btn text-[10px]" onclick="state.data.hooksFilter='';state.data.hooksEvent='';state.data.hooksScope='all';state.data.hooksRiskOnly=false;renderView();">${t('필터 초기화')}</button></div>`
      : `<div class="card empty">훅이 설정되지 않았습니다. 우측 상단 <b>＋ 새 훅 추가</b> 를 눌러 추가하세요.</div>`)}
  `;
};

// v2.42.3 — extracted from VIEWS.hooks template literal so the lazy
// recent-blocks fetcher can re-render only this panel without rebuilding
// the rest of the page. Returns '' when there are no events to render.
function _renderRecentBlocksPanel(data) {
  const items = (data && data.items) || [];
  if (!items.length) return '';
  return `
    <div class="card p-3 mb-3" style="background:rgba(239,68,68,0.05); border-color:rgba(239,68,68,0.3);">
      <div class="flex items-center justify-between mb-2">
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)] flex items-center gap-2">
          <span>🚨</span> <span>${t('최근 차단된 훅')}</span>
          <span class="text-[10px]" style="text-transform:none;letter-spacing:0;color:#fca5a5;">${data.totalEvents} ${t('차단 이벤트')} · ${data.scanned} ${t('파일 스캔')}</span>
        </div>
        <span class="text-[10px] text-[var(--text-dim)]">${t('카드를 클릭하면 검색 자동 적용')}</span>
      </div>
      <div class="grid gap-2" style="grid-template-columns:repeat(auto-fill, minmax(280px, 1fr));">
        ${items.map(rb => {
          const dt = rb.lastSeen ? new Date(rb.lastSeen).toLocaleString() : '—';
          return `<button class="rounded-lg p-2 text-left text-xs hover-lift" style="background:rgba(0,0,0,0.2); border:1px solid rgba(239,68,68,0.25); cursor:pointer;"
            data-hook-id="${escapeHtml(rb.id)}"
            onclick="_jumpToHookCard(this.dataset.hookId)">
            <div class="flex items-center justify-between gap-2 mb-1">
              <span class="font-semibold text-[#fca5a5]" style="font-size:0.92rem;">${rb.count}×</span>
              <span class="text-[10px] text-[var(--text-dim)]">${escapeHtml(dt)}</span>
            </div>
            <div class="mono truncate" style="font-size:0.78rem;color:var(--text);">${escapeHtml(rb.id)}</div>
          </button>`;
        }).join('')}
      </div>
    </div>`;
}

AFTER.hooks = () => {
  const inp = document.getElementById('hookSearch');
  if (inp) {
    let d;
    inp.addEventListener('input', e => {
      clearTimeout(d);
      d = setTimeout(() => { state.data.hooksFilter = e.target.value; renderView(); }, 180);
    });
  }
  const ro = document.getElementById('hooksRiskOnly');
  if (ro) ro.onchange = e => { state.data.hooksRiskOnly = e.target.checked; renderView(); };

  // v2.42.3 — lazy-fetch Recent Blocks once per page session. The scan reads
  // ~90 MB of jsonl, so doing it inline blocks first paint by ~1 s. Fire
  // after AFTER.hooks runs and inject into the host div when it returns.
  if (!__hooksRecentBlocks && !__hooksRecentBlocksFetching) {
    __hooksRecentBlocksFetching = true;
    api('/api/hooks/recent-blocks')
      .catch(() => ({items: [], totalEvents: 0, scanned: 0}))
      .then(data => {
        __hooksRecentBlocks = data || {items: [], totalEvents: 0, scanned: 0};
        __hooksRecentBlocksFetching = false;
        const host = document.getElementById('hooksRecentBlocksHost');
        if (host) host.innerHTML = _renderRecentBlocksPanel(__hooksRecentBlocks);
      });
  }

  // v2.40.4 — Detective: paste a block error → extract hook id → search + pulse.
  const det = document.getElementById('hookDetectiveInput');
  const detRes = document.getElementById('hookDetectiveResult');
  if (det) {
    const detect = (txt) => {
      if (!txt || !txt.trim()) {
        if (detRes) detRes.textContent = '';
        return;
      }
      const m = txt.match(/\b(?:pre|post|session|notification|user|stop|sub):[a-z][a-z0-9_-]*(?::[a-z][a-z0-9_-]*)+/g);
      if (!m || !m.length) {
        if (detRes) detRes.innerHTML = `<span style="color:#fca5a5;">${t('hook id 패턴을 찾지 못했습니다')}</span>`;
        return;
      }
      const ids = [...new Set(m)];
      if (detRes) detRes.innerHTML = ids.map(id =>
        `<button class="chip text-[10px] cursor-pointer" style="background:rgba(59,130,246,0.2);color:#93c5fd;margin-right:4px;"
          data-hook-id="${escapeHtml(id)}" onclick="_jumpToHookCard(this.dataset.hookId)">${escapeHtml(id)} ▶</button>`
      ).join('') + `<span class="ml-2 text-[10px]" style="color:var(--text-dim);">${t('클릭하면 해당 훅 카드로 이동')}</span>`;
    };
    det.addEventListener('input', e => detect(e.target.value));
    det.addEventListener('paste', () => setTimeout(() => detect(det.value), 0));
  }
};

// v2.40.5 — single entry point for "click a hook id chip → land on its card".
// Used by both the Recent Blocks panel and the Detective result chips. The
// previous inline `onclick="state.data.hooksFilter=...;renderView();..."`
// emitted double-quotes from JSON.stringify which collided with the
// attribute quoting, so the parser cut the handler short and clicks did
// nothing. Wrapping the logic here also gives us one place to extend.
function _jumpToHookCard(id) {
  if (!id) return;
  state.data.hooksFilter = String(id);
  // Clear other filters so the searched id is the sole result and pulse
  // targets the right (single) card.
  state.data.hooksScope = 'all';
  state.data.hooksEvent = '';
  state.data.hooksRiskOnly = false;
  renderView();
  setTimeout(_pulseHookCard, 200);
}

// v2.40.4 — pulse-highlight the (single) filtered hook card so the user
// sees exactly which entry was matched, even amid scroll.
function _pulseHookCard() {
  const cards = document.querySelectorAll('.card .rounded-lg');
  if (cards.length !== 1) return;
  const c = cards[0];
  c.scrollIntoView({behavior:'smooth', block:'center'});
  c.style.transition = 'box-shadow 0.3s';
  const original = c.style.boxShadow;
  let pulses = 0;
  const t = setInterval(() => {
    c.style.boxShadow = (pulses % 2 === 0) ? '0 0 0 4px rgba(59,130,246,0.55)' : '0 0 0 2px rgba(59,130,246,0.0)';
    pulses++;
    if (pulses >= 6) { clearInterval(t); c.style.boxShadow = original; }
  }, 280);
}

// v2.40.4 — decode `node -e "..."` wrapper into the dispatcher chain Claude
// Code actually invokes. The wrapper resolves CLAUDE_PLUGIN_ROOT, then either
// requires a bootstrap script or spawns `node <runner.js> <id> <handler.js>
// <flags>`. We pull out the visible trailing `node ...` invocation since
// that's the layer that carries the hook id + handler path.
function _decodeHookCommand(cmd) {
  if (!cmd || typeof cmd !== 'string') return null;
  const out = { runner: '', hookId: '', handler: '', flags: '', rawTail: '' };
  // Look for the trailing chain — flexible because plugin authors compose it
  // differently. The shape we see in practice: "...require(s)\" node <runner>
  // <hookId> <handler> <flags>".
  const m = cmd.match(/(?:require\(s\)["']?\s*)?node\s+(\S+)\s+([a-z]+(?::[a-z][a-z0-9_-]*)+)\s+(\S+)(?:\s+([^"]*))?/);
  if (m) {
    out.runner  = m[1];
    out.hookId  = m[2];
    out.handler = m[3];
    out.flags   = (m[4] || '').trim();
    out.rawTail = m[0];
  }
  // Standalone hook id anywhere in the command (fallback for shell-only entries).
  if (!out.hookId) {
    const idM = cmd.match(/\b(?:pre|post|session|notification|user|stop|sub):[a-z][a-z0-9_-]*(?::[a-z][a-z0-9_-]*)+/);
    if (idM) out.hookId = idM[0];
  }
  return out;
}

// v2.40.4 — open a modal that shows the dispatcher chain + full command.
