// AI Providers 뷰 렌더 후 비용 차트 초기화
AFTER.aiProviders = () => {
  // 모든 초기화를 병렬 실행 (await 블로킹 제거 → 체감 속도 대폭 개선)
  Promise.allSettled([
    window.initCostCharts(),
    _aiRefreshHealth(),
    _loadUsageAlertStatus(),
    _ollamaServeCheckStatus(),
    _ollamaLoadSettings(),
    _ollamaLoadCatalog(),
    _ollamaLoadInstalled(),
  ]).catch(() => {});
};

// 프로바이더 헬스 체크
async function _aiRefreshHealth() {
  const host = document.getElementById('aiHealthIndicators');
  const summary = document.getElementById('aiHealthSummary');
  if (!host) return;
  host.innerHTML = `<span class="text-xs" style="color:var(--text-dim)">${t('로딩 중...')}</span>`;
  try {
    const d = await cachedApi('/api/ai-providers/health');
    const items = d.results || d.providers || d.health || [];
    if (!items.length) {
      host.innerHTML = `<span class="text-xs" style="color:var(--text-dim)">${t('프로바이더 없음')}</span>`;
      if (summary) summary.textContent = '';
      return;
    }
    // ollama + ollama-api 는 같은 서버이므로 하나로 합침
    const merged = [];
    const seenOllama = { local: false, api: false };
    for (const p of items) {
      const pid = p.provider || p.id || '';
      if (pid === 'ollama-api') { seenOllama.api = true; continue; } // ollama 로컬이 대표
      if (pid === 'ollama') seenOllama.local = true;
      merged.push(p);
    }
    host.innerHTML = merged.map(p => {
      const ok = p.available || p.status === 'available';
      const dotColor = ok ? 'var(--ok)' : 'var(--err)';
      const icon = p.icon || '🔌';
      const pid = p.provider || p.id || '';
      const name = escapeHtml(p.name || pid);
      const chipCls = ok ? 'chip chip-ok' : 'chip chip-err';
      const ep = p.endpoint || '';
      const ptype = p.type || '';
      // endpoint 표시 로직
      let epHtml = '';
      if (ok) {
        if (ptype === 'cli' && ep.includes('/')) {
          // CLI: 짧은 경로만 (마지막 부분)
          epHtml = `<span class="text-[9px]" style="color:var(--cyan);font-family:monospace">CLI ✓</span>`;
        } else if (ep.startsWith('http')) {
          const epShort = ep.replace('https://','').replace('http://','');
          epHtml = `<span class="text-[9px]" style="color:var(--cyan);font-family:monospace">${escapeHtml(epShort)}</span>`;
        }
      }
      return `<div class="flex items-center gap-1.5" title="${escapeHtml(ep||pid)}">
        <span style="display:inline-block;width:10px;height:10px;border-radius:50%;background:${dotColor};flex-shrink:0;"></span>
        <span class="text-sm">${icon}</span>
        <span class="${chipCls} text-[11px]">${name}</span>
        ${epHtml}
      </div>`;
    }).join('');
    // 헬스 카운트도 merged 기준으로 재계산
    const mergedAvail = merged.filter(p => p.available || p.status === 'available');
    if (summary) summary.textContent = `${mergedAvail.length}/${merged.length} ${t('프로바이더 사용 가능')}`;
  } catch (e) {
    // health 엔드포인트가 없으면 기존 리스트 데이터로 폴백
    const cached = state.data._aiProviders;
    if (cached && cached.providers) {
      const items = cached.providers;
      const avail = items.filter(p => p.available);
      if (summary) summary.textContent = `${avail.length}/${items.length} ${t('프로바이더 사용 가능')}`;
      host.innerHTML = items.map(p => {
        const ok = p.available;
        const dotColor = ok ? 'var(--ok)' : 'var(--err)';
        const icon = p.icon || '🔌';
        const name = escapeHtml(p.name || p.id || '');
        const chipCls = ok ? 'chip chip-ok' : 'chip chip-err';
        return `<div class="flex items-center gap-1.5">
          <span style="display:inline-block;width:10px;height:10px;border-radius:50%;background:${dotColor};flex-shrink:0;"></span>
          <span class="text-sm">${icon}</span>
          <span class="${chipCls} text-[11px]">${name}</span>
        </div>`;
      }).join('');
    } else {
      host.innerHTML = `<span class="text-xs" style="color:var(--err)">${t('헬스 체크 실패')}</span>`;
      if (summary) summary.textContent = '';
    }
  }
}

// 사용량 알림 설정
async function _saveUsageAlert() {
  const maxCostEl = document.getElementById('usageAlertMaxCost');
  const maxTokensEl = document.getElementById('usageAlertMaxTokens');
  const maxDailyCostUsd = parseFloat(maxCostEl?.value) || 0;
  const maxDailyTokens = parseInt(maxTokensEl?.value) || 0;
  if (maxDailyCostUsd <= 0 && maxDailyTokens <= 0) {
    toast(t('한도를 하나 이상 입력하세요'), 'warn');
    return;
  }
  try {
    await api('/api/ai-providers/usage-alert/set', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ maxDailyCostUsd, maxDailyTokens })
    });
    toast(t('사용량 알림 설정이 저장되었습니다'), 'ok');
    _loadUsageAlertStatus();
  } catch (e) {
    toast(t('사용량 알림 저장 실패') + ': ' + (e.message || e), 'err');
  }
}

async function _loadUsageAlertStatus() {
  const banner = document.getElementById('usageAlertBanner');
  const costInput = document.getElementById('usageAlertMaxCost');
  const tokensInput = document.getElementById('usageAlertMaxTokens');
  if (!banner) return;
  try {
    const d = await api('/api/ai-providers/usage-alert');
    if (costInput && d.maxDailyCostUsd) costInput.value = d.maxDailyCostUsd;
    if (tokensInput && d.maxDailyTokens) tokensInput.value = d.maxDailyTokens;
    const fired = d.firedAlerts || [];
    if (fired.length > 0) {
      // Task 3: 사용량 초과 시 브라우저 Notification 발송
      fired.forEach(a => {
        const msg = a.type === 'cost' ? t('비용 한도 초과') : t('토큰 한도 초과');
        if (typeof _sendBrowserNotification === 'function') {
          _sendBrowserNotification(t('사용량 알림'), msg + ': ' + (a.message || ''));
        }
      });
      banner.innerHTML = `
        <div class="mb-4 p-3 rounded" style="background:rgba(248,113,113,0.1);border:1px solid rgba(248,113,113,0.3);">
          <div class="flex items-center gap-2 mb-1">
            <span style="font-size:1.1rem;">⚠️</span>
            <span class="text-sm font-semibold" style="color:var(--err)">${t('사용량 알림 발생')}</span>
          </div>
          ${fired.map(a => `
            <div class="text-xs mt-1" style="color:var(--text-mute)">
              ${escapeHtml(a.type === 'cost' ? t('비용 한도 초과') : t('토큰 한도 초과'))}: ${escapeHtml(a.message || '')}
              <span style="color:var(--text-dim)"> — ${escapeHtml(a.timestamp || '')}</span>
            </div>
          `).join('')}
        </div>`;
    } else if (d.maxDailyCostUsd || d.maxDailyTokens) {
      banner.innerHTML = `
        <div class="mb-4 p-2 rounded text-[11px]" style="background:rgba(74,222,128,0.08);border:1px solid rgba(74,222,128,0.2);color:var(--ok);">
          ✅ ${t('알림 활성')} — ${d.maxDailyCostUsd ? t('비용 한도') + ': $' + d.maxDailyCostUsd : ''} ${d.maxDailyTokens ? t('토큰 한도') + ': ' + Number(d.maxDailyTokens).toLocaleString() : ''}
        </div>`;
    } else {
      banner.innerHTML = '';
    }
  } catch (e) {
    banner.innerHTML = '';
  }
}

