window._wizardSaveApiKey = async (providerId) => {
  const inp = document.getElementById('wizardApiKey');
  if (!inp || !inp.value.trim()) { toast(t('API 키를 입력하세요'), 'warn'); return; }
  const r = await api('/api/ai-providers/save-key', {
    method: 'POST', body: JSON.stringify({ providerId, apiKey: inp.value.trim() }),
  });
  if (r.ok) {
    toast(t('API 키 저장 완료'), 'ok');
    inp.value = '';
    inp.placeholder = t('저장됨') + ' ✓';
    inp.disabled = true;
  } else {
    toast(errMsg(r), 'err');
  }
};

window._wizardTestConnection = async () => {
  const result = document.getElementById('wizardTestResult');
  if (!result) return;

  const providerMap = { claude: 'claude-cli', openai: 'openai-api', gemini: 'gemini-api', ollama: 'ollama' };
  const pid = providerMap[__wizardSelectedProvider] || __wizardSelectedProvider;
  if (!pid) { toast(t('프로바이더를 먼저 선택하세요'), 'warn'); return; }

  result.innerHTML = `<span style="color:var(--text-dim)">${t('테스트 중...')}</span>`;
  try {
    const r = await api('/api/ai-providers/test', { method: 'POST', body: JSON.stringify({ providerId: pid }) });
    if (r.ok) {
      const resp = r.response || {};
      const outPreview = (resp.output || '').substring(0, 80);
      result.innerHTML = `<span style="color:var(--ok)">✓ ${t('성공')} (${resp.duration_ms || 0}ms)${outPreview ? ' — ' + escapeHtml(outPreview) : ''}</span>`;
    } else {
      const errTxt = r.error || (r.response||{}).error || t('실패');
      result.innerHTML = `<span style="color:var(--err)">✗ ${escapeHtml(errTxt)}</span>`;
    }
  } catch (e) {
    const msg = String(e);
    // 서버 재시작이 필요한 신규 라우트 누락 케이스 친절하게 안내
    const hint = /unknown route|404/.test(msg)
      ? ' — ' + t('대시보드 서버를 재시작하면 최신 기능이 적용됩니다')
      : '';
    result.innerHTML = `<span style="color:var(--err)">✗ ${escapeHtml(msg)}${hint}</span>`;
  }
};

window._wizardDismiss = (checked) => {
  if (checked) {
    localStorage.setItem('providerWizardDismissed', '1');
  } else {
    localStorage.removeItem('providerWizardDismissed');
  }
};

window._cliInstall = async (toolId) => {
  const confirmed = await confirmModal({
    title: t('CLI 설치'),
    message: t('터미널 창이 열리고 설치 명령이 실행됩니다. 계속할까요?'),
    confirmLabel: t('설치 시작'),
  });
  if (!confirmed) return;
  try {
    const r = await api('/api/cli/install', { method: 'POST', body: JSON.stringify({ tool: toolId }) });
    if (r.ok) {
      if (r.alreadyInstalled) {
        toast(t('이미 설치되어 있습니다'), 'ok');
      } else {
        toast(t('터미널에서 설치가 진행 중입니다. 완료 후 새로고침하세요.'), 'ok');
      }
      // 10초마다 상태 재확인 (완료 시 자동 UI 갱신)
      let tries = 0;
      const poll = setInterval(async () => {
        // v2.46.0 perf — pause while tab is hidden so we don't burn the
        // 30-try budget on background polls the user can't see finish.
        if (document.hidden) return;
        tries += 1;
        try {
          const s = await api('/api/cli/status');
          if (s && s.tools && s.tools[toolId] && s.tools[toolId].installed) {
            clearInterval(poll);
            toast(t('설치가 감지되었습니다 — 새로고침합니다'), 'ok');
            if (state.view === 'aiProviders') renderView();
          } else if (tries >= 30) { // 5분 후 중단
            clearInterval(poll);
          }
        } catch {}
      }, 10000);
    } else {
      toast(errMsg(r) || t('설치 실패'), 'err');
    }
  } catch (e) { toast(String(e), 'err'); }
};

window._cliLogin = async (toolId) => {
  try {
    const r = await api('/api/cli/login', { method: 'POST', body: JSON.stringify({ tool: toolId }) });
    if (r.ok) {
      if (r.noLoginRequired) {
        toast(t('이 도구는 로그인이 필요하지 않습니다'), 'ok');
      } else {
        toast(t('터미널에서 로그인 창이 열렸습니다'), 'ok');
      }
    } else {
      toast(errMsg(r) || t('로그인 실패'), 'err');
    }
  } catch (e) { toast(String(e), 'err'); }
};

window.testProvider = async (pid) => {
  const el = document.getElementById('testResult-' + pid);
  if (el) el.innerHTML = '<span class="text-xs" style="color:var(--text-dim)">테스트 중...</span>';
  try {
    const r = await api('/api/ai-providers/test', { method: 'POST', body: JSON.stringify({ providerId: pid }) });
    if (r.ok) {
      const resp = r.response || {};
      el.innerHTML = `<div class="text-xs" style="color:var(--ok)">✓ 성공 (${resp.duration_ms || 0}ms) — ${escapeHtml((resp.output || '').substring(0, 100))}</div>`;
    } else {
      el.innerHTML = `<div class="text-xs" style="color:var(--err)">✗ ${escapeHtml(r.error || (r.response||{}).error || '실패')}</div>`;
    }
  } catch (e) { if (el) el.innerHTML = `<div class="text-xs" style="color:var(--err)">✗ ${escapeHtml(String(e))}</div>`; }
};

window._saveFallbackChain = async () => {
  const cbs = document.querySelectorAll('.fallback-chain-cb:checked');
  const chain = Array.from(cbs).map(cb => cb.value);
  const msgEl = document.getElementById('fallbackChainMsg');
  try {
    const r = await api('/api/ai-providers/fallback-chain', {
      method: 'POST', body: JSON.stringify({ chain }),
    });
    if (r.ok) {
      if (msgEl) msgEl.innerHTML = `<span style="color:var(--ok)">✓ ${t('저장됨')} (${chain.length}${t('개')})</span>`;
      toast(t('폴백 체인이 저장되었습니다'), 'ok');
    } else {
      if (msgEl) msgEl.innerHTML = `<span style="color:var(--err)">✗ ${errMsg(r)}</span>`;
    }
  } catch(e) {
    if (msgEl) msgEl.innerHTML = `<span style="color:var(--err)">✗ ${escapeHtml(String(e))}</span>`;
  }
};

window.saveApiKey = async (pid) => {
  const inp = document.getElementById('apiKey-' + pid);
  if (!inp) return;
  const val = inp.value.trim();
  if (!val || val === '••••••••') { toast(t('enter_api_key','API 키를 입력하세요'), 'warn'); return; }
  const r = await api('/api/ai-providers/save-key', { method: 'POST', body: JSON.stringify({ providerId: pid, apiKey: val }) });
  if (r.ok) { toast(t('api_key_saved','API 키 저장 완료'), 'ok'); renderView(); }
  else toast(errMsg(r), 'err');
};

