window._ollamaShowInfo = _ollamaShowInfo;

function _formatBytes(bytes) {
  if (!bytes || bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
}

// Cost chart instances now live in the shared _chartInstances Map.

window.__lastCostsData = null; // 비용 데이터 캐시 — 스택 바 차트에서 재사용
window.initCostCharts = async () => {
  try {
    const d = await cachedApi('/api/ai-providers/costs', 20000);
    if (!d || !d.ok) return;
    window.__lastCostsData = d; // 캐시 저장
    const costs = d.costs || {};
    const daily = costs.daily || [];        // [{date, cost, tokens, calls}]
    const byProvider = costs.byProvider || []; // [{provider, cost, tokens, calls}]
    const totals = costs.totals || {};      // {totalCalls, totalTokens, totalCostUSD}

    // 요약 카드 업데이트
    const elCalls = document.getElementById('costTotalCalls');
    const elTokens = document.getElementById('costTotalTokens');
    const elUSD = document.getElementById('costTotalUSD');
    if (elCalls) elCalls.textContent = (totals.totalCalls || 0).toLocaleString();
    if (elTokens) elTokens.textContent = (totals.totalTokens || 0).toLocaleString();
    if (elUSD) elUSD.textContent = '$' + (totals.totalCostUSD || 0).toFixed(4);

    // 공통 Chart.js 색상
    const textColor = getComputedStyle(document.documentElement).getPropertyValue('--text-mute').trim() || '#a0a0a8';
    const gridColor = getComputedStyle(document.documentElement).getPropertyValue('--border').trim() || 'rgba(255,255,255,0.07)';

    // 일별 비용 타임라인 (라인 차트)
    const ctxTimeline = document.getElementById('costTimeline');
    if (ctxTimeline) {
      _renderChart(ctxTimeline, {
        type: 'line',
        data: {
          labels: daily.map(d => d.date),
          datasets: [{
            label: t('비용 (USD)'),
            data: daily.map(d => d.cost || 0),
            borderColor: '#d97757',
            backgroundColor: 'rgba(217,119,87,0.15)',
            fill: true,
            tension: 0.35,
            pointRadius: 3,
            pointBackgroundColor: '#d97757',
          }]
        },
        options: {
          responsive: true, maintainAspectRatio: false,
          plugins: {
            legend: { labels: { color: textColor, font: { size: 11 } } },
            tooltip: { callbacks: { label: ctx => '$' + (ctx.parsed.y || 0).toFixed(4) } },
          },
          scales: {
            x: { ticks: { color: textColor, font: { size: 10 } }, grid: { color: gridColor } },
            y: { ticks: { color: textColor, font: { size: 10 }, callback: v => '$' + v.toFixed(2) }, grid: { color: gridColor } },
          }
        }
      });
    }

    // 프로바이더별 비용 비교 (도넛 차트)
    const ctxProvider = document.getElementById('costByProvider');
    if (ctxProvider) {
      const providerColors = ['#d97757','#7dd3fc','#4ade80','#c084fc','#fbbf24','#f87171','#a78bfa','#38bdf8'];
      _renderChart(ctxProvider, {
        type: 'doughnut',
        data: {
          labels: byProvider.map(p => p.provider),
          datasets: [{
            data: byProvider.map(p => p.cost || 0),
            backgroundColor: byProvider.map((_, i) => providerColors[i % providerColors.length]),
            borderColor: 'transparent',
            borderWidth: 2,
          }]
        },
        options: {
          responsive: true, maintainAspectRatio: false,
          plugins: {
            legend: { position: 'right', labels: { color: textColor, font: { size: 11 }, padding: 12 } },
            tooltip: { callbacks: { label: ctx => ctx.label + ': $' + (ctx.parsed || 0).toFixed(4) } },
          }
        }
      });
    }
  } catch(e) { /* 비용 API 미지원 시 조용히 무시 */ }
};

// ── 멀티 AI 비교 모드 ──
window.runMultiCompare = async () => {
  const prompt = (document.getElementById('multiComparePrompt')?.value || '').trim();
  if (!prompt) { toast(t('프롬프트를 입력하세요'), 'warn'); return; }
  const cbs = document.querySelectorAll('.multi-compare-cb:checked');
  const selectedIds = Array.from(cbs).map(cb => cb.value);
  if (!selectedIds.length) { toast(t('프로바이더를 선택하세요'), 'warn'); return; }

  const resultsEl = document.getElementById('multiCompareResults');
  if (!resultsEl) return;
  resultsEl.innerHTML = `<div class="text-sm" style="color:var(--text-dim)">${t('비교 실행 중...')} (${selectedIds.length} ${t('프로바이더')})</div>`;

  // 모든 프로바이더에 동시에 요청
  const promises = selectedIds.map(async (pid) => {
    const start = Date.now();
    try {
      const r = await api('/api/ai-providers/test', {
        method: 'POST',
        body: JSON.stringify({ providerId: pid, prompt }),
      });
      const elapsed = Date.now() - start;
      const resp = r.response || {};
      return {
        providerId: pid,
        ok: !!r.ok,
        output: resp.output || r.error || t('응답 없음'),
        duration: resp.duration_ms || elapsed,
        tokens: resp.tokens || 0,
        error: r.ok ? null : (r.error || resp.error || t('실패')),
      };
    } catch(e) {
      return { providerId: pid, ok: false, output: '', duration: Date.now() - start, tokens: 0, error: String(e) };
    }
  });

  const results = await Promise.allSettled(promises);
  const providers = (state.data._aiProviders?.providers) || [];

  const cards = results.map(r => {
    const v = r.status === 'fulfilled' ? r.value : { providerId: '?', ok: false, output: '', duration: 0, tokens: 0, error: t('요청 실패') };
    const p = providers.find(x => x.id === v.providerId) || {};
    const statusChip = v.ok
      ? '<span class="chip chip-ok text-xs">' + t('성공') + '</span>'
      : '<span class="chip chip-err text-xs">' + t('실패') + '</span>';
    return `
      <div class="card p-4 flex-1 min-w-[260px]">
        <div class="flex items-center justify-between mb-2">
          <div class="flex items-center gap-2">
            <span class="text-lg">${p.icon || '🔌'}</span>
            <span class="font-semibold text-sm" style="color:var(--text)">${escapeHtml(p.name || v.providerId)}</span>
          </div>
          ${statusChip}
        </div>
        <div class="flex gap-3 mb-2">
          <span class="chip text-xs">${v.duration}ms</span>
          <span class="chip text-xs">${(v.tokens || 0).toLocaleString()} ${t('토큰')}</span>
        </div>
        ${v.error ? `<div class="text-xs mb-2" style="color:var(--err)">${escapeHtml(v.error)}</div>` : ''}
        <pre class="text-xs whitespace-pre-wrap break-words" style="max-height:200px;overflow-y:auto;color:var(--text-mute);background:var(--code-bg);padding:8px;border-radius:8px;">${escapeHtml((v.output || '').substring(0, 2000))}</pre>
      </div>`;
  }).join('');

  resultsEl.innerHTML = `<div class="flex flex-wrap gap-4">${cards}</div>`;
};

