function editOutputStyle(existing) {
  const e = existing || { id: '', name: '', description: '', raw: '---\nname: my-style\ndescription: 한 줄 설명\n---\n\n## 톤\n- 항상 한국어로 답한다.\n- 불필요한 감탄사 생략.\n\n## 포맷\n- 긴 답변은 섹션 헤더 사용.\n' };
  const isEdit = !!existing;
  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <h2 class="font-semibold">${isEdit ? '출력 스타일 편집' : '새 출력 스타일'}</h2>
      <button class="btn-ghost btn" onclick="closeModal()">✕</button>
    </div>
    <div class="p-5 space-y-3">
      ${isEdit ? '' : `<div>
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">이름 (파일명, 소문자-하이픈)</div>
        <input id="osId" class="input" placeholder="예: terse-korean" />
      </div>`}
      <div>
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">스타일 본문 (frontmatter + 지침)</div>
        <textarea id="osRaw" class="input" style="min-height:420px;">${escapeHtml(e.raw)}</textarea>
      </div>
    </div>
    <div class="p-4 border-t border-[var(--border)] flex justify-end gap-2">
      <button class="btn" onclick="closeModal()">취소</button>
      <button class="btn-primary btn" id="osSaveBtn">저장</button>
    </div>
  `);
  document.getElementById('osSaveBtn').onclick = async () => {
    const id = isEdit ? e.id : document.getElementById('osId').value.trim();
    const raw = document.getElementById('osRaw').value;
    if (!id) { toast('이름 입력', 'warn'); return; }
    const r = await api('/api/output-styles/save', {
      method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ id, raw }),
    });
    if (r.ok) { toast('저장됨', 'ok'); closeModal(); renderView(); }
    else toast(errMsg(r), 'err');
  };
}

async function deleteOutputStyle(id) {
  const ok = await confirmModal({
    title: t('출력 스타일 삭제'),
    message: `'${id}' ` + t('출력 스타일을 삭제할까요?'),
    confirmLabel: t('삭제'), danger: true,
  });
  if (!ok) return;
  const r = await api('/api/output-styles/delete', {
    method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ id }),
  });
  if (r.ok) { toast('삭제됨', 'ok'); renderView(); } else toast(errMsg(r), 'err');
}

