AFTER.metrics = () => {
  const d = state.data.metrics;
  const ctx = document.getElementById('metricsDaily');
  if (!ctx || !d?.timeline) return;
  _renderChart(ctx, {
    type: 'line',
    data: {
      labels: d.timeline.map(x => x.date.slice(5)),
      datasets: [
        { label: '입력', data: d.timeline.map(x=>x.in), borderColor: '#86efac', backgroundColor: 'rgba(134,239,172,0.1)', fill: true, tension: 0.4, yAxisID: 'y' },
        { label: '출력', data: d.timeline.map(x=>x.out), borderColor: '#7dd3fc', backgroundColor: 'rgba(125,211,252,0.1)', fill: true, tension: 0.4, yAxisID: 'y' },
        { label: '캐시 read', data: d.timeline.map(x=>x.cacheRead||0), borderColor: '#a78bfa', tension: 0.4, yAxisID: 'y' },
        { label: '전체', data: d.timeline.map(x=>x.total||0), borderColor: '#d97757', tension: 0.4, yAxisID: 'y', borderWidth: 2 },
        { label: '비용 ($)', data: d.timeline.map(x=>x.cost), borderColor: '#4ade80', tension: 0.4, yAxisID: 'y1', borderDash: [4,3] },
      ],
    },
    options: { responsive: true, maintainAspectRatio: false,
      plugins: {
        legend: { labels: { color: '#e7e7ea' } },
        tooltip: { callbacks: { label: c => {
          const l = c.dataset.label;
          if (l === '비용 ($)') return `${l}: $${c.parsed.y.toFixed(2)}`;
          return `${l}: ${fmtTokens(c.parsed.y)}`;
        }}},
      },
      scales: {
        x: { ticks: { color: document.body.classList.contains('theme-light') ? '#666' : '#9aa0aa' }, grid: { color: document.body.classList.contains('theme-light') ? 'rgba(0,0,0,0.08)' : 'rgba(255,255,255,0.05)' } },
        y: { position: 'left', ticks: { color: document.body.classList.contains('theme-light') ? '#666' : '#9aa0aa', callback: v => fmtTokens(v) }, grid: { color: document.body.classList.contains('theme-light') ? 'rgba(0,0,0,0.08)' : 'rgba(255,255,255,0.05)' }, beginAtZero: true },
        y1: { position: 'right', ticks: { color: document.body.classList.contains('theme-light') ? '#666' : '#9aa0aa' }, grid: { display: false }, beginAtZero: true },
      },
    },
  });
};

// ────────────────────────────────────────────────────────────────
// BACKUPS / FILE HISTORY / SHELL SNAPSHOTS
// ────────────────────────────────────────────────────────────────
// v2.33.8 — backups 탭: 2개 파일 선택 → unified diff 모달
state.data._bkSel = state.data._bkSel || [];
function _bkToggleSel(path) {
  const arr = state.data._bkSel;
  const idx = arr.indexOf(path);
  if (idx >= 0) arr.splice(idx, 1);
  else { arr.push(path); if (arr.length > 2) arr.shift(); }
  renderView();
  if (arr.length === 2) _bkShowDiff(arr[0], arr[1]);
}
async function _bkShowDiff(a, b) {
  showModalLoading(t('diff 계산 중…'));
  try {
    const qs = new URLSearchParams({ a, b });
    const r = await api('/api/backups/diff?' + qs);
    if (!r.ok) { closeModal(); toast(r.error || 'diff failed', 'err'); return; }
    const esc = (s) => s.replace(/[&<>]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;'}[c]));
    const colored = r.diff.split('\n').map(line => {
      let color = 'var(--text-mute)';
      if (line.startsWith('+++') || line.startsWith('---')) color = '#7dd3fc';
      else if (line.startsWith('@@')) color = '#c4b5fd';
      else if (line.startsWith('+')) color = '#4ade80';
      else if (line.startsWith('-')) color = '#f87171';
      return `<div style="color:${color}">${esc(line) || '&nbsp;'}</div>`;
    }).join('');
    showModal(`
      <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
        <div>
          <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">${t('파일 비교')}</div>
          <h2 class="text-lg font-bold">🔀 ${t('유니파이드 diff')}</h2>
          <div class="text-[11px] text-[var(--text-mute)] mt-1">
            <span class="text-[#4ade80]">+${r.added}</span>
            · <span class="text-[#f87171]">-${r.removed}</span>
            · ${formatBytes(r.aSize)} → ${formatBytes(r.bSize)}
          </div>
        </div>
        <button class="btn-ghost btn" onclick="closeModal(); state.data._bkSel=[]; renderView();">✕</button>
      </div>
      <pre class="mono text-[11px] p-5" style="max-height:65vh; overflow:auto; white-space:pre; background:var(--code-bg);">${colored}</pre>
    `);
  } catch (e) { closeModal(); toast(String(e), 'err'); }
}

VIEWS.backups = async () => {
  const d = await api('/api/backups/list');
  const sel = state.data._bkSel || [];
  const renderGroup = (title, hint, data, compareable) => `
    <div class="card p-5 mb-4">
      <div class="flex items-center justify-between mb-3">
        <div>
          <h3 class="font-semibold text-sm">${title}</h3>
          <p class="text-[11px] text-[var(--text-mute)] mt-0.5">${hint}${compareable ? ` · <span class="text-[var(--accent)]">${t('파일 2개를 선택해 diff 비교')}</span>` : ''}</p>
        </div>
        <span class="chip">${data.items.length} / 전체 ${data.total||'—'}</span>
      </div>
      ${data.exists ? `
        <table class="data">
          <thead><tr>${compareable ? '<th></th>' : ''}<th>이름</th><th class="text-right">크기</th><th class="text-right">수정</th></tr></thead>
          <tbody>
            ${data.items.map(x => {
              const isPicked = sel.includes(x.path);
              const canPick = compareable && !x.isDir;
              return `
              <tr ${canPick ? `class="link-row" onclick="_bkToggleSel(${JSON.stringify(x.path).replace(/"/g,'&quot;')})"` : ''} style="${isPicked?'background:rgba(217,119,87,0.12);':''}">
                ${compareable ? `<td style="width:30px;">${canPick ? (isPicked ? '✓' : '○') : ''}</td>` : ''}
                <td class="mono text-xs truncate" style="max-width:420px;">${x.isDir?'📁 ':'📄 '}${escapeHtml(x.name)}</td>
                <td class="text-right text-xs">${formatBytes(x.size)}</td>
                <td class="text-right text-xs text-[var(--text-mute)]">${fmtRel(x.modifiedAt)}</td>
              </tr>`;
            }).join('') || `<tr><td colspan="${compareable?4:3}" class="empty text-xs">없음</td></tr>`}
          </tbody>
        </table>` : '<div class="empty text-xs">디렉토리 없음</div>'}
    </div>`;
  const selHint = sel.length
    ? `<div class="chip chip-accent mb-3">${t('선택됨')}: ${sel.length}/2 · <button class="btn-ghost text-[10px] ml-1" onclick="state.data._bkSel=[]; renderView();">✕</button></div>`
    : '';
  return `
    ${viewHeader('백업 / 파일 히스토리', 'Claude Code 가 자동 생성하는 복구/롤백 데이터', 'backups')}
    ${selHint}
    ${renderGroup('💾 Backups', '~/.claude/backups/ — 세션 자동 백업', d.backups, true)}
    ${renderGroup('📝 File History', '~/.claude/file-history/<sessionId>/ — 세션 중 파일 편집 이력', d.fileHistory, false)}
    ${renderGroup('🖥 Shell Snapshots', '~/.claude/shell-snapshots/ — Claude Code 가 덮어쓴 쉘 환경 스냅샷', d.shellSnapshots, true)}`;
};
function formatBytes(n) {
  if (!n) return '0';
  if (n < 1024) return n + 'B';
  if (n < 1024*1024) return (n/1024).toFixed(1) + 'KB';
  if (n < 1024*1024*1024) return (n/1024/1024).toFixed(2) + 'MB';
  return (n/1024/1024/1024).toFixed(2) + 'GB';
}

// ────────────────────────────────────────────────────────────────
// ARTIFACTS VIEWER (v2.33.0) — 워크플로우 출력물 4중 보안 미리보기
// ────────────────────────────────────────────────────────────────
VIEWS.artifacts = async () => {
  const d = await api('/api/artifacts/list');
  if (!d.ok) return `<div class="card p-6 text-[12px]">${t('데이터를 불러오지 못했습니다')}</div>`;
  const items = d.items || [];
  const selected = state.data._artRunId || '';
  const fmtMs = (ms) => ms ? new Date(ms).toLocaleString() : '-';

  const left = items.length ? items.map(it => `
    <div class="card p-2 mb-1 ${selected === it.runId ? 'border-[var(--accent)]' : ''}"
         style="border-width:1px;cursor:pointer;"
         onclick="_artSelect('${escapeHtml(it.runId)}')">
      <div class="text-[11px] font-semibold truncate">${escapeHtml(it.workflowName)}</div>
      <div class="text-[10px] font-mono" style="color:var(--text-dim)">${escapeHtml(it.runId.slice(-12))}</div>
      <div class="flex items-center gap-1 mt-1">
        <span class="chip text-[9px]">${escapeHtml(it.formatHint)}</span>
        <span class="chip text-[9px]" style="color:${it.status==='ok'?'var(--success)':'#fca5a5'}">${escapeHtml(it.status)}</span>
        <span class="text-[9px]" style="color:var(--text-dim);margin-left:auto;">${it.outputLen.toLocaleString()}B</span>
      </div>
      <div class="text-[9px]" style="color:var(--text-dim)">${fmtMs(it.finishedAt)}</div>
    </div>
  `).join('') : `<div class="text-[11px]" style="color:var(--text-dim)">${t('art_no_outputs', '출력물이 있는 run 이 없습니다.')}</div>`;

  return `
    ${viewHeader('🎨 Artifacts Viewer', t('art_subtitle', '워크플로우 출력물을 sandbox iframe + CSP + 정적 필터 4중 보안으로 안전하게 미리보기 — 스크립트 실행·외부 네트워크·쿠키 모두 차단.'), 'artifacts')}
    <div class="grid grid-cols-1 lg:grid-cols-[320px_1fr] gap-4">
      <div style="max-height:75vh;overflow-y:auto;">
        <div class="text-[10px] uppercase tracking-wider mb-1" style="color:var(--text-dim)">${t('art_recent', '최근 50 run')}</div>
        ${left}
      </div>
      <div id="artDetail" class="card p-4">
        ${selected ? `<div class="text-[11px]" style="color:var(--text-dim)">${t('로딩 중...')}</div>`
          : `<div class="text-[12px] text-center py-16" style="color:var(--text-dim)">
              ${t('art_pick', '왼쪽에서 run 을 선택하세요.')}<br>
              <div class="text-[10px] mt-3">🛡️ ${t('art_sec_hint', 'sandbox 속성 = "" (모든 권한 차단) + CSP default-src:none + 정적 필터 (script/iframe/on*/javascript: 제거).')}</div>
             </div>`
        }
      </div>
    </div>
  `;
};

function _artSelect(rid) {
  state.data._artRunId = rid;
  state.data._artFormat = 'auto';
  renderView();
  setTimeout(() => _artLoad(rid), 30);
}

async function _artLoad(rid) {
  const host = document.getElementById('artDetail');
  if (!host) return;
  const fmt = state.data._artFormat || 'auto';
  try {
    const r = await api(`/api/artifacts/render?runId=${encodeURIComponent(rid)}&format=${encodeURIComponent(fmt)}`);
    if (!r.ok) { host.innerHTML = `<div class="text-[12px]" style="color:var(--danger)">${escapeHtml(r.error||'error')}</div>`; return; }
    const formats = ['auto','html','svg','markdown','json','text'];
    const fmtTabs = formats.map(f => `
      <button class="btn text-[10px] ${(f===fmt||(f==='auto'&&fmt==='auto'))?'btn-primary':''}"
              onclick="_artSetFormat('${f}')">${f}</button>
    `).join(' ');
    // sandbox="" (빈 문자열) = 모든 권한 차단. srcdoc 은 서버 sanitize 완료.
    host.innerHTML = `
      <div class="flex items-center justify-between mb-2 gap-2 flex-wrap">
        <div class="text-[11px]">
          <span class="chip text-[10px]">📄 ${escapeHtml(r.format)}</span>
          <span class="text-[10px]" style="color:var(--text-dim);margin-left:6px;">${(r.rawLen||0).toLocaleString()} bytes</span>
        </div>
        <div class="flex gap-1">${fmtTabs}</div>
      </div>
      <iframe id="artFrame" sandbox="" style="width:100%;height:60vh;border:1px solid var(--border);border-radius:6px;background:#1a1a1a;"></iframe>
      <div class="text-[9px] mt-2" style="color:var(--text-dim)">
        🛡️ ${t('art_sandbox_note', 'iframe sandbox="" — 스크립트·폼·쿠키·탐색·플러그인 전부 차단. CSP default-src:none, img-src:data 만 허용.')}
      </div>
    `;
    // srcdoc 을 JS 로 할당해 HTML 파서가 속성 해석하는 과정을 피함
    const fr = document.getElementById('artFrame');
    if (fr) fr.srcdoc = r.srcdoc || '';
  } catch (e) {
    host.innerHTML = `<div class="text-[12px]" style="color:var(--danger)">${escapeHtml(String(e))}</div>`;
  }
}

function _artSetFormat(f) {
  state.data._artFormat = f;
  _artLoad(state.data._artRunId);
}

// ────────────────────────────────────────────────────────────────
// ORCHESTRATOR — Slack/Telegram → Claude planner → multi-agent dispatch
// ────────────────────────────────────────────────────────────────
VIEWS.orchestrator = async () => {
  const [cfgR, slkR, tgR, histR, provR] = await Promise.all([
    api('/api/orchestrator/config'),
    api('/api/slack/config'),
    api('/api/telegram/config'),
    api('/api/orchestrator/history?limit=20'),
    api('/api/ai-providers/list'),
  ]);
  if (!cfgR.ok) return `<div class="card p-6 text-[12px]">${t('데이터를 불러오지 못했습니다')}</div>`;
  const cfg = cfgR.config || {};
  const avail = (cfgR.availableProviders || []).join(', ') || '—';
  const bindings = cfg.bindings || [];
  const slackOk = slkR && slkR.configured;
  const tgOk    = tgR && tgR.configured;

  // W1 (v2.66.9) — picker-friendly assignee list. Build from
  // /api/ai-providers/list, restricted to *available* providers, and
  // grouped by provider in a single <select>. The full
  // ``provider:model`` string is the value (matches what
  // ``execute_with_assignee`` parses).
  const allProvs = (provR && provR.providers) || [];
  const availProvs = allProvs.filter(p => p.available && (p.models || []).length > 0);
  // Provider-alias short names so the option labels stay readable
  const _provAlias = {
    'claude-cli': 'claude',     'claude': 'claude',
    'anthropic-api': 'claude-api', 'openai-api': 'openai',
    'gemini-cli': 'gemini',     'gemini-api': 'gemini-api',
    'ollama': 'ollama',         'ollama-api': 'ollama-api',
    'codex': 'codex',           'groq-api': 'groq',
    'deepseek-api': 'deepseek',
  };
  // X3 (v2.66.10) — clean assignee-option builder. Skip embedding-only
  // models since the orchestrator's planner/sub-agent path is chat. Filter
  // out the 'embed' capability when present. Labels show the
  // provider-friendly name + context-window in k tokens.
  function _buildAssigneeOptions(selected) {
    if (!availProvs.length) {
      return `<option value="" disabled>${t('가용 프로바이더 없음 — AI 프로바이더 탭에서 키 설정')}</option>`;
    }
    return availProvs.map(p => {
      const alias = _provAlias[p.id] || p.id;
      // Drop pure-embedding models from the picker (chat-only context).
      const chatModels = (p.models || []).filter(m => {
        const caps = m.capabilities || [];
        return caps.length === 0 || caps.includes('chat');
      });
      if (!chatModels.length) return '';
      const opts = chatModels.map(m => {
        // Canonical assignee value is alias:<model-id>. The backend's
        // resolve_assignee normalises common Claude aliases (opus/sonnet/
        // haiku) but leaves arbitrary ids untouched, so passing the raw
        // model id is the safe default for every other provider.
        const value = `${alias}:${m.id}`;
        const ctx = m.contextWindow ? ` · ${Math.round(m.contextWindow / 1000)}k` : '';
        const note = m.note ? ` — ${m.note}` : '';
        const label = `${m.label || m.id}${ctx}${note}`;
        return `<option value="${escapeHtml(value)}" ${selected === value ? 'selected' : ''}>${escapeHtml(label)}</option>`;
      }).join('');
      return `<optgroup label="${escapeHtml(p.icon + ' ' + p.name)}">${opts}</optgroup>`;
    }).join('');
  }
  // For the multi-select we keep the existing CSV underneath but render
  // a chip picker on top. Toggling a chip updates the CSV state.

  const bindRows = bindings.length ? bindings.map((b, i) => `
    <tr class="text-[11px]">
      <td class="p-1 font-mono">${escapeHtml(b.kind)}</td>
      <td class="p-1 font-mono">${escapeHtml(b.channel || b.chat || '')}</td>
      <td class="p-1">${escapeHtml((b.assignees || []).join(', ') || '(defaults)')}</td>
      <td class="p-1">${escapeHtml(b.workflowId || '(ad-hoc)')}</td>
      <td class="p-1"><button class="chip text-[10px]" onclick="_orchUnbind('${escapeHtml(b.kind)}','${escapeHtml(b.channel || b.chat || '')}')">${t('삭제')}</button></td>
    </tr>
  `).join('') : `<tr><td colspan="5" class="p-2 text-[11px]" style="color:var(--text-dim);text-align:center;">${t('아직 바인딩 없음')}</td></tr>`;

  return `
    ${viewHeader('🎼 Orchestrator', t('orch_subtitle', 'Slack/Telegram 채널 멘션 → Claude 플래너 → 멀티 모델 병렬 분담 → 채널 회신. 에이전트 간 라이브 보고는 Agent Bus 탭/SSE 로 연결.'), 'orchestrator')}
    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="card p-4">
        <div class="text-[12px] font-semibold mb-2">${t('연결 상태')}</div>
        <div class="text-[11px] mb-1">Slack: <span class="chip text-[10px]" style="color:${slackOk?'var(--success)':'#fca5a5'}">${slackOk?'configured':'not set'}</span></div>
        <div class="text-[11px] mb-1">Telegram: <span class="chip text-[10px]" style="color:${tgOk?'var(--success)':'#fca5a5'}">${tgOk?'configured':'not set'}</span></div>
        <div class="text-[11px] mt-3" style="color:var(--text-dim)">${t('가용 프로바이더')}: ${escapeHtml(avail)}</div>
        <button class="chip text-[10px] mt-3" onclick="_orchStart()">${t('리스너 시작')}</button>
      </div>
      <div class="lc-card">
        <div class="lc-section-title">${t('기본 설정')}</div>
        <label class="text-[11px] block mb-3">
          <span class="lc-section-sub">${t('플래너')}</span>
          <select id="orchPlanner" class="input mt-1">
            ${_buildAssigneeOptions(cfg.plannerAssignee)}
          </select>
          <div class="text-[10px] mt-1" style="color:var(--text-dim)">${t('사용자 메시지를 단계별로 분해하는 모델')}</div>
        </label>
        <label class="text-[11px] block mb-3">
          <span class="lc-section-sub">${t('취합기')}</span>
          <select id="orchAggregator" class="input mt-1">
            ${_buildAssigneeOptions(cfg.aggregatorAssignee)}
          </select>
          <div class="text-[10px] mt-1" style="color:var(--text-dim)">${t('서브 에이전트 결과를 합쳐 채널 회신을 작성')}</div>
        </label>
        <div class="text-[11px] block mb-3">
          <span class="lc-section-sub">${t('기본 어사이니')}</span>
          <div id="orchAssigneeChips" class="flex flex-wrap gap-1 mt-1 mb-2 min-h-[28px] p-2" style="border:1px solid var(--border);border-radius:8px;background:rgba(255,255,255,0.02);">
            ${((cfg.defaultAssignees || []).map(a => `
              <span class="chip text-[10px]" style="cursor:pointer;background:rgba(167,139,250,0.18);border-color:rgba(167,139,250,0.4);" onclick="_orchToggleAssignee('${escapeHtml(a)}')">${escapeHtml(a)} ✕</span>
            `).join('') || `<span class="text-[10px]" style="color:var(--text-dim)">${t('아래 + 버튼으로 추가')}</span>`)}
          </div>
          <select id="orchAssigneePicker" class="input" onchange="if(this.value){_orchToggleAssignee(this.value);this.value='';}">
            <option value="">+ ${t('어사이니 추가')}</option>
            ${_buildAssigneeOptions('')}
          </select>
          <input id="orchDefaults" type="hidden" value="${escapeHtml((cfg.defaultAssignees || []).join(','))}">
          <div class="text-[10px] mt-1" style="color:var(--text-dim)">${t('플래너가 작업 분배 시 후보로 사용하는 모델 목록')}</div>
        </div>
        <label class="text-[11px] block mb-3">
          <span class="lc-section-sub">${t('동시 실행')}</span>
          <input id="orchParallel" type="number" min="1" max="16" class="input mt-1" style="width:80px;" value="${cfg.maxParallel || 4}">
        </label>
        <button class="btn text-xs" onclick="_orchSaveCfg()">${t('저장')}</button>
      </div>
      <div class="card p-4 lg:col-span-2">
        <div class="flex items-center justify-between mb-2">
          <div class="text-[12px] font-semibold">${t('바인딩')}</div>
          <button class="chip text-[10px]" onclick="_orchAddBinding()">+ ${t('바인딩 추가')}</button>
        </div>
        <table class="w-full text-left">
          <thead><tr class="text-[10px]" style="color:var(--text-dim)"><th class="p-1">kind</th><th class="p-1">channel/chat</th><th class="p-1">assignees</th><th class="p-1">workflow</th><th class="p-1"></th></tr></thead>
          <tbody>${bindRows}</tbody>
        </table>
      </div>
      <div class="card p-4 lg:col-span-2">
        <div class="text-[12px] font-semibold mb-2">${t('최근 디스패치')}</div>
        ${(() => {
          const runs = (histR && histR.runs) || [];
          if (!runs.length) return _emptyState(t('아직 디스패치 기록 없음'), '🎼');
          return `<table class="w-full text-left">
            <thead><tr class="text-[10px]" style="color:var(--text-dim)"><th class="p-1">ts</th><th class="p-1">kind</th><th class="p-1">via</th><th class="p-1">channel</th><th class="p-1">text</th><th class="p-1">final</th></tr></thead>
            <tbody>${runs.map(r => `
              <tr class="text-[11px]">
                <td class="p-1 font-mono">${new Date(r.ts).toLocaleTimeString()}</td>
                <td class="p-1">${escapeHtml(r.kind)}</td>
                <td class="p-1">${escapeHtml(r.via)}</td>
                <td class="p-1 font-mono">${escapeHtml((r.channel || '').slice(0, 16))}</td>
                <td class="p-1 truncate" style="max-width:280px;">${escapeHtml((r.text || '').slice(0, 80))}</td>
                <td class="p-1 truncate" style="max-width:380px;color:${r.ok?'var(--text)':'#fca5a5'};">${escapeHtml((r.final || r.error || '').slice(0, 120))}</td>
              </tr>`).join('')}</tbody>
          </table>`;
        })()}
      </div>
      <div class="card p-4 lg:col-span-2">
        <div class="text-[12px] font-semibold mb-2">${t('라이브 디스패치 테스트')}</div>
        <textarea id="orchTestText" rows="3" class="input text-xs" placeholder="${t('메시지를 입력해 ad-hoc 디스패치')}"></textarea>
        <details class="mt-2 text-[11px]">
          <summary style="cursor:pointer;color:var(--text-dim)">${t('이 호출만 모델 오버라이드')}</summary>
          <div class="grid grid-cols-3 gap-2 mt-2">
            <div>
              <label class="text-[10px] block">${t('Planner')}</label>
              <input id="orchOvrPlanner" class="input text-xs w-full" placeholder="${t('비워두면 기본값')}">
            </div>
            <div>
              <label class="text-[10px] block">${t('Aggregator')}</label>
              <input id="orchOvrAgg" class="input text-xs w-full" placeholder="${t('비워두면 기본값')}">
            </div>
            <div>
              <label class="text-[10px] block">${t('Assignees (csv)')}</label>
              <input id="orchOvrAssignees" class="input text-xs w-full" placeholder="claude:sonnet, openai:gpt-4.1">
            </div>
          </div>
        </details>
        <div class="flex items-center gap-2 mt-2">
          <button class="chip text-[10px]" onclick="_orchDispatch()">${t('실행')}</button>
          <button class="chip text-[10px]" onclick="_orchToggleLive()" id="orchLiveBtn">${t('라이브 시작')}</button>
          <span id="orchLiveStatus" class="text-[10px]" style="color:var(--text-dim)">${t('대기')}</span>
        </div>
        <pre id="orchOutput" class="text-[10px] mt-3 whitespace-pre-wrap" style="color:var(--text-dim)"></pre>
        <div class="text-[10px] uppercase tracking-wider mt-3" style="color:var(--text-dim)">${t('라이브 이벤트')}</div>
        <pre id="orchLiveLog" class="text-[10px] whitespace-pre-wrap" style="max-height:240px;overflow-y:auto;color:var(--text-dim)"></pre>
      </div>
      <div class="card p-4 lg:col-span-2">
        <div class="flex items-center gap-2 mb-2">
          <div class="text-[12px] font-semibold">${t('스케줄러 상태')}</div>
          <span class="text-[10px]" style="color:var(--text-dim)">${t('schedule.everyMinutes 가 설정된 바인딩의 다음 실행 시각')}</span>
          <button class="chip text-[10px] ml-auto" onclick="_orchRefreshSweeper()">${t('새로고침')}</button>
        </div>
        <div id="orchSweeper" class="text-[11px]" style="color:var(--text-dim)">${t('로딩 중...')}</div>
      </div>
      <div class="card p-4 lg:col-span-2">
        <div class="flex items-center gap-2 mb-2">
          <div class="text-[12px] font-semibold">${t('IPC 스트림')}</div>
          <span class="text-[10px]" style="color:var(--text-dim)">${t('inbound (사용자 → 오케) / outbound (오케 → 채널) 분리 로그')}</span>
          <button class="chip text-[10px] ml-auto" onclick="_orchRefreshIpc()">${t('새로고침')}</button>
          <input id="orchIpcChan" class="input text-xs" placeholder="${t('채널 필터 (선택)')}" oninput="_orchRefreshIpc()">
        </div>
        <div class="grid grid-cols-1 lg:grid-cols-2 gap-3">
          <div>
            <div class="text-[10px] uppercase tracking-wider mb-1" style="color:var(--text-dim)">⬇ inbound</div>
            <div id="orchIpcInbound" class="text-[11px]" style="max-height:280px;overflow-y:auto;"></div>
          </div>
          <div>
            <div class="text-[10px] uppercase tracking-wider mb-1" style="color:var(--text-dim)">⬆ outbound</div>
            <div id="orchIpcOutbound" class="text-[11px]" style="max-height:280px;overflow-y:auto;"></div>
          </div>
        </div>
      </div>
    </div>
  `;
};

async function _orchRefreshSweeper() {
  const r = await api('/api/orchestrator/sweeper-status').catch(() => null);
  const host = document.getElementById('orchSweeper');
  if (!host || !r) return;
  if (!r.ok) { host.textContent = r.error || 'error'; return; }
  if (!r.schedules.length) {
    host.innerHTML = `${t('예약된 바인딩 없음')} · sweeper ${r.running?'🟢':'⚪'}`;
    return;
  }
  const rows = r.schedules.map(s => {
    const nextRel = s.dueNow ? `<span style="color:var(--success)">⚡ ${t('지금 실행 가능')}</span>`
      : `<span class="font-mono">${new Date(s.nextFireMs).toLocaleTimeString()}</span>`;
    return `<tr class="text-[11px]">
      <td class="p-1 font-mono">${escapeHtml(s.kind)}</td>
      <td class="p-1 font-mono truncate" style="max-width:200px;">${escapeHtml(s.channel)}</td>
      <td class="p-1">${s.everyMinutes}m</td>
      <td class="p-1 truncate" style="max-width:280px;color:var(--text)">${escapeHtml(s.promptHead)}</td>
      <td class="p-1">${nextRel}</td>
    </tr>`;
  }).join('');
  host.innerHTML = `
    <div class="text-[10px] mb-2">sweeper ${r.running?'🟢':'⚪'} · ${t('주기')} ${r.intervalSec}s · ${r.schedules.length} ${t('예약됨')}</div>
    <table class="w-full text-left">
      <thead><tr class="text-[10px]" style="color:var(--text-dim)">
        <th class="p-1">kind</th><th class="p-1">channel</th>
        <th class="p-1">${t('주기')}</th><th class="p-1">prompt</th>
        <th class="p-1">${t('다음 실행')}</th>
      </tr></thead>
      <tbody>${rows}</tbody>
    </table>`;
}

async function _orchRefreshIpc() {
  const chan = (document.getElementById('orchIpcChan') || {}).value || '';
  const qs = chan ? '?channel=' + encodeURIComponent(chan) : '';
  const [inb, out] = await Promise.all([
    api('/api/orchestrator/inbound' + qs).catch(() => null),
    api('/api/orchestrator/outbound' + qs).catch(() => null),
  ]);
  const fmtMs = (ms) => ms ? new Date(ms).toLocaleTimeString() : '—';
  const inHost = document.getElementById('orchIpcInbound');
  const outHost = document.getElementById('orchIpcOutbound');
  if (inHost) {
    const items = (inb && inb.items) || [];
    inHost.innerHTML = items.length ? items.map(it => `
      <div class="card p-2 mb-1" style="background:rgba(96,165,250,0.04);">
        <div class="flex items-center gap-2 text-[10px]" style="color:var(--text-dim)">
          <span class="font-mono">${fmtMs(it.ts)}</span>
          <span class="chip text-[9px]">${escapeHtml(it.kind)}</span>
          <span class="font-mono truncate" style="max-width:120px;">${escapeHtml(it.channel || '')}</span>
          <span class="font-mono ml-auto" style="color:var(--text-dim)">#${it.id}</span>
        </div>
        <div class="text-[11px] mt-1">${escapeHtml((it.text || '').slice(0, 200))}</div>
      </div>`).join('') : _emptyState(t('inbound 없음'), '⬇');
  }
  if (outHost) {
    const items = (out && out.items) || [];
    outHost.innerHTML = items.length ? items.map(it => `
      <div class="card p-2 mb-1" style="background:rgba(${it.ok?'34,197,94':'252,165,165'},0.04);">
        <div class="flex items-center gap-2 text-[10px]" style="color:var(--text-dim)">
          <span class="font-mono">${fmtMs(it.ts)}</span>
          <span class="chip text-[9px]">${escapeHtml(it.kind)}</span>
          <span class="chip text-[9px]">${escapeHtml(it.via || 'ad-hoc')}</span>
          <span class="font-mono truncate" style="max-width:120px;">${escapeHtml(it.channel || '')}</span>
          <span class="font-mono ml-auto" style="color:${it.ok?'var(--success)':'#fca5a5'};">${it.ok?'ok':'err'}</span>
        </div>
        <div class="text-[11px] mt-1">${escapeHtml((it.text || '').slice(0, 200))}</div>
      </div>`).join('') : _emptyState(t('outbound 없음'), '⬆');
  }
}

AFTER.orchestrator = () => {
  // I4 (v2.61.0) — initial IPC fetch.
  try { _orchRefreshIpc(); } catch (_) {}
  // K2 (v2.63.0) — initial sweeper status fetch.
  try { _orchRefreshSweeper(); } catch (_) {}
  // Auto-stop any prior stream when leaving the tab.
  if (state.data._orchEs) {
    try { state.data._orchEs.close(); } catch (_) {}
    state.data._orchEs = null;
  }
};

// W1 (v2.66.9) — chip-based multi-picker for default assignees. The
// hidden #orchDefaults input mirrors the chip list as a CSV so the save
// path stays the same.
function _orchToggleAssignee(value) {
  const hidden = document.getElementById('orchDefaults');
  if (!hidden) return;
  const cur = (hidden.value || '').split(',').map(s => s.trim()).filter(Boolean);
  const idx = cur.indexOf(value);
  if (idx >= 0) cur.splice(idx, 1); else cur.push(value);
  hidden.value = cur.join(',');
  // Re-render chips block in place
  const host = document.getElementById('orchAssigneeChips');
  if (host) {
    host.innerHTML = cur.length
      ? cur.map(a => `<span class="chip text-[10px]" style="cursor:pointer;background:rgba(167,139,250,0.18);border-color:rgba(167,139,250,0.4);" onclick="_orchToggleAssignee('${escapeHtml(a)}')">${escapeHtml(a)} ✕</span>`).join('')
      : `<span class="text-[10px]" style="color:var(--text-dim)">${t('아래 + 버튼으로 추가')}</span>`;
  }
}

async function _orchSaveCfg() {
  const body = {
    plannerAssignee:    (document.getElementById('orchPlanner') || {}).value,
    aggregatorAssignee: (document.getElementById('orchAggregator') || {}).value,
    defaultAssignees:   ((document.getElementById('orchDefaults') || {}).value || '').split(',').map(s => s.trim()).filter(Boolean),
    maxParallel:        parseInt((document.getElementById('orchParallel') || {}).value || '4', 10),
  };
  const r = await api('/api/orchestrator/config/save', { method: 'POST', body });
  toast(r.ok ? t('저장됨') : (r.error || t('저장 실패')));
  if (r.ok) renderView();
}
async function _orchAddBinding() {
  const kind = (prompt('kind (slack/telegram/http):') || '').trim();
  if (!kind) return;
  const target = (prompt(kind === 'telegram' ? 'chat id:' : 'channel id:') || '').trim();
  if (!target) return;
  const assignees = (prompt('assignees (csv, blank=defaults):') || '').split(',').map(s => s.trim()).filter(Boolean);
  const workflowId = (prompt('workflowId (blank for ad-hoc):') || '').trim();
  const body = { kind };
  body[kind === 'telegram' ? 'chat' : 'channel'] = target;
  if (assignees.length) body.assignees = assignees;
  if (workflowId) body.workflowId = workflowId;
  const r = await api('/api/orchestrator/bind', { method: 'POST', body });
  toast(r.ok ? t('추가됨') : (r.error || t('실패')));
  if (r.ok) renderView();
}
async function _orchUnbind(kind, target) {
  if (!confirm(t('바인딩을 삭제할까요?'))) return;
  const body = { kind };
  body[kind === 'telegram' ? 'chat' : 'channel'] = target;
  const r = await api('/api/orchestrator/unbind', { method: 'POST', body });
  toast(r.ok ? t('삭제됨') : (r.error || t('실패')));
  if (r.ok) renderView();
}
async function _orchStart() {
  const r = await api('/api/orchestrator/start', { method: 'POST', body: {} });
  toast(r.ok ? `OK: ${JSON.stringify(r.status)}` : (r.error || t('실패')));
}
async function _orchDispatch() {
  const txt = (document.getElementById('orchTestText') || {}).value || '';
  const out = document.getElementById('orchOutput');
  if (!txt.trim()) return;
  if (out) out.textContent = t('실행 중...');
  const planner = ((document.getElementById('orchOvrPlanner') || {}).value || '').trim();
  const agg = ((document.getElementById('orchOvrAgg') || {}).value || '').trim();
  const assigneesRaw = ((document.getElementById('orchOvrAssignees') || {}).value || '').trim();
  const body = { text: txt, kind: 'http', channel: 'ui-test' };
  if (planner) body.plannerAssignee = planner;
  if (agg) body.aggregatorAssignee = agg;
  if (assigneesRaw) body.assignees = assigneesRaw.split(',').map(s => s.trim()).filter(Boolean);
  const r = await api('/api/orchestrator/dispatch', { method: 'POST', body });
  if (out) out.textContent = JSON.stringify(r, null, 2);
}

function _orchToggleLive() {
  const btn = document.getElementById('orchLiveBtn');
  const stat = document.getElementById('orchLiveStatus');
  const log = document.getElementById('orchLiveLog');
  if (state.data._orchEs) {
    try { state.data._orchEs.close(); } catch (_) {}
    state.data._orchEs = null;
    if (btn) btn.textContent = t('라이브 시작');
    if (stat) stat.textContent = t('대기');
    return;
  }
  if (typeof EventSource !== 'function') {
    if (stat) stat.textContent = 'EventSource not supported';
    return;
  }
  const es = new EventSource('/api/agent-bus/stream?topics=' + encodeURIComponent('orch.*,wf.**'));
  state.data._orchEs = es;
  if (btn) btn.textContent = t('라이브 중지');
  if (stat) stat.textContent = t('연결됨');
  es.addEventListener('bus', (e) => {
    try {
      const ev = JSON.parse(e.data);
      const line = `[${new Date(ev.ts).toLocaleTimeString()}] ${ev.topic}  ${ev.source||''}  ` + JSON.stringify(ev.payload).slice(0, 240);
      if (log) {
        log.textContent = (line + '\n' + log.textContent).slice(0, 16000);
      }
    } catch (_) {}
  });
  es.addEventListener('ping', () => {
    if (stat) stat.textContent = t('연결됨') + ' · ♥';
  });
  es.onerror = () => {
    if (stat) stat.textContent = t('연결 끊김');
    try { es.close(); } catch (_) {}
    state.data._orchEs = null;
    if (btn) btn.textContent = t('라이브 시작');
  };
}

// ────────────────────────────────────────────────────────────────
// 🦞 RALPH LOOP — same-prompt iteration with 4-fold safety
// ────────────────────────────────────────────────────────────────
VIEWS.ralph = async () => {
  const r = await api('/api/ralph/list?limit=200');
  if (!r.ok) return `<div class="card p-6 text-[12px]">${t('데이터를 불러오지 못했습니다')}</div>`;
  const allRuns = r.runs || [];
  // K4 (v2.63.0) — client-side status filter + prompt search.
  const filterStatus = state.data._ralphFilter || 'all';
  const filterQ = (state.data._ralphFilterQ || '').toLowerCase();
  const runs = allRuns.filter(it => {
    if (filterStatus !== 'all' && it.status !== filterStatus) return false;
    if (filterQ && !((it.runId||'') + ' ' + (it.assignee||'')).toLowerCase().includes(filterQ)) return false;
    return true;
  });
  // count by status for the chip bar
  const statusCounts = {};
  for (const it of allRuns) {
    statusCounts[it.status] = (statusCounts[it.status] || 0) + 1;
  }
  const _statusChip = (k, label) => {
    const n = statusCounts[k] || 0;
    const active = filterStatus === k;
    return `<button class="chip text-[10px]" style="${active?'background:var(--accent);color:#fff;':''}"
      onclick="state.data._ralphFilter='${k}';renderView()">${label}${n?` <span class="font-mono ml-1">${n}</span>`:''}</button>`;
  };
  const fmtMs = (ms) => ms ? new Date(ms).toLocaleString() : '—';
  const statusClass = (st) => ({
    done: 'var(--success)', running: 'var(--accent)',
    cancelled: 'var(--text-dim)', max_iter: '#fcd34d',
    budget: '#fca5a5', error: 'var(--danger)',
  })[st] || 'var(--text)';

  const rows = runs.length ? runs.map(it => `
    <tr class="text-[11px]" onclick="_ralphSelect('${escapeHtml(it.runId)}')" style="cursor:pointer;">
      <td class="p-1 font-mono">${escapeHtml(it.runId.slice(-10))}</td>
      <td class="p-1"><span class="chip text-[10px]" style="color:${statusClass(it.status)}">${escapeHtml(it.status)}</span></td>
      <td class="p-1">${it.iterations}/${it.maxIter}</td>
      <td class="p-1">$${(it.costUsd || 0).toFixed(4)} / $${(it.budgetUsd || 0).toFixed(2)}</td>
      <td class="p-1 font-mono">${escapeHtml(it.assignee)}</td>
      <td class="p-1" style="color:var(--text-dim)">${fmtMs(it.tsStart)}</td>
      <td class="p-1" onclick="event.stopPropagation()">
        <button class="chip text-[9px]" onclick="_ralphDuplicateRun('${escapeHtml(it.runId)}')" title="${t('이 실행을 동일 설정으로 다시 시작')}">🔁</button>
      </td>
    </tr>`).join('')
    : `<tr><td colspan="6" class="p-2 text-[11px]" style="color:var(--text-dim);text-align:center;">${t('아직 Ralph 실행 기록 없음')}</td></tr>`;

  return `
    ${viewHeader('🦞 Ralph Loop', t('ralph_subtitle', 'Same-prompt 반복 — Geoffrey Huntley Ralph Wiggum 패턴. max-iter / completion-promise / 예산 USD / 수동 cancel 4중 안전장치.'), 'ralph')}
    <div class="grid grid-cols-1 lg:grid-cols-[1fr_360px] gap-4">
      <div class="card p-4">
        <div class="flex items-center justify-between mb-2 flex-wrap gap-2">
          <div class="text-[12px] font-semibold">${t('실행 목록')}
            <span class="text-[10px] ml-2" style="color:var(--text-dim)">${runs.length}/${allRuns.length}</span>
          </div>
          <button class="chip text-[10px]" onclick="renderView()">${t('새로고침')}</button>
        </div>
        <div class="flex items-center gap-1 flex-wrap mb-2">
          ${_statusChip('all', t('전체'))}
          ${_statusChip('running', '⚡ running')}
          ${_statusChip('done', '✓ done')}
          ${_statusChip('budget', '💰 budget')}
          ${_statusChip('max_iter', '🔁 max-iter')}
          ${_statusChip('cancelled', '⏹ cancelled')}
          ${_statusChip('error', '✗ error')}
          <input class="input text-xs ml-auto" placeholder="${t('runId / assignee 검색')}"
            value="${escapeHtml(filterQ)}"
            oninput="state.data._ralphFilterQ=this.value;renderView()" style="width:200px;">
        </div>
        <table class="w-full text-left">
          <thead><tr class="text-[10px]" style="color:var(--text-dim)">
            <th class="p-1">runId</th><th class="p-1">status</th>
            <th class="p-1">iter</th><th class="p-1">cost / budget</th>
            <th class="p-1">assignee</th><th class="p-1">started</th>
            <th class="p-1"></th>
          </tr></thead>
          <tbody>${rows}</tbody>
        </table>
        <div id="ralphLive" class="mt-4"></div>
      </div>
      <div class="card p-4">
        <div class="text-[12px] font-semibold mb-2">${t('새 실행 시작')}</div>
        <label class="text-[11px] block mb-1">${t('Prompt')}
          <textarea id="ralphPrompt" rows="6" class="input text-xs" placeholder="Fix every failing test. Output <promise>DONE</promise> when green."></textarea>
        </label>
        <label class="text-[11px] block mb-1">${t('Assignee')}
          <input id="ralphAssignee" class="input text-xs" placeholder="claude:sonnet">
        </label>
        <label class="text-[11px] block mb-1">${t('Completion 표식')}
          <input id="ralphCompletion" class="input text-xs" value="<promise>DONE</promise>">
        </label>
        <div class="flex gap-2 mb-1">
          <label class="text-[11px] flex-1">${t('Max iter')}
            <input id="ralphMax" type="number" min="1" max="200" class="input text-xs" value="25">
          </label>
          <label class="text-[11px] flex-1">${t('예산 USD')}
            <input id="ralphBudget" type="number" min="0.01" max="100" step="0.5" class="input text-xs" value="5">
          </label>
        </div>
        <button class="chip text-[10px] mt-2" onclick="_ralphStart()">🚀 ${t('시작')}</button>
        <div class="text-[10px] mt-3" style="color:var(--text-dim)">
          ${t('CLI')}: <code>python3 tools/ralph_loop.py --prompt-file PROMPT.md</code>
        </div>
        <div class="mt-4 pt-3 border-t border-[var(--border)]">
          <div class="flex items-center gap-2 mb-2">
            <div class="text-[12px] font-semibold">${t('Polish 시스템 프롬프트')}</div>
            <span id="ralphPolishSrc" class="chip text-[10px]" style="color:var(--text-dim)">—</span>
          </div>
          <div class="text-[10px] mb-2" style="color:var(--text-dim)">
            ${t('LLM polish 패스가 추천 PROMPT.md를 다듬을 때 사용하는 시스템 프롬프트. 비워두고 저장하면 기본값으로 복원.')}
          </div>
          <textarea id="ralphPolishText" rows="6" class="input text-xs" placeholder="${t('비워두면 기본값 사용')}"></textarea>
          <div class="flex items-center gap-2 mt-2">
            <button class="chip text-[10px]" onclick="_ralphPolishLoad()">${t('현재 로드')}</button>
            <button class="chip text-[10px]" onclick="_ralphPolishSave()">${t('저장')}</button>
            <button class="chip text-[10px]" onclick="_ralphPolishClear()">${t('기본값으로 복원')}</button>
          </div>
        </div>
      </div>
    </div>
  `;
};

async function _ralphPolishLoad() {
  const r = await api('/api/ralph/polish-prompt');
  const text = (r && r.current) || '';
  const src = (r && r.source) || 'default';
  const ta = document.getElementById('ralphPolishText');
  const lbl = document.getElementById('ralphPolishSrc');
  if (ta) ta.value = text;
  if (lbl) lbl.textContent = `${t('출처')}: ${src}`;
}
async function _ralphPolishSave() {
  const text = (document.getElementById('ralphPolishText') || {}).value || '';
  if (!text.trim()) { toast(t('비어있는 프롬프트는 저장할 수 없음. 기본값 복원을 사용하세요.'), 'err'); return; }
  const r = await api('/api/ralph/polish-prompt', { method: 'POST', body: { text }});
  toast(r && r.ok ? t('저장됨') : ((r && r.error) || t('실패')), r && r.ok ? 'ok' : 'err');
  if (r && r.ok) _ralphPolishLoad();
}
async function _ralphPolishClear() {
  if (!confirm(t('Polish 시스템 프롬프트를 기본값으로 되돌릴까요?'))) return;
  const r = await api('/api/ralph/polish-prompt', { method: 'POST', body: { clear: true }});
  toast(r && r.ok ? t('기본값으로 복원됨') : ((r && r.error) || t('실패')), r && r.ok ? 'ok' : 'err');
  if (r && r.ok) _ralphPolishLoad();
}

AFTER.ralph = () => {
  if (state.data._ralphEs) {
    try { state.data._ralphEs.close(); } catch (_) {}
    state.data._ralphEs = null;
  }
  // J1 (v2.62.0) — auto-load polish prompt on tab open.
  try { _ralphPolishLoad(); } catch (_) {}
  // L1 (v2.64.0) — poll the runs list while any run is in-flight; stop
  // when all settle. Cleared on tab leave by BEFORE-style hook below.
  try { _ralphStartAutoRefresh(); } catch (_) {}
};

function _ralphStartAutoRefresh() {
  if (state.data._ralphPollTimer) {
    clearInterval(state.data._ralphPollTimer);
    state.data._ralphPollTimer = null;
  }
  // X2 (v2.66.10) — only renderView when the runs list *actually changed*.
  // The previous version called renderView every 3s regardless of new
  // data, which caused visible flicker on the Ralph tab even with no
  // active runs. Hash the (id,status,iter) tuple per run; render only on
  // change.
  state.data._ralphPollTimer = setInterval(async () => {
    if (state.view !== 'ralph') {
      clearInterval(state.data._ralphPollTimer);
      state.data._ralphPollTimer = null;
      return;
    }
    try {
      const r = await api('/api/ralph/list?limit=200');
      if (!r || !r.ok) return;
      const runs = r.runs || [];
      const sig = runs.map(x => `${x.runId}:${x.status}:${x.iterations||0}:${(x.costUsd||0).toFixed(4)}`).join('|');
      const anyRunning = runs.some(x => x.status === 'running');
      if (!anyRunning) {
        clearInterval(state.data._ralphPollTimer);
        state.data._ralphPollTimer = null;
      }
      if (sig !== state.data._ralphRunsSig) {
        state.data._ralphRunsSig = sig;
        renderView();
      }
    } catch (_) { /* keep timer alive on transient errors */ }
  }, 3000);
}

async function _ralphStart() {
  const prompt   = (document.getElementById('ralphPrompt') || {}).value || '';
  const assignee = (document.getElementById('ralphAssignee') || {}).value || '';
  const completion = (document.getElementById('ralphCompletion') || {}).value || '';
  const max    = parseInt((document.getElementById('ralphMax') || {}).value || '25', 10);
  const budget = parseFloat((document.getElementById('ralphBudget') || {}).value || '5');
  if (!prompt.trim()) { toast(t('프롬프트가 비어 있음')); return; }
  const r = await api('/api/ralph/start', { method: 'POST', body: {
    prompt, assignee, completion, maxIterations: max, budgetUsd: budget,
  }});
  if (!r.ok) { toast(r.error || 'failed'); return; }
  toast(`${t('시작됨')}: ${r.runId}`);
  _ralphSelect(r.runId);
  setTimeout(renderView, 600);
}

function _ralphSelect(runId) {
  const host = document.getElementById('ralphLive');
  if (!host) return;
  if (state.data._ralphEs) {
    try { state.data._ralphEs.close(); } catch (_) {}
    state.data._ralphEs = null;
  }
  host.innerHTML = `
    <div class="flex items-center gap-2 mb-2">
      <div class="text-[12px] font-semibold">${t('라이브')}: <code>${escapeHtml(runId)}</code></div>
      <button class="chip text-[10px]" onclick="_ralphCancel('${escapeHtml(runId)}')">⏹ ${t('취소')}</button>
      <span id="ralphStatus" class="text-[10px]" style="color:var(--text-dim)">${t('연결 중')}</span>
    </div>
    <pre id="ralphLog" class="text-[10px] whitespace-pre-wrap" style="max-height:300px;overflow-y:auto;color:var(--text-dim)"></pre>
  `;
  if (typeof EventSource !== 'function') {
    const stat = document.getElementById('ralphStatus');
    if (stat) stat.textContent = 'EventSource not supported'; return;
  }
  const es = new EventSource('/api/agent-bus/stream?topics=' + encodeURIComponent('ralph.' + runId + '.**'));
  state.data._ralphEs = es;
  const log = document.getElementById('ralphLog');
  const stat = document.getElementById('ralphStatus');
  if (stat) stat.textContent = t('연결됨');
  es.addEventListener('bus', (e) => {
    try {
      const ev = JSON.parse(e.data);
      const tag = ev.topic.split('.').slice(2).join('.');
      const line = `[${new Date(ev.ts).toLocaleTimeString()}] ${tag}  ${JSON.stringify(ev.payload).slice(0, 200)}`;
      if (log) log.textContent = (line + '\n' + log.textContent).slice(0, 16000);
      if (tag === 'end') {
        if (stat) stat.textContent = `${t('종료')}: ${ev.payload.status}`;
        try { es.close(); } catch (_) {}
        state.data._ralphEs = null;
      }
    } catch (_) {}
  });
  es.addEventListener('ping', () => { if (stat) stat.textContent = t('연결됨') + ' · ♥'; });
  es.onerror = () => {
    if (stat) stat.textContent = t('연결 끊김');
    try { es.close(); } catch (_) {}
    state.data._ralphEs = null;
  };
}

async function _ralphCancel(runId) {
  if (!confirm(t('이 Ralph 루프를 중단할까요?'))) return;
  const r = await api('/api/ralph/cancel', { method: 'POST', body: { runId }});
  toast(r.ok ? t('취소 요청 전송됨') : (r.error || t('실패')));
}

// M2 (v2.65.0) — duplicate run: prefill the start form with the same
// configuration as the picked run so the user can tweak (or just hit
// Start) instead of retyping everything.
async function _ralphDuplicateRun(runId) {
  const r = await api('/api/ralph/status?runId=' + encodeURIComponent(runId));
  if (!r || !r.ok) { toast(r && r.error || t('실패'), 'err'); return; }
  const run = r.run || {};
  const fill = (id, v) => { const el = document.getElementById(id); if (el && v != null) el.value = v; };
  fill('ralphPrompt',     run.prompt);
  fill('ralphAssignee',   run.assignee);
  fill('ralphCompletion', run.completion);
  fill('ralphMax',        run.maxIter);
  fill('ralphBudget',     run.budgetUsd);
  // Scroll to start form
  const ta = document.getElementById('ralphPrompt');
  if (ta && ta.scrollIntoView) ta.scrollIntoView({ behavior: 'smooth', block: 'center' });
  toast(t('이전 실행 설정 불러옴 — 검토 후 시작하세요'), 'ok');
}

// ────────────────────────────────────────────────────────────────
// SECURITY SCAN (v2.31.0) — ECC AgentShield 스타일 ~/.claude 정적 검사
// ────────────────────────────────────────────────────────────────
VIEWS.securityScan = async () => {
  const d = await api('/api/security-scan');
  if (!d.ok) return `<div class="card p-6 text-[12px]">${t('데이터를 불러오지 못했습니다')}</div>`;
  const counts = d.counts || {};
  const sev = counts.bySeverity || {};
  const cat = counts.byCategory || {};
  const issues = d.issues || [];

  const sevColor = { critical: '#f87171', high: '#fbbf24', medium: '#a78bfa', low: '#60a5fa', info: '#9ca3af' };
  const sevEmoji = { critical: '🔴', high: '🟠', medium: '🟣', low: '🔵', info: '⚪' };

  const summary = `
    <div class="grid grid-cols-1 md:grid-cols-5 gap-2 mb-4">
      ${['critical','high','medium','low','info'].map(s => `
        <div class="card p-3 text-center">
          <div class="text-[10px] uppercase" style="color:${sevColor[s]}">${sevEmoji[s]} ${s}</div>
          <div class="text-2xl font-bold mt-1 font-mono" style="color:${sevColor[s]}">${sev[s] || 0}</div>
        </div>`).join('')}
    </div>`;

  const issueRows = issues.length ? issues.map(iss => `
    <div class="card p-3 mb-2" style="border-left:3px solid ${sevColor[iss.severity]||'#888'};">
      <div class="flex items-start gap-2">
        <span>${sevEmoji[iss.severity]||'⚪'}</span>
        <div class="flex-1 min-w-0">
          <div class="flex items-center gap-2 mb-1 flex-wrap">
            <span class="text-[11px] font-semibold">${escapeHtml(iss.title)}</span>
            <span class="chip text-[9px]" style="background:rgba(255,255,255,0.06);color:${sevColor[iss.severity]}">${iss.severity}</span>
            <span class="chip text-[9px]" style="background:rgba(255,255,255,0.04);color:var(--text-dim)">${escapeHtml(iss.category)}</span>
          </div>
          ${iss.detail ? `<div class="text-[10px] mb-1" style="color:var(--text-mute)">${escapeHtml(iss.detail)}</div>` : ''}
          ${iss.location ? `<div class="text-[9px] font-mono" style="color:var(--text-dim)">📍 ${escapeHtml(iss.location)}</div>` : ''}
        </div>
      </div>
    </div>
  `).join('') : `<div class="card p-6 text-center text-[12px]" style="color:var(--success)">✅ ${t('sec_no_issues', '감지된 이슈 없음 — 깨끗합니다!')}</div>`;

  return `
    ${viewHeader('🛡️ Security Scan', t('sec_subtitle', '~/.claude 전체(설정·훅·에이전트·MCP)를 정적 검사 — 시크릿 · 위험 훅 · 과도한 권한 · 신뢰 불가 MCP. AI 호출 없음, 100% 로컬.'), 'securityScan')}
    ${summary}
    <div class="card p-4 mb-4">
      <div class="flex items-center justify-between mb-2">
        <h3 class="text-base font-semibold">${t('sec_issues_heading', '감지된 이슈')} (${issues.length})</h3>
        <button class="btn text-[11px]" onclick="renderView()">🔄 ${t('다시 검사')}</button>
      </div>
      ${issueRows}
    </div>
    <div class="text-[10px]" style="color:var(--text-dim)">
      ${t('sec_hint', '검사 대상: settings.json · CLAUDE.md · settings.hooks · ~/.claude/agents · mcp.json. ECC AgentShield 방식에서 영감. 발견된 시크릿은 rotate 후 env var 로 옮기세요.')}
    </div>
  `;
};

// ────────────────────────────────────────────────────────────────
// LEARNER (v2.30.0) — 세션 JSONL 에서 반복 패턴 추출 → skill/prompt/workflow 제안
// ────────────────────────────────────────────────────────────────
VIEWS.learner = async () => {
  const d = await api('/api/learner/patterns');
  if (!d.ok) return `<div class="card p-6 text-[12px]">${t('데이터를 불러오지 못했습니다')}</div>`;
  if ((d.sessions || 0) === 0) {
    return `
      ${viewHeader('🎓 Learner', t('learner_subtitle', '최근 세션에서 반복되는 패턴을 자동 추출. AI 판단 없이 통계 기반.'), 'learner')}
      <div class="card p-6 text-center text-[12px]" style="color:var(--text-dim)">
        ${t('learner_no_sessions', '최근 30일 세션이 없습니다. Claude Code 를 한 번 이상 사용하세요.')}
      </div>`;
  }
  const stats = d.stats || {};
  const topTools = (stats.topTools || []).slice(0, 8);
  const maxTool = topTools.reduce((m, x) => Math.max(m, x.count), 1);
  const lb = stats.lengthBuckets || {};
  const totalSess = d.sessions || 0;

  const toolRows = topTools.map(x => `
    <div class="flex items-center gap-2 text-[11px]">
      <span class="w-28 font-mono truncate" title="${escapeHtml(x.name)}">${escapeHtml(x.name)}</span>
      <div class="flex-1 h-3 rounded" style="background:rgba(255,255,255,0.06); position:relative;">
        <div style="background:var(--accent);height:100%;border-radius:4px;width:${(x.count/maxTool*100).toFixed(0)}%;"></div>
      </div>
      <span class="w-10 text-right font-mono" style="color:var(--text-dim)">${x.count}</span>
    </div>`).join('');

  const patternCards = (d.patterns || []).map((p, i) => {
    if (p.type === 'repeated_prompt') {
      return `
        <div class="card p-3">
          <div class="flex items-start justify-between mb-1 gap-2">
            <div class="text-[12px] font-semibold">📝 ${t('learner_repeated_prompt', '반복 프롬프트')}</div>
            <span class="chip text-[10px]">${p.count}×</span>
          </div>
          <div class="text-[11px] mb-2 line-clamp-2" style="color:var(--text-mute)">${escapeHtml(p.detail)}</div>
          <button class="btn btn-primary text-[11px] w-full"
                  onclick='_learnerToPromptLib(${JSON.stringify(p.action).replace(/'/g, "&#39;")})'>
            → ${t('learner_to_prompt_lib', 'Prompt Library 로 저장')}
          </button>
        </div>`;
    } else if (p.type === 'tool_sequence') {
      return `
        <div class="card p-3">
          <div class="flex items-start justify-between mb-1 gap-2">
            <div class="text-[12px] font-semibold">🔀 ${t('learner_tool_seq', 'Tool 시퀀스')}</div>
            <span class="chip text-[10px]">${p.count}×</span>
          </div>
          <div class="text-[11px] mb-2">
            ${p.action.sequence.map(s => `<span class="chip text-[10px] font-mono">${escapeHtml(s)}</span>`).join(' → ')}
          </div>
          <div class="text-[10px] mb-2" style="color:var(--text-dim)">${escapeHtml(p.detail)}</div>
          <button class="btn btn-primary text-[11px] w-full" onclick="go('workflows')">
            → ${t('learner_to_workflows', '워크플로우 탭으로 이동')}
          </button>
        </div>`;
    }
    return '';
  }).join('') || `<div class="text-[11px]" style="color:var(--text-dim)">${t('learner_no_patterns', '아직 제안할 패턴이 충분히 누적되지 않았습니다.')}</div>`;

  const lengthsTotal = (lb.small||0)+(lb.medium||0)+(lb.large||0)+(lb.huge||0);
  const bar = (n) => lengthsTotal ? (n/lengthsTotal*100).toFixed(0) : 0;

  return `
    ${viewHeader('🎓 Learner', t('learner_subtitle', '최근 세션에서 반복되는 패턴을 자동 추출. AI 판단 없이 통계 기반.'), 'learner')}

    <div class="grid grid-cols-1 md:grid-cols-3 gap-3 mb-4">
      <div class="card p-4">
        <div class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider">${t('learner_sessions_scanned', '스캔한 세션')}</div>
        <div class="text-2xl font-bold mt-1 font-mono">${totalSess}</div>
        <div class="text-[10px]" style="color:var(--text-dim)">${t('learner_days_window', `최근 ${d.days}일`)}</div>
      </div>
      <div class="card p-4">
        <div class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider">${t('learner_total_tokens', '누적 토큰')}</div>
        <div class="text-2xl font-bold mt-1 font-mono" style="color:var(--accent)">${(stats.totalTokens||0).toLocaleString()}</div>
      </div>
      <div class="card p-4">
        <div class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('learner_length_dist', '세션 길이 분포')}</div>
        <div class="flex gap-1 h-4 rounded overflow-hidden" style="background:rgba(255,255,255,0.05);">
          <div style="width:${bar(lb.small||0)}%;background:#4ade80" title="small ≤10: ${lb.small||0}"></div>
          <div style="width:${bar(lb.medium||0)}%;background:#60a5fa" title="medium 10-50: ${lb.medium||0}"></div>
          <div style="width:${bar(lb.large||0)}%;background:#a78bfa" title="large 50-200: ${lb.large||0}"></div>
          <div style="width:${bar(lb.huge||0)}%;background:#f472b6" title="huge >200: ${lb.huge||0}"></div>
        </div>
        <div class="flex gap-2 text-[9px] mt-1" style="color:var(--text-dim)">
          <span>🟢 ${lb.small||0} small</span><span>🔵 ${lb.medium||0} med</span>
          <span>🟣 ${lb.large||0} large</span><span>🌸 ${lb.huge||0} huge</span>
        </div>
      </div>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4 mb-4">
      <div class="card p-4">
        <div class="text-[12px] font-semibold mb-2">🛠️ ${t('learner_top_tools', '자주 쓰는 Tool')}</div>
        <div class="space-y-1.5">${toolRows || `<div class="text-[10px]" style="color:var(--text-dim)">${t('데이터 없음')}</div>`}</div>
      </div>
      <div class="card p-4">
        <div class="text-[12px] font-semibold mb-2">💡 ${t('learner_suggestions', '자동 추출된 제안')}</div>
        <div class="grid grid-cols-1 gap-2">${patternCards}</div>
      </div>
    </div>

    <div class="text-[10px]" style="color:var(--text-dim)">
      ${t('learner_hint', '분석은 완전히 로컬에서 수행됩니다. Claude API 호출 없음. 제안 카드는 클릭 시 해당 탭으로 이동하여 수동 저장할 수 있습니다.')}
    </div>
  `;
};

function _learnerToPromptLib(action) {
  try {
    state.data.pl = state.data.pl || {};
    state.data.pl.editing = {
      title: (action.suggestedTitle || '').slice(0, 80) || 'From Learner',
      body: action.body || '',
      tags: ['learner'], tagsRaw: 'learner',
      keywords: [], keywordsRaw: '',
      model: '',
    };
    go('promptLibrary');
    toast(t('learner_prefilled', '에디터에 미리 채워졌습니다 — 검토 후 저장하세요'), 'ok');
  } catch (e) { toast(String(e), 'err'); }
}

