// SESSION REPLAY LAB (v2.25.0) — Claude Code JSONL 타임라인 재생
// ────────────────────────────────────────────────────────────────
VIEWS.sessionReplay = async () => {
  const d = await api('/api/session-replay/list');
  if (!d.ok) return `<div class="card p-6 text-[12px]">${t('데이터를 불러오지 못했습니다')}</div>`;
  const files = d.files || [];
  const sel = state.data._srSelected || '';
  const fmt = (n) => n < 1024 ? n + 'B' : n < 1048576 ? (n/1024).toFixed(1) + 'KB' : (n/1048576).toFixed(2) + 'MB';
  const fmtTime = (ms) => new Date(ms).toLocaleString();
  const fileList = files.length
    ? files.map(f => `
        <div class="card p-2 flex items-center justify-between gap-2 ${sel === f.path ? 'border-[var(--accent)]' : ''}" style="border-width:1px;cursor:pointer;" onclick="_srSelect('${escapeHtml(f.path)}')">
          <div class="min-w-0 flex-1">
            <div class="text-[11px] font-mono truncate">${escapeHtml(f.project)}</div>
            <div class="text-[10px] text-[var(--text-dim)] truncate">${escapeHtml(f.path.split('/').pop())}</div>
          </div>
          <div class="text-[10px] text-[var(--text-mute)] flex-shrink-0 text-right">
            <div>${fmt(f.size)}</div>
            <div>${fmtTime(f.mtime)}</div>
          </div>
        </div>`).join('')
    : `<div class="text-[11px]" style="color:var(--text-dim)">${t('sr_no_sessions', '세션 JSONL 이 없습니다. Claude Code 를 최소 한 번 사용해 주세요.')}</div>`;

  return `
    ${viewHeader('🎞️ Session Replay', t('sr_subtitle', 'Claude Code 세션 로그(JSONL)를 시간순으로 재생 · 툴 호출 강조 · 누적 토큰 차트'), 'sessionReplay')}
    <div class="grid grid-cols-1 lg:grid-cols-[320px_1fr] gap-4">
      <div class="space-y-2" style="max-height:70vh;overflow-y:auto;">
        <div class="text-[10px] uppercase tracking-wider" style="color:var(--text-dim)">${t('sr_recent', '최근 50 세션')}</div>
        ${fileList}
      </div>
      <div id="srDetail">
        ${sel ? '<div class="text-[11px]" style="color:var(--text-dim)">로딩 중...</div>' : `<div class="card p-6 text-[12px]" style="color:var(--text-dim)">${t('sr_pick', '왼쪽에서 세션을 선택하세요.')}</div>`}
      </div>
    </div>
  `;
};

function _srSelect(path) {
  state.data._srSelected = path;
  renderView();
  setTimeout(() => _srLoad(path), 20);
}

// v2.33.8 — sessionReplay 키보드 네비 (J/K/숫자/Home/End)
function _srHighlight(idx) {
  const rows = document.querySelectorAll('.sr-event-row');
  if (!rows.length) return;
  const n = rows.length;
  idx = Math.max(0, Math.min(n - 1, idx));
  rows.forEach(r => r.style.outline = '');
  const row = rows[idx];
  if (!row) return;
  row.style.outline = '2px solid var(--accent)';
  row.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
  state.data._srCurIdx = idx;
}
_KEYDOWN_HANDLERS.push((e) => {
  if (state.view !== 'sessionReplay') return;
  if (['INPUT','TEXTAREA','SELECT'].includes((document.activeElement||{}).tagName)) return;
  const events = state.data._srEvents || [];
  if (!events.length) return;
  let cur = state.data._srCurIdx;
  if (cur == null || cur < 0) cur = -1;
  const n = events.length;
  if (e.key === 'j' || e.key === 'J') { e.preventDefault(); _srHighlight(cur + 1); return true; }
  if (e.key === 'k' || e.key === 'K') { e.preventDefault(); _srHighlight(cur - 1); return true; }
  if (e.key === 'Home') { e.preventDefault(); _srHighlight(0); return true; }
  if (e.key === 'End') { e.preventDefault(); _srHighlight(n - 1); return true; }
  if (/^[1-9]$/.test(e.key)) {
    e.preventDefault();
    const pct = parseInt(e.key, 10) / 10;
    _srHighlight(Math.floor((n - 1) * pct));
    return true;
  }
});

async function _srLoad(path) {
  const host = document.getElementById('srDetail');
  if (!host) return;
  try {
    const r = await api('/api/session-replay/load?path=' + encodeURIComponent(path));
    if (!r.ok) { host.innerHTML = `<div class="card p-4 text-[12px]" style="color:var(--danger)">${escapeHtml(r.error||'error')}</div>`; return; }
    const events = r.events || [];
    // 토큰 누적 스파크라인 계산
    let acc = 0;
    const points = events.map(e => { acc += (e.tokensIn||0) + (e.tokensOut||0); return acc; });
    const maxAcc = Math.max(1, ...points);
    const spark = points.length ? events.map((e, i) => {
      const x = (i / Math.max(1, points.length - 1)) * 600;
      const y = 40 - (points[i] / maxAcc) * 36;
      return `${i===0?'M':'L'}${x.toFixed(1)},${y.toFixed(1)}`;
    }).join(' ') : '';
    // v2.33.8 — 각 이벤트 row 에 data-sr-idx 부여, J/K/숫자 키보드 네비
    state.data._srEvents = events;
    state.data._srCurIdx = -1;
    const evtRows = events.map((e, idx) => {
      const roleColor = e.role === 'assistant' ? '#60a5fa' : e.role === 'user' ? '#fbbf24' : '#9ca3af';
      const time = e.ts ? new Date(e.ts).toLocaleTimeString() : '';
      const hasToolUse = (e.summary||'').includes('[tool_use:');
      const bg = hasToolUse ? 'background:rgba(168, 139, 250, 0.08);' : '';
      return `
        <div class="text-[10px] flex gap-2 py-1 border-b border-[var(--border)] sr-event-row" data-sr-idx="${idx}" style="${bg}">
          <span class="font-mono flex-shrink-0" style="color:var(--text-dim);width:80px;">${time}</span>
          <span class="font-semibold flex-shrink-0" style="color:${roleColor};width:70px;">${escapeHtml(e.role || e.type || '-')}</span>
          <span class="flex-1 break-all">${escapeHtml(e.summary || e.operation || '')}</span>
          <span class="flex-shrink-0 font-mono" style="color:var(--text-mute);">${e.tokensIn||0}↓ ${e.tokensOut||0}↑</span>
        </div>`;
    }).join('');
    host.innerHTML = `
      <div class="card p-3 mb-3">
        <div class="grid grid-cols-3 gap-3 mb-2">
          <div><div class="text-[10px]" style="color:var(--text-dim)">${t('이벤트')}</div><div class="text-lg font-semibold">${events.length}${r.truncated?'+':''}</div></div>
          <div><div class="text-[10px]" style="color:var(--text-dim)">${t('토큰 입력')}</div><div class="text-lg font-semibold" style="color:#60a5fa">${(r.totalTokensIn||0).toLocaleString()}</div></div>
          <div><div class="text-[10px]" style="color:var(--text-dim)">${t('토큰 출력')}</div><div class="text-lg font-semibold" style="color:#f472b6">${(r.totalTokensOut||0).toLocaleString()}</div></div>
        </div>
        ${spark ? `<svg viewBox="0 0 600 40" width="100%" height="40"><path d="${spark}" fill="none" stroke="var(--accent)" stroke-width="1.5" /></svg>` : ''}
        <div class="text-[10px] font-mono break-all" style="color:var(--text-dim)">${escapeHtml(r.path)}</div>
        <div class="text-[10px] mt-1" style="color:var(--text-dim)">⌨ ${t('J/K')} ${t('이벤트 이동')} · ${t('1-9')} ${t('10% 점프')} · ${t('Home/End')} ${t('처음/끝')}</div>
      </div>
      <div class="card p-3" id="srEventList" style="max-height:60vh;overflow-y:auto;">
        ${evtRows || `<div class="text-[11px]" style="color:var(--text-dim)">(empty)</div>`}
      </div>
    `;
  } catch (e) { host.innerHTML = `<div class="card p-4 text-[12px]" style="color:var(--danger)">${escapeHtml(String(e))}</div>`; }
}

// ────────────────────────────────────────────────────────────────
// RTK OPTIMIZER (v2.24.0) — rtk-ai/rtk 토큰 절감 프록시 통합
