// Shared formatter — bytes → human-readable. Local to this region; no global leak.
function _pmFmtBytes(b) {
  if (!b || b < 0) return '—';
  if (b < 1024) return b + ' B';
  if (b < 1024 * 1024) return (b / 1024).toFixed(1) + ' KB';
  if (b < 1024 * 1024 * 1024) return (b / (1024 * 1024)).toFixed(1) + ' MB';
  return (b / (1024 * 1024 * 1024)).toFixed(2) + ' GB';
}
function _pmFmtIdle(sec) {
  if (sec == null || sec < 0) return '—';
  if (sec < 60) return sec + 's';
  if (sec < 3600) return Math.floor(sec / 60) + 'm';
  return Math.floor(sec / 3600) + 'h ' + Math.floor((sec % 3600) / 60) + 'm';
}
async function _pmKillPid(pid, sigName) {
  if (!confirm(t('정말 이 프로세스를 종료하시겠습니까?') + ' PID ' + pid + ' (' + sigName + ')')) return;
  try {
    const r = await api('/api/process/kill', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ pid: pid, signal: sigName }),
    });
    if (r && r.ok) {
      toast(t('프로세스를 종료했습니다') + ' · PID ' + pid, 'ok');
      setTimeout(() => renderView && renderView(), 600);
    } else {
      toast(t('종료 실패') + ': ' + (r && r.error ? r.error : 'unknown'), 'err');
    }
  } catch (e) { toast(t('종료 실패') + ': ' + e.message, 'err'); }
}

