async function _pmOpenSessTerm(sid) {
  try {
    const r = await api('/api/sessions-monitor/open-terminal', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sessionId: sid }),
    });
    if (r && r.ok) toast(t('터미널을 활성화했습니다'), 'ok');
    else toast(t('터미널 열기 실패') + ': ' + (r && r.error ? r.error : 'unknown'), 'err');
  } catch (e) { toast(t('터미널 열기 실패') + ': ' + e.message, 'err'); }
}

async function _pmKillIdle() {
  if (!confirm(t('idle 상태인 모든 Claude Code 세션을 종료하시겠습니까?'))) return;
  try {
    const r = await api('/api/memory/kill-idle-claude', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ thresholdSec: 600 }),
    });
    if (r && r.ok) {
      toast(t('일괄 종료 완료') + ': ' + (r.killed || []).length + ' / ' + t('건'), 'ok');
      setTimeout(() => renderView && renderView(), 600);
    } else {
      toast(t('일괄 종료 실패') + ': ' + (r && r.error ? r.error : 'unknown'), 'err');
    }
  } catch (e) { toast(t('일괄 종료 실패') + ': ' + e.message, 'err'); }
}

VIEWS.memoryManager = async () => {
  const r = await api('/api/memory/snapshot');
  if (!r || !r.ok) {
    return `
      ${viewHeader('메모리 관리', '시스템 메모리 + 상위 프로세스', 'memoryManager')}
      <div class="card p-6 text-sm text-[var(--text-mute)]">${t('메모리 정보를 불러올 수 없습니다')}</div>`;
  }
  const m = r.memory || {};
  const top = r.topProcesses || [];
  const idleCount = r.idleClaudeCodeCount || 0;
  const total = m.total_bytes || 1;
  const used = m.used_bytes || 0;
  const free = m.free_bytes || 0;
  const usedPct = Math.min(100, Math.round((used / total) * 100));
  const freePct = Math.min(100, Math.round((free / total) * 100));
  const swapTotal = m.swap_total_bytes || 0;
  const swapUsed = m.swap_used_bytes || 0;
  const swapPct = swapTotal > 0 ? Math.round((swapUsed / swapTotal) * 100) : 0;
  const bar = (label, valueText, pct, color) => `
    <div class="mb-3">
      <div class="flex items-center justify-between text-xs mb-1">
        <span class="text-[var(--text-mute)]">${escapeHtml(label)}</span>
        <span class="mono">${escapeHtml(valueText)} · ${pct}%</span>
      </div>
      <div style="height:8px;background:var(--card-2,rgba(255,255,255,0.06));border-radius:4px;overflow:hidden;">
        <div style="height:100%;width:${pct}%;background:${color};transition:width 200ms;"></div>
      </div>
    </div>`;
  return `
    ${viewHeader('메모리 관리', '시스템 메모리 + 상위 프로세스', 'memoryManager')}

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4 mb-4">
      <div class="card p-5">
        <h3 class="font-semibold text-sm mb-3">🧮 ${t('시스템 메모리')}</h3>
        ${bar(t('사용 중'), _pmFmtBytes(used) + ' / ' + _pmFmtBytes(total), usedPct, 'var(--accent, #6aa6ff)')}
        ${bar(t('여유'), _pmFmtBytes(free), freePct, 'var(--ok, #5cc97a)')}
        ${swapTotal > 0 ? bar(t('스왑'), _pmFmtBytes(swapUsed) + ' / ' + _pmFmtBytes(swapTotal), swapPct, 'var(--warn, #d6a45c)') : ''}
        <div class="text-[10px] text-[var(--text-dim)] mt-2 mono">
          active=${_pmFmtBytes(m.active_bytes)} · wired=${_pmFmtBytes(m.wired_bytes)} · compressed=${_pmFmtBytes(m.compressed_bytes)}
        </div>
      </div>
      <div class="card p-5">
        <h3 class="font-semibold text-sm mb-3">🧹 ${t('idle Claude Code 정리')}</h3>
        <div class="text-sm mb-3">
          ${t('idle 600초 이상 세션')}: <b class="mono">${idleCount}</b>
        </div>
        <button class="btn-primary btn text-xs" style="padding:0.5rem 0.9rem;" onclick="_pmKillIdle()">
          🧹 ${t('idle Claude Code 일괄 종료')}
        </button>
        <div class="text-[10px] text-[var(--text-dim)] mt-2">
          ${t('SIGTERM 으로 안전하게 종료합니다. 시스템 PID(<500) 는 보호됩니다.')}
        </div>
      </div>
    </div>

    <div class="card p-5">
      <h3 class="font-semibold text-sm mb-3">📊 ${t('상위 30 프로세스')}</h3>
      <div style="overflow-x:auto;">
        <table class="data">
          <thead><tr>
            <th>PID</th><th>${t('명령')}</th>
            <th class="text-right">RSS</th><th class="text-right">CPU%</th>
            <th class="text-right">${t('작업')}</th>
          </tr></thead>
          <tbody>
            ${top.map(p => `
              <tr ${p.isClaudeCode ? 'style="background:rgba(106,166,255,0.08);"' : ''}>
                <td class="mono text-xs">${p.pid}</td>
                <td class="text-xs">${p.isClaudeCode ? '🟦 ' : ''}${escapeHtml(p.command || '')}</td>
                <td class="mono text-xs text-right">${_pmFmtBytes(p.rss_bytes)}</td>
                <td class="mono text-xs text-right">${(p.cpu_pct || 0).toFixed(1)}</td>
                <td class="text-right"><button class="btn text-xs" onclick="_pmKillPid(${p.pid}, 'SIGTERM')">${t('종료')}</button></td>
              </tr>
            `).join('')}
          </tbody>
        </table>
      </div>
    </div>`;
};

// ────────────────────────────────────────────────────────────────
// v2.45.0 — Claude Code Router (CCR / zclaude) setup wizard
// ────────────────────────────────────────────────────────────────
window.__ccr = window.__ccr || { config: null, presets: [], status: null, alias: null };

function _ccrPill(ok, label) {
  const color = ok ? 'var(--ok, #5cc97a)' : 'var(--err, #e16060)';
  const icon = ok ? '✓' : '✗';
  return `<span class="mono text-xs" style="color:${color};">${icon}</span>
          <span class="text-xs ml-1">${escapeHtml(label)}</span>`;
}

function _ccrEsc(s) { return escapeHtml(s == null ? '' : String(s)); }

async function _ccrLoadAll() {
  const [st, cfg, pre, alias] = await Promise.all([
    api('/api/ccr/status'),
    api('/api/ccr/config'),
    api('/api/ccr/presets'),
    api('/api/ccr/alias-snippet'),
  ]);
  window.__ccr.status = st || {};
  window.__ccr.config = (cfg && cfg.config) ? cfg.config : { LOG: true, HOST: '127.0.0.1', PORT: 3456, Providers: [], Router: {} };
  if (!Array.isArray(window.__ccr.config.Providers)) window.__ccr.config.Providers = [];
  if (!window.__ccr.config.Router || typeof window.__ccr.config.Router !== 'object') window.__ccr.config.Router = {};
  window.__ccr.presets = (pre && pre.presets) ? pre.presets : [];
  window.__ccr.alias = alias || {};
}

function _ccrRenderStatus() {
  const s = window.__ccr.status || {};
  const installCmd = 'npm install -g @musistudio/claude-code-router';
  const ccrLine = s.ccr_installed
    ? _ccrPill(true, 'ccr ' + (s.ccr_version || ''))
    : `${_ccrPill(false, t('ccr 설치됨') + ' — ' + t('설치되지 않음'))}
       <div class="mt-2"><div class="text-[11px] text-[var(--text-mute)] mb-1">${t('설치 명령')}</div>
       <code class="mono text-xs block p-2 rounded" style="background:var(--code-bg);">${_ccrEsc(installCmd)}</code>
       <button class="btn text-xs mt-1" onclick="_ccrCopy('${_ccrEsc(installCmd)}', this)">${t('복사')}</button>
       <div class="text-[11px] text-[var(--text-dim)] mt-1">${t('이 명령을 직접 터미널에서 실행하세요')}</div></div>`;
  const nodeLine = s.node_ok
    ? _ccrPill(true, 'Node ' + (s.node_version || ''))
    : _ccrPill(false, t('Node.js 20 이상이 필요합니다') + (s.node_version ? ' (' + s.node_version + ')' : ''));
  const claudeLine = s.claude_installed
    ? _ccrPill(true, 'claude ' + (s.claude_version || ''))
    : _ccrPill(false, t('claude CLI 설치됨') + ' — ' + t('설치되지 않음'));
  const cfgLine = s.config_exists
    ? _ccrPill(true, t('config.json 존재'))
    : _ccrPill(false, t('config.json 존재') + ' — ' + (s.config_path || ''));
  const svc = s.service_running
    ? _ccrPill(true, t('ccr 서비스 실행 중') + ` · ${t('포트')} ${s.service_port}` + (s.service_pid ? ` · PID ${s.service_pid}` : ''))
    : _ccrPill(false, t('ccr 서비스 실행 중') + ' — ' + (s.service_port ? `${t('포트')} ${s.service_port}` : ''));
  return `
    <div class="card p-5 mb-4">
      <div class="flex items-center justify-between mb-3">
        <h3 class="font-semibold text-sm">① ${t('단계 1 · 환경 점검')}</h3>
        <button class="btn text-xs" onclick="_ccrRefreshStatus()">🔄 ${t('서비스 상태 새로고침')}</button>
      </div>
      <ul class="space-y-2">
        <li>${nodeLine}</li>
        <li>${ccrLine}</li>
        <li>${claudeLine}</li>
        <li>${cfgLine} <span class="text-[11px] text-[var(--text-dim)] ml-2 mono">${_ccrEsc(s.config_path || '')}</span></li>
        <li>${svc}</li>
      </ul>
    </div>`;
}

function _ccrRenderProviders() {
  const cfg = window.__ccr.config || {};
  const list = cfg.Providers || [];
  const presets = window.__ccr.presets || [];
  const presetBtns = presets.map((p, i) =>
    `<button class="btn text-xs" onclick="_ccrInsertPreset(${i})">+ ${_ccrEsc(p.label)}</button>`
  ).join(' ');
  const rows = list.map((p, i) => {
    const transformerJson = p.transformer ? JSON.stringify(p.transformer, null, 2) : '';
    return `
      <div class="card p-4 mb-3" data-ccr-row="${i}">
        <div class="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <label class="text-xs">${t('프로바이더 이름')}
            <input class="input w-full mt-1" data-ccr-field="name" data-idx="${i}" value="${_ccrEsc(p.name || '')}" oninput="_ccrFieldEdit(${i},'name',this.value)">
          </label>
          <label class="text-xs">${t('API base URL')}
            <input class="input w-full mt-1" data-ccr-field="api_base_url" data-idx="${i}" value="${_ccrEsc(p.api_base_url || '')}" oninput="_ccrFieldEdit(${i},'api_base_url',this.value)">
          </label>
          <label class="text-xs">${t('API 키')}
            <input class="input w-full mt-1" type="password" data-idx="${i}" value="${_ccrEsc(p.api_key || '')}" oninput="_ccrFieldEdit(${i},'api_key',this.value)">
          </label>
          <label class="text-xs">${t('모델 (한 줄에 하나씩)')}
            <textarea class="input w-full mt-1 mono text-xs" rows="3" oninput="_ccrModelsEdit(${i}, this.value)">${_ccrEsc((p.models || []).join('\n'))}</textarea>
          </label>
        </div>
        <details class="mt-2">
          <summary class="text-xs text-[var(--text-mute)] cursor-pointer">${t('고급: transformer (JSON)')}</summary>
          <textarea class="input w-full mt-2 mono text-xs" rows="4" oninput="_ccrTransformerEdit(${i}, this.value)" placeholder='{"use":["openrouter"]}'>${_ccrEsc(transformerJson)}</textarea>
        </details>
        <div class="flex justify-end mt-2">
          <button class="btn text-xs" onclick="_ccrRemoveRow(${i})">🗑 ${t('프로바이더 행 제거')}</button>
        </div>
      </div>`;
  }).join('');
  const empty = list.length === 0
    ? `<div class="text-xs text-[var(--text-mute)] italic mb-3">${t('프로바이더가 없습니다. 프리셋을 사용해 시작하세요.')}</div>`
    : '';
  return `
    <div class="card p-5 mb-4">
      <h3 class="font-semibold text-sm mb-3">② ${t('단계 2 · 프로바이더')}</h3>
      <div class="text-[11px] text-[var(--text-mute)] mb-2">${t('주의: API 키는 클라이언트 메모리에만 보관되며 ~/.claude-code-router/config.json 에 저장됩니다.')}</div>
      <div class="flex flex-wrap gap-2 mb-3">${presetBtns}<button class="btn text-xs" onclick="_ccrAddBlank()">+ ${t('프로바이더 추가')}</button></div>
      ${empty}
      ${rows}
      <div class="flex justify-end mt-2">
        <button class="btn-primary btn text-xs" onclick="_ccrSaveConfig()">💾 ${t('프로바이더 저장')}</button>
      </div>
    </div>`;
}

function _ccrRouterChoices(selected) {
  const list = (window.__ccr.config && window.__ccr.config.Providers) || [];
  const cur = selected || '';
  const opts = [`<option value="" ${cur === '' ? 'selected' : ''}>${t('선택 안 함')}</option>`];
  list.forEach(p => {
    (p.models || []).forEach(m => {
      const v = `${p.name},${m}`;
      const sel = v === cur ? ' selected' : '';
      opts.push(`<option value="${_ccrEsc(v)}"${sel}>${_ccrEsc(v)}</option>`);
    });
  });
  return opts.join('');
}

function _ccrRenderRouter() {
  const r = (window.__ccr.config && window.__ccr.config.Router) || {};
  const sel = (key, label) => `
    <label class="text-xs">${label}
      <select class="input w-full mt-1" onchange="_ccrRouterEdit('${key}', this.value)">
        ${_ccrRouterChoices(r[key] || '')}
      </select>
    </label>`;
  return `
    <div class="card p-5 mb-4">
      <h3 class="font-semibold text-sm mb-3">③ ${t('단계 3 · 라우팅 규칙')}</h3>
      <div class="text-[11px] text-[var(--text-mute)] mb-3">${t('프로바이더와 모델을 먼저 설정한 뒤 라우팅 규칙을 지정하세요.')}</div>
      <div class="grid grid-cols-1 sm:grid-cols-2 gap-3">
        ${sel('default', t('기본 (default)'))}
        ${sel('background', t('백그라운드 (background)'))}
        ${sel('think', t('Think (think)'))}
        ${sel('longContext', t('롱컨텍스트 (longContext)'))}
        ${sel('webSearch', t('웹 검색 (webSearch)'))}
        <label class="text-xs">${t('롱컨텍스트 임계값 (토큰)')}
          <input class="input w-full mt-1" type="number" min="0" value="${_ccrEsc(r.longContextThreshold || '')}" oninput="_ccrRouterEdit('longContextThreshold', this.value)">
        </label>
      </div>
      <div class="flex justify-end mt-3">
        <button class="btn-primary btn text-xs" onclick="_ccrSaveConfig()">💾 ${t('라우팅 규칙 저장')}</button>
      </div>
    </div>`;
}

function _ccrRenderService() {
  const s = window.__ccr.status || {};
  const disabled = !s.ccr_installed ? 'disabled' : '';
  return `
    <div class="card p-5 mb-4">
      <h3 class="font-semibold text-sm mb-3">④ ${t('단계 4 · 서비스 제어')}</h3>
      <div class="flex flex-wrap gap-2">
        <button class="btn-primary btn text-xs" onclick="_ccrSvc('start')" ${disabled}>▶ ${t('서비스 시작')}</button>
        <button class="btn text-xs" onclick="_ccrSvc('stop')" ${disabled}>⏹ ${t('서비스 중지')}</button>
        <button class="btn text-xs" onclick="_ccrSvc('restart')" ${disabled}>🔄 ${t('서비스 재시작')}</button>
      </div>
      ${!s.ccr_installed ? `<div class="text-xs mt-3" style="color:var(--err);">${t('ccr 가 설치되어 있지 않습니다')}</div>` : ''}
      <div id="ccrSvcOut" class="mono text-[11px] mt-3 whitespace-pre-wrap" style="color:var(--text-mute);"></div>
    </div>`;
}

function _ccrRenderAlias() {
  const a = window.__ccr.alias || {};
  const present = a.already_present;
  const snippet = a.zshrc_snippet || '';
  const alt = a.alternate_command || '';
  return `
    <div class="card p-5 mb-4">
      <h3 class="font-semibold text-sm mb-3">⑤ ${t('단계 5 · zclaude 별칭')}</h3>
      <div class="text-xs mb-1">${t('현재 셸')}: <b class="mono">${_ccrEsc(a.current_shell || '')}</b></div>
      <div class="text-xs mb-2">${t('RC 파일')}: <code class="mono">${_ccrEsc(a.rc_path || '')}</code>
        ${present ? `<span class="ml-2" style="color:var(--ok);">✓ ${t('이미 적용됨')}</span>` : `<span class="ml-2" style="color:var(--text-mute);">${t('아직 적용되지 않음')}</span>`}
      </div>
      <pre class="mono text-xs p-3 rounded whitespace-pre-wrap" style="background:var(--code-bg);">${_ccrEsc(snippet)}</pre>
      <button class="btn text-xs mt-2" onclick="_ccrCopy(${JSON.stringify(snippet)}, this)">📋 ${t('복사')}</button>
      <div class="text-[11px] text-[var(--text-mute)] mt-3">${t('위 블록을 RC 파일에 추가한 뒤 새 터미널을 여세요.')}</div>
      <div class="text-[11px] text-[var(--text-mute)] mt-2">${t('다른 옵션')}: <code class="mono">${_ccrEsc(alt)}</code></div>
    </div>`;
}

VIEWS.zclaude = async () => {
  try {
    await _ccrLoadAll();
  } catch (e) {
    return `${viewHeader('Claude Code Router (zclaude)', 'Claude Code를 GLM/Z.AI/DeepSeek 등 다른 LLM으로 라우팅', 'zclaude')}
      <div class="card p-6 text-sm text-[var(--text-mute)]">${t('환경 정보를 불러오지 못했습니다')}: ${escapeHtml(e.message || '')}</div>`;
  }
  return `
    ${viewHeader('Claude Code Router (zclaude)', 'Claude Code를 GLM/Z.AI/DeepSeek 등 다른 LLM으로 라우팅', 'zclaude')}
    ${_ccrRenderStatus()}
    ${_ccrRenderProviders()}
    ${_ccrRenderRouter()}
    ${_ccrRenderService()}
    ${_ccrRenderAlias()}`;
};

AFTER.zclaude = () => { /* event handlers attached inline via onclick */ };

// ── helpers (window-scoped so inline handlers can call them) ──
window._ccrCopy = (text, btn) => {
  try {
    navigator.clipboard.writeText(text);
    if (btn) { const old = btn.textContent; btn.textContent = '✓ ' + t('복사됨'); setTimeout(() => { btn.textContent = old; }, 1200); }
  } catch (e) { toast(String(e), 'err'); }
};

window._ccrFieldEdit = (i, field, value) => {
  const list = window.__ccr.config.Providers;
  if (!list[i]) return;
  list[i][field] = value;
};

window._ccrModelsEdit = (i, value) => {
  const list = window.__ccr.config.Providers;
  if (!list[i]) return;
  list[i].models = String(value || '').split(/\r?\n/).map(s => s.trim()).filter(Boolean);
};

window._ccrTransformerEdit = (i, value) => {
  const list = window.__ccr.config.Providers;
  if (!list[i]) return;
  const v = String(value || '').trim();
  if (!v) { delete list[i].transformer; return; }
  try { list[i].transformer = JSON.parse(v); } catch (e) { /* keep typing */ }
};

window._ccrRouterEdit = (key, value) => {
  const r = window.__ccr.config.Router || (window.__ccr.config.Router = {});
  if (key === 'longContextThreshold') {
    const n = parseInt(value, 10);
    if (Number.isFinite(n)) r[key] = n; else delete r[key];
  } else {
    if (value) r[key] = value; else delete r[key];
  }
};

window._ccrAddBlank = () => {
  window.__ccr.config.Providers.push({ name: '', api_base_url: '', api_key: '', models: [] });
  renderView && renderView();
};

window._ccrInsertPreset = (i) => {
  const p = window.__ccr.presets[i];
  if (!p) return;
  const row = { name: p.name, api_base_url: p.api_base_url, api_key: '', models: (p.models || []).slice() };
  if (p.transformer) row.transformer = JSON.parse(JSON.stringify(p.transformer));
  window.__ccr.config.Providers.push(row);
  renderView && renderView();
};

window._ccrRemoveRow = (i) => {
  window.__ccr.config.Providers.splice(i, 1);
  renderView && renderView();
};

window._ccrSaveConfig = async () => {
  try {
    const r = await api('/api/ccr/config', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ config: window.__ccr.config }),
    });
    if (r && r.ok) {
      toast(t('프로바이더 저장 완료'), 'ok');
      if (Array.isArray(r.warnings) && r.warnings.length) {
        toast(r.warnings.join(' · '), 'info');
      }
      window.__ccr.config = r.config || window.__ccr.config;
    } else {
      toast(t('저장 실패') + ': ' + ((r && r.error) || 'unknown'), 'err');
    }
  } catch (e) { toast(t('저장 실패') + ': ' + e.message, 'err'); }
};

window._ccrSvc = async (action) => {
  const out = document.getElementById('ccrSvcOut');
  if (out) out.textContent = '… ' + action;
  try {
    const r = await api('/api/ccr/service', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action }),
    });
    if (out) out.textContent = (r && r.output) ? r.output : (r && r.error) ? r.error : '';
    if (!r || !r.ok) toast(t('서비스 명령 실패') + ': ' + ((r && r.error) || ''), 'err');
    setTimeout(() => _ccrRefreshStatus(), 400);
  } catch (e) {
    if (out) out.textContent = e.message;
    toast(t('서비스 명령 실패') + ': ' + e.message, 'err');
  }
};

window._ccrRefreshStatus = async () => {
  try {
    const s = await api('/api/ccr/status');
    window.__ccr.status = s || {};
    renderView && renderView();
  } catch (e) { toast(e.message, 'err'); }
};

// ────────────────────────────────────────────────────────────────
// AUTO-RESUME MANAGER (v2.49.0)
// ────────────────────────────────────────────────────────────────
const _ARM_STATE_LABEL = {
  running:   '실행 중',
  waiting:   '대기 중',
  watching:  '감시 중',
  done:      '정상 종료',
  failed:    '실패',
  exhausted: '소진',
  stopped:   '중지',
  error:     '오류',
};
const _ARM_STATE_COLOR = {
  running:   { bg: 'rgba(34,197,94,.15)',  fg: '#22c55e' },
  waiting:   { bg: 'rgba(234,179,8,.18)',  fg: '#eab308' },
  watching:  { bg: 'rgba(59,130,246,.15)', fg: '#3b82f6' },
  done:      { bg: 'rgba(34,197,94,.15)',  fg: '#22c55e' },
  failed:    { bg: 'rgba(239,68,68,.18)',  fg: '#ef4444' },
  exhausted: { bg: 'rgba(148,163,184,.20)',fg: '#94a3b8' },
  stopped:   { bg: 'rgba(148,163,184,.20)',fg: '#94a3b8' },
  error:     { bg: 'rgba(239,68,68,.18)',  fg: '#ef4444' },
};

function _armEtaText(nextAttemptAt) {
  if (!nextAttemptAt) return '—';
  const now = Math.floor(Date.now() / 1000);
  const dt = nextAttemptAt - now;
  if (dt <= 0) return t('방금');
  if (dt < 60) return dt + 's';
  if (dt < 3600) return Math.floor(dt / 60) + 'm ' + (dt % 60) + 's';
  return Math.floor(dt / 3600) + 'h ' + Math.floor((dt % 3600) / 60) + 'm';
}

function _armStateChip(state) {
  const lbl = _ARM_STATE_LABEL[state] || state || '—';
  const c = _ARM_STATE_COLOR[state] || { bg: 'rgba(148,163,184,.20)', fg: '#94a3b8' };
  return `<span class="mono text-[10px]" style="display:inline-block;padding:2px 8px;border-radius:9999px;background:${c.bg};color:${c.fg};">${escapeHtml(t(lbl))}</span>`;
}

VIEWS.autoResumeManager = async () => {
  const r = await api('/api/auto_resume/status').catch(() => null);
  if (!r || !r.ok) {
    return `
      ${viewHeader('Auto-Resume 관리', 'Auto-Resume 바인딩 상태 모니터링', 'autoResumeManager')}
      <div class="card p-6 text-sm text-[var(--text-mute)]">
        ${t('세션 정보를 불러올 수 없습니다')}
      </div>`;
  }
  const active = r.active || [];
  // count by state
  const byState = {};
  for (const e of active) {
    const k = e.state || 'unknown';
    byState[k] = (byState[k] || 0) + 1;
  }
  const breakdownHtml = Object.keys(byState).length
    ? Object.entries(byState).map(([s, n]) =>
        `<span class="mr-2 mb-1 inline-block">${_armStateChip(s)} <span class="mono text-xs">${n}</span></span>`
      ).join('')
    : `<span class="text-xs text-[var(--text-mute)]">${t('활성 바인딩 없음')}</span>`;

  // Sort defensively client-side too: live first, then dead.
  const sortedActive = active.slice().sort((a, b) => {
    const la = a.liveSession ? 0 : 1;
    const lb = b.liveSession ? 0 : 1;
    if (la !== lb) return la - lb;
    return (b.createdAt || 0) - (a.createdAt || 0);
  });
  const rowsHtml = sortedActive.length ? sortedActive.map(e => {
    const sid = e.sessionId || '';
    const sidShort = sid.slice(0, 8);
    const cwd = e.cwd || '';
    const attempts = e.attempts ?? 0;
    const maxA = e.maxAttempts ?? 0;
    const eta = _armEtaText(e.nextAttemptAt || 0);
    const termApp = e.terminal_app || '';
    const pid = (e.pid != null ? e.pid : '');
    const liveChip = e.liveSession
      ? `<span class="badge text-[10px]" style="background:rgba(34,197,94,.15);color:#16a34a;">🟢 ${t('실행 중')}</span>`
      : `<span class="badge text-[10px]" style="background:rgba(148,163,184,.15);color:var(--text-mute);">⚪ ${t('종료됨')}</span>`;
    const termCell = termApp || pid
      ? `<div class="mono text-[10px]">${escapeHtml(termApp || '-')}${pid ? ' <span class="text-[var(--text-mute)]">#'+escapeHtml(String(pid))+'</span>' : ''}</div><div class="mt-0.5">${liveChip}</div>`
      : `<div>${liveChip}</div>`;
    return `
      <tr data-sid="${escapeHtml(sid)}">
        <td><input type="checkbox" class="arm-row-chk" data-sid="${escapeHtml(sid)}" /></td>
        <td class="mono text-[10px]" title="${escapeHtml(sid)}">${escapeHtml(sidShort)}</td>
        <td class="mono text-[10px] text-[var(--text-mute)] truncate" style="max-width:280px;" title="${escapeHtml(cwd)}">${escapeHtml(cwd)}</td>
        <td>${termCell}</td>
        <td>${_armStateChip(e.state)}</td>
        <td class="mono text-xs">${attempts}/${maxA}</td>
        <td class="mono text-xs">${escapeHtml(eta)}</td>
        <td class="text-right">
          <button class="btn text-xs" onclick="_armOpenDetail('${escapeHtml(sid)}')">${t('상세')}</button>
          <button class="btn text-xs" onclick="_armAdvise('${escapeHtml(sid)}')" title="${t('Hyper Advisor')}">🧠 ${t('Hyper Advisor')}</button>
          <button class="btn text-xs" onclick="_armCancelOne('${escapeHtml(sid)}')">${t('취소')}</button>
        </td>
      </tr>`;
  }).join('') : '';

  return `
    ${viewHeader('Auto-Resume 관리', 'Auto-Resume 바인딩 상태 모니터링', 'autoResumeManager')}

    <div class="card p-5 mb-4">
      <div class="flex items-center justify-between flex-wrap gap-2 mb-3">
        <h3 class="font-semibold text-sm">🔄 ${t('활성 바인딩')}
          <span class="text-[var(--text-mute)] mono text-xs ml-2">${t('총')} ${active.length} ${t('건')}</span>
        </h3>
      </div>
      <div>${breakdownHtml}</div>
    </div>

    <div class="card p-5">
      <div class="flex items-center justify-between flex-wrap gap-2 mb-3">
        <h3 class="font-semibold text-sm">${t('활성 바인딩')}</h3>
        <div class="flex gap-2">
          <button class="btn text-xs" onclick="_armOpenAddDialog()">+ ${t('새 바인딩 추가')}</button>
          <button class="btn text-xs" onclick="_armCancelSelected()">${t('선택 취소')}</button>
        </div>
      </div>
      ${active.length ? `
        <div style="overflow-x:auto;">
          <table class="data">
            <thead><tr>
              <th style="width:30px;"><input type="checkbox" id="arm-chk-all" /></th>
              <th>${t('세션')}</th>
              <th>cwd</th>
              <th>${t('터미널')}</th>
              <th>${t('상태')}</th>
              <th>${t('시도 수')}</th>
              <th>${t('다음 시도까지')}</th>
              <th class="text-right">${t('작업')}</th>
            </tr></thead>
            <tbody>${rowsHtml}</tbody>
          </table>
        </div>
      ` : _emptyState(t('활성 바인딩 없음'), '🔄')}
    </div>
    <style>
      @media (max-width: 640px) {
        #view table.data thead { display: none; }
        #view table.data, #view table.data tbody, #view table.data tr, #view table.data td { display: block; width: 100%; }
        #view table.data tr { border-bottom: 1px solid var(--border, rgba(148,163,184,.2)); padding: 6px 0; }
        #view table.data td { padding: 3px 4px; max-width: 100% !important; white-space: normal; }
      }
    </style>
  `;
};

AFTER.autoResumeManager = () => {
  const all = document.getElementById('arm-chk-all');
  if (all) {
    all.addEventListener('change', () => {
      document.querySelectorAll('.arm-row-chk').forEach(cb => { cb.checked = all.checked; });
    });
  }
  // auto-refresh every 10s; pause when tab hidden
  if (window.__armTimer) { clearInterval(window.__armTimer); }
  window.__armTimer = setInterval(() => {
    if (document.hidden) return;
    if (state.view !== 'autoResumeManager') {
      clearInterval(window.__armTimer); window.__armTimer = null; return;
    }
    renderView && renderView();
  }, 10000);
};

window._armOpenDetail = (sid) => {
  // Reuse existing session detail flow if available; otherwise show binding json.
  if (typeof showAutoResumeDetail === 'function') {
    try { showAutoResumeDetail(sid); return; } catch {}
  }
  api('/api/auto_resume/get?sessionId=' + encodeURIComponent(sid))
    .then(r => {
      if (!r || !r.ok) return toast(t('세션 정보를 불러올 수 없습니다'), 'err');
      const txt = JSON.stringify(r.entry || {}, null, 2);
      // best-effort: log to console + clipboard so user can inspect
      try { navigator.clipboard.writeText(txt); } catch {}
      toast(t('상세') + ': ' + sid.slice(0, 8), 'ok');
      console.log('[auto-resume detail]', r.entry);
    })
    .catch(e => toast(e.message, 'err'));
};

// Hyper Advisor — opt-in meta-LLM call to suggest retry-policy adjustments.
// Results are advisory only; user clicks Apply to push them via /api/auto_resume/set.
window._armAdvise = async (sid) => {
  if (!sid) return;
  showModalLoading(t('재시도 분석') + '…');
  let r;
  try {
    r = await api('/api/auto_resume/advise', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sessionId: sid }),
    });
  } catch (e) {
    closeModal();
    return toast(e.message, 'err');
  }
  if (!r || !r.ok || !r.advice) {
    closeModal();
    const err = (r && r.error) || 'unknown';
    if (/Not enough failure history/i.test(err)) {
      return toast(t('분석할 실패 이력이 부족함'), 'err');
    }
    return toast(t('Hyper Advisor') + ': ' + err, 'err');
  }
  const a = r.advice;
  const adviceJson = JSON.stringify({
    sessionId: sid,
    pollInterval: a.pollIntervalSec,
    maxAttempts: a.maxAttempts,
  });
  const promptHintHtml = a.promptHint
    ? `<div class="mb-2"><div class="text-xs text-[var(--text-mute)] mb-1">${t('프롬프트 힌트')}</div>
        <div class="mono text-xs p-2 rounded" style="background:rgba(148,163,184,.08);">${escapeHtml(a.promptHint)}</div></div>`
    : '';
  showModal(`
    <div class="p-5">
      <h3 class="font-semibold text-base mb-3">🧠 ${t('Hyper Advisor')} — ${t('권장 조정')}</h3>
      <div class="grid grid-cols-2 gap-3 mb-3 text-sm">
        <div>
          <div class="text-xs text-[var(--text-mute)]">${t('권장 폴링 간격(초)')}</div>
          <div class="mono">${a.pollIntervalSec} <span class="text-[var(--text-mute)] text-xs">(${t('현재')}: ${r.currentPollInterval})</span></div>
        </div>
        <div>
          <div class="text-xs text-[var(--text-mute)]">${t('권장 최대 시도')}</div>
          <div class="mono">${a.maxAttempts} <span class="text-[var(--text-mute)] text-xs">(${t('현재')}: ${r.currentMaxAttempts})</span></div>
        </div>
      </div>
      ${promptHintHtml}
      <div class="mb-3">
        <div class="text-xs text-[var(--text-mute)] mb-1">${t('근거')}</div>
        <div class="text-sm">${escapeHtml(a.rationale || '')}</div>
      </div>
      <div class="text-[10px] text-[var(--text-mute)] mb-3 mono">
        ${escapeHtml(a.provider || '')} ${escapeHtml(a.model || '')} · cost $${(r.cost_usd || 0).toFixed(4)}
      </div>
      <div class="flex justify-end gap-2">
        <button class="btn text-xs" onclick="closeModal()">${t('닫기')}</button>
        <button class="btn primary text-xs" onclick='_armApplyAdvice(${JSON.stringify(adviceJson).replace(/</g, "\\u003c")})'>${t('적용')}</button>
      </div>
    </div>
  `);
};

window._armApplyAdvice = async (payloadJson) => {
  let payload;
  try { payload = JSON.parse(payloadJson); } catch { return toast('bad payload', 'err'); }
  try {
    const r = await api('/api/auto_resume/set', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId:    payload.sessionId,
        pollInterval: payload.pollInterval,
        maxAttempts:  payload.maxAttempts,
      }),
    });
    if (r && r.ok) {
      closeModal();
      toast(t('적용') + ' ✓', 'ok');
      setTimeout(() => renderView && renderView(), 400);
    } else {
      toast(t('Hyper Advisor') + ': ' + ((r && r.error) || 'unknown'), 'err');
    }
  } catch (e) { toast(e.message, 'err'); }
};

