// K3 (v2.63.0) — per-UUID-prefix cwd memory so repeat-binders don't retype.
function _armRememberCwd(sid, cwd) {
  if (!sid || !cwd) return;
  const key = sid.slice(0, 8);
  try {
    const raw = localStorage.getItem('cc.ar.cwds') || '{}';
    const map = JSON.parse(raw);
    map[key] = cwd;
    // bound: 32 entries
    const keys = Object.keys(map);
    if (keys.length > 32) {
      keys.slice(0, keys.length - 32).forEach(k => delete map[k]);
    }
    localStorage.setItem('cc.ar.cwds', JSON.stringify(map));
  } catch (_) {}
}
function _armRecallCwd(sid) {
  if (!sid) return '';
  try {
    const raw = localStorage.getItem('cc.ar.cwds') || '{}';
    return JSON.parse(raw)[sid.slice(0, 8)] || '';
  } catch (_) { return ''; }
}

window._armSubmitAddDialog = async () => {
  const sid = (document.getElementById('armSid')||{}).value || '';
  const cwd = (document.getElementById('armCwd')||{}).value || '';
  const prompt = (document.getElementById('armPrompt')||{}).value || '';
  const poll = parseInt((document.getElementById('armPoll')||{}).value || '300', 10);
  const idle = parseInt((document.getElementById('armIdle')||{}).value || '90', 10);
  const max = parseInt((document.getElementById('armMax')||{}).value || '12', 10);
  const useContinue = !!(document.getElementById('armUseContinue')||{}).checked;
  const allowUnbound = !!(document.getElementById('armAllowUnbound')||{}).checked;
  if (!sid.trim()) { toast(t('Session UUID 가 비어있음'), 'err'); return; }
  try {
    const r = await api('/api/auto_resume/set', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId: sid.trim(), cwd: cwd.trim(), prompt: prompt.trim(),
        pollInterval: poll, idleSeconds: idle, maxAttempts: max,
        useContinue, allowUnboundSession: allowUnbound,
      }),
    });
    if (r && r.ok) {
      _armRememberCwd(sid, cwd);
      closeModal();
      toast(t('바인딩 추가됨'), 'ok');
      setTimeout(() => renderView && renderView(), 200);
    } else {
      toast(t('실패') + ': ' + ((r && r.error) || 'unknown'), 'err');
    }
  } catch (e) {
    toast(t('실패') + ': ' + e.message, 'err');
  }
};

window._armCancelOne = async (sid) => {
  if (!sid) return;
  if (!confirm(t('선택한 바인딩을 취소하시겠습니까?'))) return;
  try {
    const r = await api('/api/auto_resume/cancel', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sessionId: sid }),
    });
    if (r && r.ok) toast(t('취소 완료'), 'ok');
    else toast(t('취소 실패') + ': ' + (r && r.error ? r.error : 'unknown'), 'err');
  } catch (e) { toast(t('취소 실패') + ': ' + e.message, 'err'); }
  setTimeout(() => renderView && renderView(), 400);
};

window._armCancelSelected = async () => {
  const checked = Array.from(document.querySelectorAll('.arm-row-chk'))
    .filter(cb => cb.checked)
    .map(cb => cb.getAttribute('data-sid'))
    .filter(Boolean);
  if (!checked.length) {
    toast(t('선택할 항목이 없습니다'), 'err');
    return;
  }
  if (!confirm(t('선택한 바인딩을 취소하시겠습니까?'))) return;
  let okN = 0, failN = 0;
  for (const sid of checked) {
    try {
      const r = await api('/api/auto_resume/cancel', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sessionId: sid }),
      });
      if (r && r.ok) okN++; else failN++;
    } catch { failN++; }
  }
  if (failN === 0) toast(t('취소 완료') + ': ' + okN + ' ' + t('건'), 'ok');
  else toast(t('취소 실패') + ': ' + failN + ' / ' + (okN + failN), 'err');
  setTimeout(() => renderView && renderView(), 400);
};

